import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
// Note: In a real environment, ensure process.env.API_KEY is set.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Filters a list of keywords based on a user prompt using Gemini.
 * Returns the list of keywords that SHOULD BE KEPT.
 */
export const filterKeywordsBatch = async (
  keywords: string[],
  userPrompt: string
): Promise<string[]> => {
  if (!keywords.length) return [];

  const modelId = 'gemini-2.5-flash-latest'; // Fast and cost-effective for this task

  // Schema to ensure we get a clean list of strings back
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      keptKeywords: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "The list of keywords that match the criteria and should be kept."
      }
    },
    required: ["keptKeywords"]
  };

  const systemInstruction = `
    You are a specialized SEO keyword filtering assistant.
    Your task is to analyze a list of keywords and filter them based strictly on the user's criteria.

    Rules:
    1. You will receive a JSON list of keywords and a filtering criteria (Prompt).
    2. Return ONLY the keywords that satisfy the user's criteria in the 'keptKeywords' array.
    3. If the user asks to "remove" something, return the list WITHOUT those items.
    4. If the user asks to "keep" something, return ONLY those items.
    5. Do not modify the text of the keywords. Return them exactly as received.
  `;

  const prompt = `
    User Filtering Criteria: "${userPrompt}"

    Keywords List to Process:
    ${JSON.stringify(keywords)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1, // Low temperature for deterministic results
      },
    });

    const text = response.text;
    if (!text) return keywords; // Fallback: keep all if response is empty

    const parsed = JSON.parse(text);
    return parsed.keptKeywords || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    // In case of error, we throw it so the UI can handle the retry or logging
    throw error;
  }
};

import React, { useState, useRef, useCallback } from 'react';
import { 
  Search, 
  Download, 
  Copy, 
  Play, 
  Square, 
  Settings, 
  Database, 
  Layers, 
  Terminal,
  Trash2,
  XCircle,
  Sparkles,
  Filter,
  Loader2
} from 'lucide-react';
import { filterKeywordsBatch } from './services/geminiService';

// --- Type Definitions ---
interface SuggestionResult {
  id: string;
  keyword: string;
  sourceSeed: string;
  layer: number;
}

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error' | 'warning';
  timestamp: string;
}

// --- Utils ---

// Normalization function for Persian/Arabic text
const normalizeText = (text: string): string => {
  if (!text) return '';
  return text
    .trim()
    .replace(/\s+/g, ' ') // Remove extra spaces
    .replace(/ي/g, 'ی')   // Arabic Ye to Persian Ye
    .replace(/ك/g, 'ک')   // Arabic Kaf to Persian Kaf
    .toLowerCase();       // Lowercase (useful for English)
};

// Generate CSV content
const generateCSV = (data: SuggestionResult[]) => {
  const header = ['Keyword,Source Seed,Layer'];
  const rows = data.map(item => `"${item.keyword}","${item.sourceSeed}",${item.layer}`);
  return [header, ...rows].join('\n');
};

// --- Main Component ---

export default function DeepSuggestFetcher() {
  // --- State ---
  const [seeds, setSeeds] = useState<string>('');
  const [language, setLanguage] = useState<string>('fa');
  const [country, setCountry] = useState<string>('ir');
  const [depth, setDepth] = useState<number>(1);
  const [delay, setDelay] = useState<number>(1000); 
  const [concurrency, setConcurrency] = useState<number>(2); 

  const [results, setResults] = useState<SuggestionResult[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [progress, setProgress] = useState<{ processed: number; total: number }>({ processed: 0, total: 0 });

  // AI Filter State
  const [aiPrompt, setAiPrompt] = useState<string>('');
  const [isAiFiltering, setIsAiFiltering] = useState<boolean>(false);

  // Refs for controlling the loop
  const abortControllerRef = useRef<AbortController | null>(null);
  const processedKeywordsRef = useRef<Set<string>>(new Set());

  // --- Helper: Logging ---
  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100)); // Keep last 100 logs
  }, []);

  // --- Core Logic: Fetcher with Proxy Rotation ---
  const fetchSuggestions = async (query: string): Promise<string[]> => {
    const targetUrl = `https://suggestqueries.google.com/complete/search?client=chrome&hl=${language}&gl=${country}&q=${encodeURIComponent(query)}`;

    // Strategy: Try faster proxy first, fall back to robust one
    const proxies = [
      {
        name: 'CORSProxy',
        url: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}`,
        isJsonWrapped: false
      },
      {
        name: 'AllOrigins',
        url: (u: string) => `https://api.allorigins.win/get?url=${encodeURIComponent(u)}`,
        isJsonWrapped: true
      }
    ];

    let lastError: any = null;

    for (const proxy of proxies) {
      if (abortControllerRef.current?.signal.aborted) {
        throw new DOMException('Aborted', 'AbortError');
      }

      try {
        const response = await fetch(proxy.url(targetUrl), {
          signal: abortControllerRef.current?.signal
        });

        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`);
        }

        const data = await response.json();

        let resultData;
        if (proxy.isJsonWrapped) {
          // AllOrigins wraps response in { contents: "..." }
          resultData = JSON.parse(data.contents);
        } else {
          // CORSProxy returns raw Google response
          resultData = data;
        }

        // Google API returns [query, [suggestions...], ...]
        if (Array.isArray(resultData) && Array.isArray(resultData[1])) {
           return resultData[1];
        }

        return [];

      } catch (error: any) {
        if (error.name === 'AbortError') throw error;
        lastError = error;
        // Continue to next proxy silently
      }
    }

    // If all proxies failed
    // console.error(`All proxies failed for "${query}". Last error:`, lastError);
    throw lastError || new Error('All proxies failed');
  };

  // --- Core Logic: Recursive Processor (BFS) ---
  const startProcessing = async () => {
    if (!seeds.trim()) {
      addLog('لطفا کلمات کلیدی اولیه را وارد کنید.', 'error');
      return;
    }

    setIsProcessing(true);
    setResults([]);
    setLogs([]);
    processedKeywordsRef.current = new Set();
    abortControllerRef.current = new AbortController();

    const seedList = seeds.split('\n').map(s => normalizeText(s)).filter(s => s.length > 0);

    // Initial Queue: Items to process
    let queue: { keyword: string; source: string; layer: number }[] = seedList.map(s => ({
      keyword: s,
      source: 'SEED',
      layer: 0 // Layer 0 means it's a seed
    }));

    // Mark seeds as processed
    seedList.forEach(s => processedKeywordsRef.current.add(s));

    addLog(`شروع پردازش با ${seedList.length} کلمه کلیدی...`, 'info');

    let totalProcessedCount = 0;

    try {
      // While there are items in the queue and we haven't been stopped
      while (queue.length > 0 && abortControllerRef.current) {

        // Take a batch of items from the queue based on concurrency
        const currentBatch = queue.splice(0, concurrency);

        // Update progress UI (Estimation)
        setProgress({ processed: totalProcessedCount, total: totalProcessedCount + queue.length + currentBatch.length });

        // Process batch in parallel
        const batchPromises = currentBatch.map(async (item) => {
          // If we reached max depth, stop fetching for this branch
          if (item.layer >= depth) return []; 

          try {
            const suggestions = await fetchSuggestions(item.keyword);

            const newKeywords: { keyword: string; source: string; layer: number }[] = [];

            suggestions.forEach(sugg => {
              const normalizedSugg = normalizeText(sugg);

              // Deduplication check
              if (!processedKeywordsRef.current.has(normalizedSugg)) {
                processedKeywordsRef.current.add(normalizedSugg);

                // Add to visible results
                const newResult: SuggestionResult = {
                  id: Math.random().toString(36).substr(2, 9),
                  keyword: normalizedSugg,
                  sourceSeed: item.keyword,
                  layer: item.layer + 1
                };

                setResults(prev => [...prev, newResult]);

                // Add to queue if depth allows
                if (item.layer + 1 < depth) {
                  newKeywords.push({
                    keyword: normalizedSugg,
                    source: item.keyword,
                    layer: item.layer + 1
                  });
                }
              }
            });
            return newKeywords;
          } catch (err: any) {
            if (err.name !== 'AbortError') {
               addLog(`خطا در دریافت ساجست برای: "${item.keyword}"`, 'warning');
            }
            return [];
          }
        });

        // Wait for all requests in this batch
        const batchResults = await Promise.all(batchPromises);
        totalProcessedCount += currentBatch.length;

        // Add new found keywords to the end of the queue (BFS)
        batchResults.forEach(newItems => {
          queue.push(...newItems);
        });

        // Artificial Delay to respect rate limits
        if (queue.length > 0) {
          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }

      if (abortControllerRef.current) {
        addLog('پردازش با موفقیت به پایان رسید.', 'success');
      }

    } catch (error: any) {
      if (error.name !== 'AbortError') {
        addLog('پردازش با خطای غیرمنتظره متوقف شد.', 'error');
      }
    } finally {
      setIsProcessing(false);
      abortControllerRef.current = null;
    }
  };

  const stopProcessing = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
      setIsProcessing(false);
      addLog('پردازش توسط کاربر متوقف شد.', 'warning');
    }
  };

  // --- AI Filtering Logic ---
  const handleAiFilter = async () => {
    if (results.length === 0) {
      addLog('هیچ کلمه‌ای برای تحلیل وجود ندارد.', 'warning');
      return;
    }
    if (!aiPrompt.trim()) {
      addLog('لطفا دستور فیلتر (Prompt) را وارد کنید.', 'error');
      return;
    }

    if (!process.env.API_KEY) {
      addLog('API Key یافت نشد. لطفا تنظیمات برنامه را بررسی کنید.', 'error');
      return;
    }

    setIsAiFiltering(true);
    addLog('شروع تحلیل هوشمند کلمات با هوش مصنوعی...', 'info');

    try {
      // Chunk size for Gemini (50 is a safe bet for token limits per request)
      const CHUNK_SIZE = 50;
      const allKeywords = results.map(r => r.keyword);
      const chunks = [];

      for (let i = 0; i < allKeywords.length; i += CHUNK_SIZE) {
        chunks.push(allKeywords.slice(i, i + CHUNK_SIZE));
      }

      let keptKeywordsSet = new Set<string>();
      let processedCount = 0;

      for (let i = 0; i < chunks.length; i++) {
        const chunk = chunks[i];
        try {
          // Send to Gemini
          const keptInChunk = await filterKeywordsBatch(chunk, aiPrompt);
          keptInChunk.forEach(k => keptKeywordsSet.add(k));

          processedCount += chunk.length;
          addLog(`تحلیل دسته ${i + 1} از ${chunks.length} انجام شد.`, 'info');
        } catch (err) {
          console.error(err);
          addLog(`خطا در تحلیل دسته ${i + 1}. نادیده گرفته شد.`, 'warning');
          // On error, decide whether to keep or drop. Here we keep original to be safe? 
          // Or strictly drop? Let's keep original chunk if AI fails to prevent data loss.
          chunk.forEach(k => keptKeywordsSet.add(k));
        }
      }

      // Calculate stats
      const initialCount = results.length;
      const finalCount = keptKeywordsSet.size;
      const removedCount = initialCount - finalCount;

      // Update Results
      const newResults = results.filter(r => keptKeywordsSet.has(r.keyword));
      setResults(newResults);

      // Re-sync processedKeywordsRef to match current list
      processedKeywordsRef.current = new Set(newResults.map(r => r.keyword));

      addLog(`پایان تحلیل. ${removedCount} کلمه حذف شد و ${finalCount} کلمه باقی ماند.`, 'success');

    } catch (error) {
      addLog('خطای کلی در فرآیند هوش مصنوعی.', 'error');
      console.error(error);
    } finally {
      setIsAiFiltering(false);
    }
  };

  // --- Handlers ---
  const handleExport = () => {
    const csvContent = generateCSV(results);
    const blob = new Blob([`\uFEFF${csvContent}`], { type: 'text/csv;charset=utf-8;' }); // Add BOM for Excel UTF-8
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `deep_suggest_${new Date().toISOString().slice(0,10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    addLog('فایل CSV دانلود شد.', 'success');
  };

  const handleCopy = () => {
    const text = results.map(r => r.keyword).join('\n');

    // Robust copy method for restricted environments (iframe)
    const textArea = document.createElement("textarea");
    textArea.value = text;

    // Ensure it's part of DOM but hidden
    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    textArea.style.top = "0";
    document.body.appendChild(textArea);

    textArea.focus();
    textArea.select();

    try {
      const successful = document.execCommand('copy');
      if (successful) {
        addLog(`${results.length} کلمه کلیدی در کلیپ‌بورد کپی شد.`, 'success');
      } else {
        addLog('کپی ناموفق بود. لطفا دستی کپی کنید.', 'error');
      }
    } catch (err) {
      console.error('Copy failed', err);
      addLog('خطا در کپی کردن متن.', 'error');
    }

    document.body.removeChild(textArea);
  };

  const handleClear = () => {
    setResults([]);
    setLogs([]);
    processedKeywordsRef.current = new Set();
    setProgress({ processed: 0, total: 0 });
  };

  const handleDeleteItem = (targetKeyword: string) => {
    // 1. Identify all keywords to delete (Target + Descendants)
    const toRemove = new Set<string>([targetKeyword]);
    const queue = [targetKeyword];

    let head = 0;
    while(head < queue.length){
        const currentParent = queue[head];
        head++;

        // Find direct children in the results array
        // A child is any result where sourceSeed matches currentParent
        const children = results.filter(r => r.sourceSeed === currentParent);

        children.forEach(child => {
            if (!toRemove.has(child.keyword)) {
                toRemove.add(child.keyword);
                queue.push(child.keyword);
            }
        });
    }

    // 2. Update State
    setResults(prev => prev.filter(r => !toRemove.has(r.keyword)));

    // 3. Cleanup internal Set (optional, allows re-fetching if user inputs it again)
    toRemove.forEach(k => processedKeywordsRef.current.delete(k));

    addLog(`کلمه "${targetKeyword}" و ${toRemove.size - 1} زیرمجموعه آن حذف شدند.`, 'warning');
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans" dir="rtl">

      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg text-white">
              <Search size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900">Deep Suggest & AI Filter</h1>
              <p className="text-xs text-gray-500">ابزار استخراج و پالایش هوشمند کلمات کلیدی</p>
            </div>
          </div>
          <div className="flex gap-2">
            {isProcessing ? (
              <button 
                onClick={stopProcessing}
                className="flex items-center gap-2 bg-red-50 text-red-600 border border-red-200 px-4 py-2 rounded-md hover:bg-red-100 transition-colors"
              >
                <Square size={18} fill="currentColor" />
                <span>توقف</span>
              </button>
            ) : (
              <button 
                onClick={startProcessing}
                disabled={isAiFiltering}
                className="flex items-center gap-2 bg-blue-600 text-white px-6 py-2 rounded-md hover:bg-blue-700 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Play size={18} fill="currentColor" />
                <span>شروع استخراج</span>
              </button>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6 grid grid-cols-1 lg:grid-cols-12 gap-6">

        {/* Left Column: Configuration (4 cols) */}
        <div className="lg:col-span-4 space-y-6">

          {/* Input Panel */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <Database size={20} className="text-blue-500" />
              ورودی‌ها
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">کلمات کلیدی اولیه (Seed)</label>
                <textarea
                  className="w-full h-32 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm resize-none"
                  placeholder="هر خط یک کلمه...&#10;خرید موبایل&#10;آموزش سئو"
                  value={seeds}
                  onChange={(e) => setSeeds(e.target.value)}
                  disabled={isProcessing || isAiFiltering}
                ></textarea>
                <p className="text-xs text-gray-500 mt-1 text-left ltr">
                  {seeds.split('\n').filter(s => s.trim()).length} Seed Keywords
                </p>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">زبان (hl)</label>
                  <select 
                    value={language} 
                    onChange={(e) => setLanguage(e.target.value)}
                    className="w-full p-2 border border-gray-300 rounded-md text-sm"
                    disabled={isProcessing || isAiFiltering}
                  >
                    <option value="fa">فارسی (fa)</option>
                    <option value="en">English (en)</option>
                    <option value="ar">Arabic (ar)</option>
                    <option value="tr">Turkish (tr)</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">منطقه (gl)</label>
                  <select 
                    value={country} 
                    onChange={(e) => setCountry(e.target.value)}
                    className="w-full p-2 border border-gray-300 rounded-md text-sm"
                    disabled={isProcessing || isAiFiltering}
                  >
                    <option value="ir">ایران (ir)</option>
                    <option value="us">United States (us)</option>
                    <option value="ae">UAE (ae)</option>
                    <option value="tr">Turkey (tr)</option>
                  </select>
                </div>
              </div>
            </div>
          </div>

          {/* AI Filter Panel */}
          <div className="bg-gradient-to-br from-indigo-50 to-purple-50 rounded-xl shadow-sm border border-indigo-100 p-5">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2 text-indigo-900">
              <Sparkles size={20} className="text-indigo-600" />
              فیلتر هوشمند (AI)
            </h2>
            <div className="space-y-3">
              <div>
                <label className="block text-sm font-medium text-indigo-800 mb-1">چه کلماتی را نگه دارم/حذف کنم؟</label>
                <textarea 
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  disabled={isProcessing || isAiFiltering}
                  placeholder="مثال: کلمات مربوط به 'رایگان' یا 'کرک' را حذف کن. فقط کلمات خرید آنلاین را نگه دار."
                  className="w-full h-24 p-3 border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 text-sm resize-none bg-white"
                />
              </div>
              <button
                onClick={handleAiFilter}
                disabled={isProcessing || isAiFiltering || results.length === 0}
                className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
              >
                {isAiFiltering ? (
                  <>
                    <Loader2 size={18} className="animate-spin" />
                    <span>در حال تحلیل...</span>
                  </>
                ) : (
                  <>
                    <Filter size={18} />
                    <span>اعمال فیلتر روی نتایج</span>
                  </>
                )}
              </button>
              <p className="text-xs text-indigo-400 leading-relaxed">
                این ابزار لیست نتایج فعلی را به Gemini می‌فرستد و بر اساس دستور شما آن را پالایش می‌کند.
              </p>
            </div>
          </div>

          {/* Settings Panel */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <Settings size={20} className="text-gray-500" />
              تنظیمات پیشرفته
            </h2>

            <div className="space-y-6">
              <div>
                <div className="flex justify-between mb-1">
                  <label className="text-sm font-medium text-gray-700">عمق جستجو (Depth)</label>
                  <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">لایه {depth}</span>
                </div>
                <input 
                  type="range" 
                  min="1" 
                  max="3" 
                  step="1"
                  value={depth}
                  onChange={(e) => setDepth(parseInt(e.target.value))}
                  disabled={isProcessing || isAiFiltering}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                />
              </div>

              <div>
                <div className="flex justify-between mb-1">
                  <label className="text-sm font-medium text-gray-700">تعداد درخواست همزمان</label>
                  <span className="text-xs text-gray-500">{concurrency} درخواست</span>
                </div>
                <input 
                  type="range" 
                  min="1" 
                  max="5" 
                  value={concurrency}
                  onChange={(e) => setConcurrency(parseInt(e.target.value))}
                  disabled={isProcessing || isAiFiltering}
                  className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                />
              </div>

              <div>
                <div className="flex justify-between mb-1">
