                    <div className="space-y-4">
                        <Loader2 size={48} className="text-blue-500 animate-spin mx-auto" />
                        <p className="text-gray-600">در حال پردازش... ({progress.current} / {progress.total})</p>
                        <div className="w-64 h-2 bg-gray-100 rounded-full mx-auto overflow-hidden">
                            <div 
                                className="h-full bg-blue-500 transition-all duration-300"
                                style={{ width: `${(progress.current / Math.max(progress.total, 1)) * 100}%` }}
