        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #6b7280;
        }
      `}</style>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
// Note: In a real environment, ensure process.env.API_KEY is set.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Filters a list of keywords based on a user prompt using Gemini.
 * Returns the list of keywords that SHOULD BE KEPT.
 */
export const filterKeywordsBatch = async (
  keywords: string[],
  userPrompt: string
): Promise<string[]> => {
  if (!keywords.length) return [];

  const modelId = 'gemini-3-flash-preview'; 

  // Schema to ensure we get a clean list of strings back
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      keptKeywords: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "The list of keywords that match the criteria and should be kept."
      }
    },
    required: ["keptKeywords"]
  };

  const systemInstruction = `
    You are a specialized SEO keyword filtering assistant.
    Your task is to analyze a list of keywords and filter them based strictly on the user's criteria.

    Rules:
    1. You will receive a JSON list of keywords and a filtering criteria (Prompt).
    2. Return ONLY the keywords that satisfy the user's criteria in the 'keptKeywords' array.
    3. If the user asks to "remove" something, return the list WITHOUT those items.
    4. If the user asks to "keep" something, return ONLY those items.
    5. Do not modify the text of the keywords. Return them exactly as received.
  `;

  const prompt = `
    User Filtering Criteria: "${userPrompt}"

    Keywords List to Process:
    ${JSON.stringify(keywords)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1, // Low temperature for deterministic results
      },
    });

    const text = response.text;
    if (!text) return keywords; // Fallback: keep all if response is empty

    const parsed = JSON.parse(text);
    return parsed.keptKeywords || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    // In case of error, we throw it so the UI can handle the retry or logging
    throw error;
  }
};

/**
 * Analyzes SERP-based clusters to assign Pillar topics, refine Cluster names, and determine Intent.
 */
export const analyzeSerpClusters = async (
  clusters: { id: number; keywords: string[] }[]
): Promise<{ id: number; pillar: string; clusterName: string; intent: string }[]> => {
  if (!clusters.length) return [];

  const modelId = 'gemini-3-flash-preview';

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      analysis: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.INTEGER, description: "The original cluster ID provided in the input." },
            pillar: { type: Type.STRING, description: "The broad Pillar Page topic this cluster belongs to." },
            clusterName: { type: Type.STRING, description: "A refined, descriptive name for this specific cluster content." },
            intent: { 
              type: Type.STRING, 
              description: "The primary search intent: Informational, Transactional, Commercial, or Navigational." 
            }
          },
          required: ["id", "pillar", "clusterName", "intent"]
        }
      }
    },
    required: ["analysis"]
  };

  const systemInstruction = `
    You are a world-class SEO strategist. 
    I will provide you with a list of keyword clusters that were generated based on SERP overlap (Google Search Results similarity).

    Your Task:
    1. Analyze the keywords in each cluster to understand the topic.
    2. Assign a 'Pillar' (Broad Topic) that groups related clusters together.
    3. Assign a 'Cluster Name' (Specific Page Topic). 
       - CRITICAL: If two different clusters (different IDs) are semantically identical or should be targeted by the SAME page, give them the EXACT SAME 'Cluster Name'. This acts as a merging suggestion.
    4. Determine the primary 'Search Intent' (Informational, Transactional, Commercial, Navigational).

    Input Format: A list of objects { id, keywords }.
    Output Format: A list of objects { id, pillar, clusterName, intent }.
  `;

  // Simplify input to save tokens: take top 5 keywords per cluster
  const simplifiedInput = clusters.map(c => ({
    id: c.id,
    keywords: c.keywords.slice(0, 5) // Send top 5 keywords for context
  }));

  const prompt = `
    Analyze these keyword clusters:
    ${JSON.stringify(simplifiedInput)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.2,
      },
    });

    const text = response.text;
    if (!text) return [];

    const parsed = JSON.parse(text);
    return parsed.analysis || [];

  } catch (error) {
    console.error("Gemini API Error (Cluster Analysis):", error);
    throw error;
  }
};

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  Settings, 
  Play, 
  Download, 
  AlertCircle, 
  CheckCircle2, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  PieChart,
  BarChart3,
  BrainCircuit,
  Lightbulb
} from 'lucide-react';
import { analyzeSerpClusters } from '../services/geminiService';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

export default function KeywordClusterer() {
  const [file, setFile] = useState<File | null>(null);
  const [domain, setDomain] = useState<string>('');
  const [apiKey, setApiKey] = useState<string>('');
  const [threshold, setThreshold] = useState<number>(5);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [resultData, setResultData] = useState<any[] | null>(null);
  const [marketShare, setMarketShare] = useState<any[] | null>(null);

  // AI State
  const [isAiAnalyzing, setIsAiAnalyzing] = useState<boolean>(false);
  const [aiAnalysisResult, setAiAnalysisResult] = useState<any[] | null>(null);

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const getTopAddresses = async (keyword: string, currentDomain: string, key: string) => {
    const url = "https://google.serper.dev/search";
    const headers = {
        'X-API-KEY': key,
        'Content-Type': 'application/json'
    };
    const payload = JSON.stringify({ q: keyword, gl: "ir", hl: "fa" });

    try {
        const response = await fetch(url, {
            method: 'POST',
            headers: headers,
            body: payload
        });

        if (!response.ok) throw new Error(`Serper API Error: ${response.status}`);

        const data = await response.json();
        const addresses: string[] = [];
        let ourRank: number | null = null;
        let ourUrl: string | null = null;
        let titleCount = 0;
        let descCount = 0;
        const kLower = keyword.toLowerCase();

        const items = data.organic || [];
        items.forEach((item: any, idx: number) => {
            const link = item.link || '';
            const title = item.title || '';
            const snippet = item.snippet || '';

            if (link) addresses.push(link);

            // Stats
            titleCount += (title.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;
            descCount += (snippet.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;

            // Rank
            if (link && currentDomain && link.includes(currentDomain) && ourRank === null) {
                ourRank = idx + 1;
                ourUrl = link;
            }
        });

        return { addresses, ourRank, ourUrl, titleCount, descCount };
    } catch (error) {
        return { addresses: [], ourRank: null, ourUrl: null, titleCount: 0, descCount: 0 };
    }
  };

  const handleRun = async () => {
    if (!file) return addLog('لطفا فایل اکسل را انتخاب کنید.', 'error');
    if (!domain) return addLog('لطفا دامنه را وارد کنید.', 'error');
    if (!apiKey) return addLog('لطفا API Key سرویس Serper را وارد کنید.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setResultData(null);
    setMarketShare(null);
    setAiAnalysisResult(null);

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        // Normalize keys to lowercase
        jsonData = jsonData.map(row => {
            const newRow: any = {};
            Object.keys(row).forEach(key => {
                newRow[key.trim().toLowerCase().replace(/ /g, '_')] = row[key];
            });
            return newRow;
        });

        // Filter valid keywords
        const keywordsData = jsonData.filter(row => row.top_queries && String(row.top_queries).trim() !== '');

        if (keywordsData.length === 0) {
            setIsProcessing(false);
            return addLog('هیچ ستون top_queries معتبری یافت نشد.', 'error');
        }

        addLog(`${keywordsData.length} کلمه کلیدی یافت شد. شروع پردازش...`, 'info');
        setProgress({ current: 0, total: keywordsData.length });

        // Step 1: Fetch SERP Data
        const serpResults: Record<string, any> = {};

        // Batch requests to avoid overwhelming the browser/API (Chunk of 3)
        const BATCH_SIZE = 3;
        for (let i = 0; i < keywordsData.length; i += BATCH_SIZE) {
            const batch = keywordsData.slice(i, i + BATCH_SIZE);
            await Promise.all(batch.map(async (row) => {
                const kw = String(row.top_queries).trim();
                const res = await getTopAddresses(kw, domain, apiKey);
                serpResults[kw] = res;
            }));

            setProgress({ current: Math.min(i + BATCH_SIZE, keywordsData.length), total: keywordsData.length });
            // Small delay
            await new Promise(r => setTimeout(r, 500));
        }

        // --- Market Share Analysis ---
        addLog('در حال محاسبه سهم بازار رقبا...', 'info');
        const domainCounts: Record<string, number> = {};
        let totalUrls = 0;

        Object.values(serpResults).forEach((res: any) => {
            const addresses = res.addresses || [];
            addresses.forEach((url: string) => {
                try {
                    const hostname = new URL(url).hostname.replace(/^www\./, '');
                    if (hostname) {
                        domainCounts[hostname] = (domainCounts[hostname] || 0) + 1;
                        totalUrls++;
                    }
                } catch (e) {}
            });
        });

        const marketShareList = Object.entries(domainCounts)
            .map(([domain, count]) => ({
                Domain: domain,
                Frequency: count,
                'Share (%)': totalUrls > 0 ? ((count / totalUrls) * 100).toFixed(2) : "0"
            }))
            .sort((a, b) => b.Frequency - a.Frequency);

        setMarketShare(marketShareList);

        // Step 2: Clustering
        addLog('در حال خوشه‌بندی کلمات...', 'info');
        const clusters: string[][] = [];
        const visited = new Set<string>();
        const keywordsList = keywordsData.map(r => String(r.top_queries).trim());

        for (let i = 0; i < keywordsList.length; i++) {
            const kw1 = keywordsList[i];
            if (visited.has(kw1)) continue;

            const cluster = [kw1];
            visited.add(kw1);
            const set1 = new Set(serpResults[kw1]?.addresses || []);

            for (let j = i + 1; j < keywordsList.length; j++) {
                const kw2 = keywordsList[j];
                if (visited.has(kw2)) continue;

                const set2 = new Set(serpResults[kw2]?.addresses || []);
                // Intersection count
                const intersection = new Set([...set1].filter(x => set2.has(x)));

                if (intersection.size >= threshold) {
                    cluster.push(kw2);
                    visited.add(kw2);
                }
            }
            clusters.push(cluster);
        }

        // Step 3: Prepare Output
        const finalRows: any[] = [];
        const optionalFields = ['clicks', 'impressions', 'ctr', 'position'];

        clusters.forEach((cluster, idx) => {
            const clusterId = idx + 1;
            const firstQuery = cluster[0];
            let clusterTotalImp = 0;

            // Calculate total impressions first if needed
            cluster.forEach(kw => {
                 const originalRow = keywordsData.find(r => String(r.top_queries).trim() === kw);
                 if (originalRow && originalRow.impressions) {
                     clusterTotalImp += Number(originalRow.impressions) || 0;
                 }
            });

            cluster.forEach(kw => {
                const originalRow = keywordsData.find(r => String(r.top_queries).trim() === kw);
                const serp = serpResults[kw];

                const outputRow: any = {
                    'Cluster ID': clusterId,
                    'First Query of Cluster': firstQuery,
                    'Query': kw,
                    'Our Rank': serp?.ourRank || '',
                    'Our URL': serp?.ourUrl || '',
                    'Title Count': serp?.titleCount || 0,
                    'Description Count': serp?.descCount || 0,
                    'Cluster Total Impression': clusterTotalImp
                };

                // Add original extra fields
                if (originalRow) {
                    optionalFields.forEach(f => {
                        if (originalRow[f] !== undefined) {
                            outputRow[f.charAt(0).toUpperCase() + f.slice(1)] = originalRow[f];
                        }
                    });
                }
                finalRows.push(outputRow);
            });
        });

        setResultData(finalRows);
        addLog(`پردازش تمام شد. ${clusters.length} خوشه ایجاد شد.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا در پردازش فایل: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleAiAnalysis = async () => {
    if (!resultData || resultData.length === 0) return;
    if (!process.env.API_KEY) {
        addLog('API Key تنظیم نشده است.', 'error');
        return;
    }

    setIsAiAnalyzing(true);
    addLog('شروع تحلیل هوشمند (Pillar/Cluster + Intent)...', 'info');

    try {
        // Group keywords by Cluster ID
        const clusterMap = new Map<number, string[]>();
        resultData.forEach(row => {
            const id = row['Cluster ID'];
            if (!clusterMap.has(id)) {
                clusterMap.set(id, []);
            }
            clusterMap.get(id)?.push(row['Query']);
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        // Call Gemini
        const analysis = await analyzeSerpClusters(clustersInput);

        // Map analysis back to a friendly format
        setAiAnalysisResult(analysis);
        addLog('تحلیل هوشمند با موفقیت انجام شد.', 'success');

    } catch (error: any) {
        console.error(error);
        addLog('خطا در تحلیل هوشمند: ' + error.message, 'error');
    } finally {
        setIsAiAnalyzing(false);
    }
  };

  const handleDownload = () => {
    if (!resultData) return;
    const wb = XLSX.utils.book_new();

    // 1. Base Data (Merged with AI if available)
    let exportData = [...resultData];
    if (aiAnalysisResult) {
        exportData = exportData.map(row => {
            const aiInfo = aiAnalysisResult.find(a => a.id === row['Cluster ID']);
            return {
                ...row,
                'AI Pillar': aiInfo?.pillar || '-',
                'AI Cluster Name': aiInfo?.clusterName || '-',
                'AI Intent': aiInfo?.intent || '-'
            };
        });
    }

    const ws1 = XLSX.utils.json_to_sheet(exportData);
    XLSX.utils.book_append_sheet(wb, ws1, "Clusters Data");

    // 2. Market Share
    if (marketShare) {
        const ws2 = XLSX.utils.json_to_sheet(marketShare);
        XLSX.utils.book_append_sheet(wb, ws2, "Market Share Analysis");
    }

    // 3. AI Summary (if available)
    if (aiAnalysisResult) {
         // Create a summary view: Pillar -> Cluster Name -> Keywords Count
         const summary = aiAnalysisResult.map(a => {
             const keywordsCount = resultData.filter(r => r['Cluster ID'] === a.id).length;
             return {
                 'Original Cluster ID': a.id,
                 'Pillar Topic': a.pillar,
                 'Cluster Name (Refined)': a.clusterName,
                 'Search Intent': a.intent,
                 'Keywords Count': keywordsCount
             };
         });
         const ws3 = XLSX.utils.json_to_sheet(summary);
         XLSX.utils.book_append_sheet(wb, ws3, "AI Strategy Plan");
    }

    XLSX.writeFile(wb, "clustered_keywords_enhanced.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
       {/* Config Panel */}
       <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
             <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
               <Settings size={20} className="text-blue-500" />
               تنظیمات کلاستر
             </h2>

             <div className="space-y-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">فایل اکسل ورودی</label>
                 <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-blue-500 transition-colors">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-2 text-gray-500">
                        <FileSpreadsheet size={32} />
                        <span className="text-xs">{file ? file.name : "فایل را اینجا رها کنید یا کلیک کنید"}</span>
                    </div>
                 </div>
                 <p className="text-xs text-gray-400 mt-1">فایل باید ستون 'top_queries' داشته باشد.</p>
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">دامنه هدف (Domain)</label>
                 <input 
                   type="text" 
                   value={domain}
                   onChange={(e) => setDomain(e.target.value)}
                   placeholder="example.com"
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Serper API Key</label>
                 <input 
                   type="password" 
                   value={apiKey}
                   onChange={(e) => setApiKey(e.target.value)}
                   placeholder="sk-..."
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <div className="flex justify-between mb-1">
                   <label className="text-sm font-medium text-gray-700">آستانه همپوشانی (Threshold)</label>
                   <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">{threshold} لینک مشترک</span>
                 </div>
                 <input 
                   type="range" 
                   min="1" 
                   max="10" 
                   value={threshold}
                   onChange={(e) => setThreshold(Number(e.target.value))}
                   className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                   disabled={isProcessing}
                 />
               </div>

               <button 
                 onClick={handleRun}
                 disabled={isProcessing || isAiAnalyzing}
                 className="w-full flex items-center justify-center gap-2 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 disabled:opacity-50 transition-all mt-4"
               >
                 {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Play size={18} />}
                 <span>شروع خوشه‌بندی SERP</span>
               </button>
             </div>
          </div>

          <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
             <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
              <Terminal size={14} />
              Logs
            </h2>
            <div className="flex-1 overflow-y-auto font-mono text-xs space-y-1 custom-scrollbar">
              {logs.map((log) => (
                <div key={log.id} className={`flex gap-2 ${
                  log.type === 'error' ? 'text-red-400' : 
                  log.type === 'success' ? 'text-green-400' : 'text-gray-300'
                }`}>
                  <span className="text-gray-600">[{log.timestamp}]</span>
                  <span>{log.message}</span>
                </div>
              ))}
            </div>
          </div>
       </div>

       {/* Result Panel */}
       <div className="lg:col-span-8 flex flex-col h-full space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col min-h-[400px]">
                {resultData ? (
                    <div className="flex-1 flex flex-col gap-6">

                        {/* Summary Header */}
                        <div className="bg-green-50 border border-green-100 rounded-lg p-4 flex items-center justify-between flex-wrap gap-4">
                            <div className="flex items-center gap-3">
                                <div className="bg-green-500 text-white p-2 rounded-full">
                                    <CheckCircle2 size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-gray-800">خوشه‌بندی SERP انجام شد</h3>
                                    <p className="text-sm text-gray-600">{resultData.length} کلمه دسته‌بندی شدند.</p>
                                </div>
                            </div>

                            <div className="flex gap-2">
                                {/* AI Button */}
                                {!aiAnalysisResult && (
                                    <button 
                                        onClick={handleAiAnalysis}
                                        disabled={isAiAnalyzing}
                                        className="flex items-center gap-2 bg-purple-600 text-white px-4 py-2 rounded-lg hover:bg-purple-700 transition-colors shadow-sm disabled:opacity-70"
                                    >
                                        {isAiAnalyzing ? <Loader2 size={18} className="animate-spin" /> : <BrainCircuit size={18} />}
                                        <span>تحلیل پیلار/کلاستر و اینتنت</span>
                                    </button>
                                )}

                                <button 
                                    onClick={handleDownload}
                                    className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors shadow-sm"
                                >
                                    <Download size={18} />
                                    <span>دانلود گزارش</span>
                                </button>
                            </div>
                        </div>

                        {/* AI Analysis Result View */}
                        {aiAnalysisResult && (
                            <div className="animate-in fade-in slide-in-from-bottom-2">
                                <h4 className="text-lg font-bold text-gray-800 mb-3 flex items-center gap-2">
                                    <Lightbulb size={20} className="text-purple-500" />
                                    پیشنهاد استراتژی محتوا (AI)
                                </h4>
                                <div className="bg-purple-50 rounded-lg border border-purple-100 overflow-hidden">
                                    <div className="overflow-x-auto max-h-60 custom-scrollbar">
                                        <table className="w-full text-sm text-right">
                                            <thead className="bg-purple-100 text-purple-900 border-b border-purple-200 sticky top-0">
                                                <tr>
                                                    <th className="px-4 py-2">ID</th>
                                                    <th className="px-4 py-2">پیلار (موضوع اصلی)</th>
                                                    <th className="px-4 py-2">نام کلاستر (پیشنهادی)</th>
                                                    <th className="px-4 py-2 text-center">اینتنت</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-purple-200 bg-white">
                                                {aiAnalysisResult.map((item, idx) => (
                                                    <tr key={idx} className="hover:bg-purple-50/50">
                                                        <td className="px-4 py-2 text-gray-500">{item.id}</td>
                                                        <td className="px-4 py-2 font-medium text-gray-800">{item.pillar}</td>
                                                        <td className="px-4 py-2 text-gray-700">{item.clusterName}</td>
                                                        <td className="px-4 py-2 text-center">
                                                            <span className={`px-2 py-0.5 rounded text-xs border ${
                                                                item.intent.toLowerCase().includes('informational') ? 'bg-blue-50 text-blue-700 border-blue-200' :
                                                                item.intent.toLowerCase().includes('transactional') ? 'bg-green-50 text-green-700 border-green-200' :
                                                                'bg-gray-100 text-gray-700 border-gray-200'
                                                            }`}>
                                                                {item.intent}
                                                            </span>
                                                        </td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                    <div className="p-2 text-center text-xs text-purple-600 bg-purple-50/80">
                                        * این تحلیل توسط هوش مصنوعی انجام شده و در فایل خروجی نهایی موجود است.
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Market Share Preview */}
                        {marketShare && marketShare.length > 0 && (
                            <div className="flex-1">
                                <h4 className="text-lg font-bold text-gray-700 mb-4 flex items-center gap-2">
                                    <BarChart3 size={20} className="text-blue-500"/>
                                    برترین رقبا (سهم بازار)
                                </h4>
                                <div className="bg-gray-50 rounded-lg border border-gray-200 overflow-hidden">
                                    <table className="w-full text-sm text-right">
                                        <thead className="bg-gray-100 text-gray-600 border-b border-gray-200">
                                            <tr>
                                                <th className="px-4 py-3">رتبه</th>
                                                <th className="px-4 py-3">دامنه</th>
                                                <th className="px-4 py-3 text-center">تعداد حضور</th>
                                                <th className="px-4 py-3 text-center">سهم (%)</th>
                                                <th className="px-4 py-3 text-left w-32">وضعیت</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-gray-200">
                                            {marketShare.slice(0, 5).map((item, idx) => (
                                                <tr key={idx} className="hover:bg-white transition-colors">
                                                    <td className="px-4 py-3 text-gray-500">{idx + 1}</td>
                                                    <td className="px-4 py-3 font-medium text-gray-800" dir="ltr">{item.Domain}</td>
                                                    <td className="px-4 py-3 text-center text-gray-600">{item.Frequency}</td>
                                                    <td className="px-4 py-3 text-center font-bold text-blue-600">{item['Share (%)']}%</td>
                                                    <td className="px-4 py-3">
                                                        <div className="w-full bg-gray-200 rounded-full h-2">
                                                            <div 
                                                                className="bg-blue-500 h-2 rounded-full" 
                                                                style={{ width: `${Math.min(100, parseFloat(item['Share (%)']))}%` }}
                                                            ></div>
                                                        </div>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        )}
                    </div>
                ) : isProcessing ? (
                    <div className="flex flex-col items-center justify-center flex-1 space-y-4">
                        <Loader2 size={48} className="text-blue-500 animate-spin" />
                        <div className="text-center">
                            <p className="text-lg font-medium text-gray-700">در حال آنالیز کلمات و رقبا...</p>
                            <p className="text-sm text-gray-500 mt-1">{progress.current} از {progress.total} کلمه پردازش شده</p>
                        </div>
                        <div className="w-64 h-2 bg-gray-100 rounded-full overflow-hidden mt-4">
                            <div 
                                className="h-full bg-blue-500 transition-all duration-300"
                                style={{ width: `${(progress.current / Math.max(progress.total, 1)) * 100}%` }}
                            />
                        </div>
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center flex-1 text-gray-400 space-y-4">
                        <div className="bg-gray-50 p-6 rounded-full">
                            <PieChart size={48} className="opacity-20" />
                        </div>
                        <div className="text-center">
                            <h3 className="text-lg font-medium text-gray-600">آماده برای شروع</h3>
                            <p className="text-sm mt-1">فایل اکسل کلمات را بارگذاری کنید تا خوشه‌بندی و تحلیل رقبا انجام شود.</p>
                        </div>
                    </div>
                )}
            </div>
       </div>

       <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #1f2937;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #4b5563;
          border-radius: 3px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #6b7280;
        }
      `}</style>
    </div>
  );
}

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  Settings, 
  Play, 
  Download, 
  AlertCircle, 
  CheckCircle2, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  PieChart,
  BarChart3,
  BrainCircuit,
  Lightbulb
} from 'lucide-react';
import { analyzeSerpClusters } from '../services/geminiService';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

export default function KeywordClusterer() {
  const [file, setFile] = useState<File | null>(null);
  const [domain, setDomain] = useState<string>('');
  const [apiKey, setApiKey] = useState<string>('');
  const [threshold, setThreshold] = useState<number>(5);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [resultData, setResultData] = useState<any[] | null>(null);
  const [marketShare, setMarketShare] = useState<any[] | null>(null);

  // AI State
  const [isAiAnalyzing, setIsAiAnalyzing] = useState<boolean>(false);
  const [aiAnalysisResult, setAiAnalysisResult] = useState<any[] | null>(null);

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const getTopAddresses = async (keyword: string, currentDomain: string, key: string) => {
    const url = "https://google.serper.dev/search";
    const headers = {
        'X-API-KEY': key,
        'Content-Type': 'application/json'
    };
    const payload = JSON.stringify({ q: keyword, gl: "ir", hl: "fa" });

    try {
        const response = await fetch(url, {
            method: 'POST',
            headers: headers,
            body: payload
        });

        if (!response.ok) throw new Error(`Serper API Error: ${response.status}`);

        const data = await response.json();
        const addresses: string[] = [];
        let ourRank: number | null = null;
        let ourUrl: string | null = null;
        let titleCount = 0;
        let descCount = 0;
        const kLower = keyword.toLowerCase();

        const items = data.organic || [];
        items.forEach((item: any, idx: number) => {
            const link = item.link || '';
            const title = item.title || '';
            const snippet = item.snippet || '';

            if (link) addresses.push(link);

            // Stats
            titleCount += (title.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;
            descCount += (snippet.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;

            // Rank
            // Only calculate rank if currentDomain is provided and valid
            if (link && currentDomain && link.includes(currentDomain) && ourRank === null) {
                ourRank = idx + 1;
                ourUrl = link;
            }
        });

        return { addresses, ourRank, ourUrl, titleCount, descCount };
    } catch (error) {
        return { addresses: [], ourRank: null, ourUrl: null, titleCount: 0, descCount: 0 };
    }
  };

  const handleRun = async () => {
    if (!file) return addLog('لطفا فایل اکسل را انتخاب کنید.', 'error');
    // Domain is optional now
    if (!apiKey) return addLog('لطفا API Key سرویس Serper را وارد کنید.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setResultData(null);
    setMarketShare(null);
    setAiAnalysisResult(null);

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        // Normalize keys to lowercase
        jsonData = jsonData.map(row => {
            const newRow: any = {};
            Object.keys(row).forEach(key => {
                newRow[key.trim().toLowerCase().replace(/ /g, '_')] = row[key];
            });
            return newRow;
        });

        // Filter valid keywords
        const keywordsData = jsonData.filter(row => row.top_queries && String(row.top_queries).trim() !== '');

        if (keywordsData.length === 0) {
            setIsProcessing(false);
            return addLog('هیچ ستون top_queries معتبری یافت نشد.', 'error');
        }

        addLog(`${keywordsData.length} کلمه کلیدی یافت شد. شروع پردازش...`, 'info');
        setProgress({ current: 0, total: keywordsData.length });

        // Step 1: Fetch SERP Data
        const serpResults: Record<string, any> = {};

        // Batch requests to avoid overwhelming the browser/API (Chunk of 3)
        const BATCH_SIZE = 3;
        for (let i = 0; i < keywordsData.length; i += BATCH_SIZE) {
            const batch = keywordsData.slice(i, i + BATCH_SIZE);
            await Promise.all(batch.map(async (row) => {
                const kw = String(row.top_queries).trim();
                const res = await getTopAddresses(kw, domain, apiKey);
                serpResults[kw] = res;
            }));

            setProgress({ current: Math.min(i + BATCH_SIZE, keywordsData.length), total: keywordsData.length });
            // Small delay
            await new Promise(r => setTimeout(r, 500));
        }

        // --- Market Share Analysis ---
        addLog('در حال محاسبه سهم بازار رقبا...', 'info');
        const domainCounts: Record<string, number> = {};
        let totalUrls = 0;

        Object.values(serpResults).forEach((res: any) => {
            const addresses = res.addresses || [];
            addresses.forEach((url: string) => {
                try {
                    const hostname = new URL(url).hostname.replace(/^www\./, '');
                    if (hostname) {
                        domainCounts[hostname] = (domainCounts[hostname] || 0) + 1;
                        totalUrls++;
                    }
                } catch (e) {}
            });
        });

        const marketShareList = Object.entries(domainCounts)
            .map(([domain, count]) => ({
                Domain: domain,
                Frequency: count,
                'Share (%)': totalUrls > 0 ? ((count / totalUrls) * 100).toFixed(2) : "0"
            }))
            .sort((a, b) => b.Frequency - a.Frequency);

        setMarketShare(marketShareList);

        // Step 2: Clustering
        addLog('در حال خوشه‌بندی کلمات...', 'info');
        const clusters: string[][] = [];
        const visited = new Set<string>();
        const keywordsList = keywordsData.map(r => String(r.top_queries).trim());

        for (let i = 0; i < keywordsList.length; i++) {
            const kw1 = keywordsList[i];
            if (visited.has(kw1)) continue;

            const cluster = [kw1];
            visited.add(kw1);
            const set1 = new Set(serpResults[kw1]?.addresses || []);

            for (let j = i + 1; j < keywordsList.length; j++) {
                const kw2 = keywordsList[j];
                if (visited.has(kw2)) continue;

                const set2 = new Set(serpResults[kw2]?.addresses || []);
                // Intersection count
                const intersection = new Set([...set1].filter(x => set2.has(x)));

                if (intersection.size >= threshold) {
                    cluster.push(kw2);
                    visited.add(kw2);
                }
            }
            clusters.push(cluster);
        }

        // Step 3: Prepare Output
        const finalRows: any[] = [];
        const optionalFields = ['clicks', 'impressions', 'ctr', 'position'];

        clusters.forEach((cluster, idx) => {
            const clusterId = idx + 1;
            const firstQuery = cluster[0];
            let clusterTotalImp = 0;

            // Calculate total impressions first if needed
            cluster.forEach(kw => {
                 const originalRow = keywordsData.find(r => String(r.top_queries).trim() === kw);
                 if (originalRow && originalRow.impressions) {
                     clusterTotalImp += Number(originalRow.impressions) || 0;
                 }
            });

            cluster.forEach(kw => {
                const originalRow = keywordsData.find(r => String(r.top_queries).trim() === kw);
                const serp = serpResults[kw];

                const outputRow: any = {
                    'Cluster ID': clusterId,
                    'First Query of Cluster': firstQuery,
                    'Query': kw,
                    'Our Rank': serp?.ourRank || '',
                    'Our URL': serp?.ourUrl || '',
                    'Title Count': serp?.titleCount || 0,
                    'Description Count': serp?.descCount || 0,
                    'Cluster Total Impression': clusterTotalImp
                };

                // Add original extra fields
                if (originalRow) {
                    optionalFields.forEach(f => {
                        if (originalRow[f] !== undefined) {
                            outputRow[f.charAt(0).toUpperCase() + f.slice(1)] = originalRow[f];
                        }
                    });
                }
                finalRows.push(outputRow);
            });
        });

        setResultData(finalRows);
        addLog(`پردازش تمام شد. ${clusters.length} خوشه ایجاد شد.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا در پردازش فایل: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleAiAnalysis = async () => {
    if (!resultData || resultData.length === 0) return;
    if (!process.env.API_KEY) {
        addLog('API Key تنظیم نشده است.', 'error');
        return;
    }

    setIsAiAnalyzing(true);
    addLog('شروع تحلیل هوشمند (Pillar/Cluster + Intent)...', 'info');

    try {
        // Group keywords by Cluster ID
        const clusterMap = new Map<number, string[]>();
        resultData.forEach(row => {
            const id = row['Cluster ID'];
            if (!clusterMap.has(id)) {
                clusterMap.set(id, []);
            }
            clusterMap.get(id)?.push(row['Query']);
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        // Call Gemini
        const analysis = await analyzeSerpClusters(clustersInput);

        // Map analysis back to a friendly format
        setAiAnalysisResult(analysis);
        addLog('تحلیل هوشمند با موفقیت انجام شد.', 'success');

    } catch (error: any) {
        console.error(error);
        addLog('خطا در تحلیل هوشمند: ' + error.message, 'error');
    } finally {
        setIsAiAnalyzing(false);
    }
  };

  const handleDownload = () => {
    if (!resultData) return;
    const wb = XLSX.utils.book_new();

    // 1. Base Data (Merged with AI if available)
    let exportData = [...resultData];
    if (aiAnalysisResult) {
        exportData = exportData.map(row => {
            const aiInfo = aiAnalysisResult.find(a => a.id === row['Cluster ID']);
            return {
                ...row,
                'AI Pillar': aiInfo?.pillar || '-',
                'AI Cluster Name': aiInfo?.clusterName || '-',
                'AI Intent': aiInfo?.intent || '-'
            };
        });
    }

    const ws1 = XLSX.utils.json_to_sheet(exportData);
    XLSX.utils.book_append_sheet(wb, ws1, "Clusters Data");

    // 2. Market Share
    if (marketShare) {
        const ws2 = XLSX.utils.json_to_sheet(marketShare);
        XLSX.utils.book_append_sheet(wb, ws2, "Market Share Analysis");
    }

    // 3. AI Summary (if available)
    if (aiAnalysisResult) {
         // Create a summary view: Pillar -> Cluster Name -> Keywords Count
         const summary = aiAnalysisResult.map(a => {
             const keywordsCount = resultData.filter(r => r['Cluster ID'] === a.id).length;
             return {
                 'Original Cluster ID': a.id,
                 'Pillar Topic': a.pillar,
                 'Cluster Name (Refined)': a.clusterName,
                 'Search Intent': a.intent,
                 'Keywords Count': keywordsCount
             };
         });
         const ws3 = XLSX.utils.json_to_sheet(summary);
         XLSX.utils.book_append_sheet(wb, ws3, "AI Strategy Plan");
    }

    XLSX.writeFile(wb, "clustered_keywords_enhanced.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
       {/* Config Panel */}
       <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
             <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
               <Settings size={20} className="text-blue-500" />
               تنظیمات کلاستر
             </h2>

             <div className="space-y-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">فایل اکسل ورودی</label>
                 <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-blue-500 transition-colors">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-2 text-gray-500">
                        <FileSpreadsheet size={32} />
                        <span className="text-xs">{file ? file.name : "فایل را اینجا رها کنید یا کلیک کنید"}</span>
                    </div>
                 </div>
                 <p className="text-xs text-gray-400 mt-1">فایل باید ستون 'top_queries' داشته باشد.</p>
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">
                   دامنه هدف (Domain)
                   <span className="text-gray-400 font-normal text-xs mr-1">(اختیاری)</span>
                 </label>
                 <input 
                   type="text" 
                   value={domain}
                   onChange={(e) => setDomain(e.target.value)}
                   placeholder="example.com"
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Serper API Key</label>
                 <input 
                   type="password" 
                   value={apiKey}
                   onChange={(e) => setApiKey(e.target.value)}
                   placeholder="sk-..."
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <div className="flex justify-between mb-1">
                   <label className="text-sm font-medium text-gray-700">آستانه همپوشانی (Threshold)</label>
                   <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">{threshold} لینک مشترک</span>
                 </div>
                 <input 
                   type="range" 
                   min="1" 
                   max="10" 
                   value={threshold}
                   onChange={(e) => setThreshold(Number(e.target.value))}
                   className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                   disabled={isProcessing}
                 />
               </div>

               <button 
                 onClick={handleRun}
                 disabled={isProcessing || isAiAnalyzing}
                 className="w-full flex items-center justify-center gap-2 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 disabled:opacity-50 transition-all mt-4"
               >
                 {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Play size={18} />}
                 <span>شروع خوشه‌بندی SERP</span>
               </button>
             </div>
          </div>

          <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
             <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
              <Terminal size={14} />
              Logs
            </h2>
            <div className="flex-1 overflow-y-auto font-mono text-xs space-y-1 custom-scrollbar">
              {logs.map((log) => (
                <div key={log.id} className={`flex gap-2 ${
                  log.type === 'error' ? 'text-red-400' : 
                  log.type === 'success' ? 'text-green-400' : 'text-gray-300'
                }`}>
                  <span className="text-gray-600">[{log.timestamp}]</span>
                  <span>{log.message}</span>
                </div>
              ))}
            </div>
          </div>
       </div>

       {/* Result Panel */}
       <div className="lg:col-span-8 flex flex-col h-full space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col min-h-[400px]">
                {resultData ? (
                    <div className="flex-1 flex flex-col gap-6">

                        {/* Summary Header */}
                        <div className="bg-green-50 border border-green-100 rounded-lg p-4 flex items-center justify-between flex-wrap gap-4">
                            <div className="flex items-center gap-3">
                                <div className="bg-green-500 text-white p-2 rounded-full">
                                    <CheckCircle2 size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-gray-800">خوشه‌بندی SERP انجام شد</h3>
                                    <p className="text-sm text-gray-600">{resultData.length} کلمه دسته‌بندی شدند.</p>
                                </div>
                            </div>

                            <div className="flex gap-2">
                                {/* AI Button */}
                                {!aiAnalysisResult && (
                                    <button 
                                        onClick={handleAiAnalysis}
                                        disabled={isAiAnalyzing}
                                        className="flex items-center gap-2 bg-purple-600 text-white px-4 py-2 rounded-lg hover:bg-purple-700 transition-colors shadow-sm disabled:opacity-70"
                                    >
                                        {isAiAnalyzing ? <Loader2 size={18} className="animate-spin" /> : <BrainCircuit size={18} />}
                                        <span>تحلیل پیلار/کلاستر و اینتنت</span>
                                    </button>
                                )}

                                <button 
                                    onClick={handleDownload}
                                    className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors shadow-sm"
                                >
                                    <Download size={18} />
                                    <span>دانلود گزارش</span>
                                </button>
                            </div>
                        </div>

                        {/* AI Analysis Result View */}
                        {aiAnalysisResult && (
                            <div className="animate-in fade-in slide-in-from-bottom-2">
                                <h4 className="text-lg font-bold text-gray-800 mb-3 flex items-center gap-2">
                                    <Lightbulb size={20} className="text-purple-500" />
                                    پیشنهاد استراتژی محتوا (AI)
                                </h4>
                                <div className="bg-purple-50 rounded-lg border border-purple-100 overflow-hidden">
                                    <div className="overflow-x-auto max-h-60 custom-scrollbar">
                                        <table className="w-full text-sm text-right">
                                            <thead className="bg-purple-100 text-purple-900 border-b border-purple-200 sticky top-0">
                                                <tr>
                                                    <th className="px-4 py-2">ID</th>
                                                    <th className="px-4 py-2">پیلار (موضوع اصلی)</th>
                                                    <th className="px-4 py-2">نام کلاستر (پیشنهادی)</th>
                                                    <th className="px-4 py-2 text-center">اینتنت</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-purple-200 bg-white">
                                                {aiAnalysisResult.map((item, idx) => (
                                                    <tr key={idx} className="hover:bg-purple-50/50">
                                                        <td className="px-4 py-2 text-gray-500">{item.id}</td>
                                                        <td className="px-4 py-2 font-medium text-gray-800">{item.pillar}</td>
                                                        <td className="px-4 py-2 text-gray-700">{item.clusterName}</td>
                                                        <td className="px-4 py-2 text-center">
                                                            <span className={`px-2 py-0.5 rounded text-xs border ${
                                                                item.intent.toLowerCase().includes('informational') ? 'bg-blue-50 text-blue-700 border-blue-200' :
                                                                item.intent.toLowerCase().includes('transactional') ? 'bg-green-50 text-green-700 border-green-200' :
                                                                'bg-gray-100 text-gray-700 border-gray-200'
                                                            }`}>
                                                                {item.intent}
                                                            </span>
                                                        </td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                    <div className="p-2 text-center text-xs text-purple-600 bg-purple-50/80">
                                        * این تحلیل توسط هوش مصنوعی انجام شده و در فایل خروجی نهایی موجود است.
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* Market Share Preview */}
                        {marketShare && marketShare.length > 0 && (
                            <div className="flex-1">
                                <h4 className="text-lg font-bold text-gray-700 mb-4 flex items-center gap-2">
                                    <BarChart3 size={20} className="text-blue-500"/>
                                    برترین رقبا (سهم بازار)
                                </h4>
                                <div className="bg-gray-50 rounded-lg border border-gray-200 overflow-hidden">
                                    <table className="w-full text-sm text-right">
                                        <thead className="bg-gray-100 text-gray-600 border-b border-gray-200">
                                            <tr>
                                                <th className="px-4 py-3">رتبه</th>
                                                <th className="px-4 py-3">دامنه</th>
                                                <th className="px-4 py-3 text-center">تعداد حضور</th>
                                                <th className="px-4 py-3 text-center">سهم (%)</th>
                                                <th className="px-4 py-3 text-left w-32">وضعیت</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-gray-200">
                                            {marketShare.slice(0, 5).map((item, idx) => (
                                                <tr key={idx} className="hover:bg-white transition-colors">
                                                    <td className="px-4 py-3 text-gray-500">{idx + 1}</td>
                                                    <td className="px-4 py-3 font-medium text-gray-800" dir="ltr">{item.Domain}</td>
                                                    <td className="px-4 py-3 text-center text-gray-600">{item.Frequency}</td>
                                                    <td className="px-4 py-3 text-center font-bold text-blue-600">{item['Share (%)']}%</td>
                                                    <td className="px-4 py-3">
                                                        <div className="w-full bg-gray-200 rounded-full h-2">
                                                            <div 
                                                                className="bg-blue-500 h-2 rounded-full" 
                                                                style={{ width: `${Math.min(100, parseFloat(item['Share (%)']))}%` }}
                                                            ></div>
                                                        </div>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        )}
                    </div>
                ) : isProcessing ? (
                    <div className="flex flex-col items-center justify-center flex-1 space-y-4">
                        <Loader2 size={48} className="text-blue-500 animate-spin" />
                        <div className="text-center">
                            <p className="text-lg font-medium text-gray-700">در حال آنالیز کلمات و رقبا...</p>
                            <p className="text-sm text-gray-500 mt-1">{progress.current} از {progress.total} کلمه پردازش شده</p>
                        </div>
                        <div className="w-64 h-2 bg-gray-100 rounded-full overflow-hidden mt-4">
                            <div 
                                className="h-full bg-blue-500 transition-all duration-300"
                                style={{ width: `${(progress.current / Math.max(progress.total, 1)) * 100}%` }}
                            />
                        </div>
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center flex-1 text-gray-400 space-y-4">
                        <div className="bg-gray-50 p-6 rounded-full">
                            <PieChart size={48} className="opacity-20" />
                        </div>
                        <div className="text-center">
                            <h3 className="text-lg font-medium text-gray-600">آماده برای شروع</h3>
                            <p className="text-sm mt-1">فایل اکسل کلمات را بارگذاری کنید تا خوشه‌بندی و تحلیل رقبا انجام شود.</p>
                        </div>
                    </div>
                )}
            </div>
       </div>

       <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #1f2937;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #4b5563;
          border-radius: 3px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #6b7280;
        }
      `}</style>
    </div>
  );
}

import React, { useState, useRef, useCallback } from 'react';
import { 
  Search, 
  Download, 
  Copy, 
  Play, 
  Square, 
  Settings, 
  Database, 
  Layers, 
  Terminal,
  Trash2,
  XCircle,
  Sparkles,
  Filter,
  Loader2,
  Eraser
} from 'lucide-react';
import { filterKeywordsBatch } from '../services/geminiService';

// --- Type Definitions ---
interface SuggestionResult {
  id: string;
  keyword: string;
  sourceSeed: string;
  layer: number;
}

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error' | 'warning';
  timestamp: string;
}

// --- Utils ---

const normalizeText = (text: string): string => {
  if (!text) return '';
  return text
    .trim()
    .replace(/\s+/g, ' ') 
    .replace(/ي/g, 'ی')   
    .replace(/ك/g, 'ک')   
    .toLowerCase();       
};

const generateCSV = (data: SuggestionResult[]) => {
  const header = ['Keyword,Source Seed,Layer'];
  const rows = data.map(item => `"${item.keyword}","${item.sourceSeed}",${item.layer}`);
  return [header, ...rows].join('\n');
};

export default function KeywordFetcher() {
  const [seeds, setSeeds] = useState<string>('');
  const [language, setLanguage] = useState<string>('fa');
  const [country, setCountry] = useState<string>('ir');
  const [depth, setDepth] = useState<number>(1);
  const [delay, setDelay] = useState<number>(1000); 
  const [concurrency, setConcurrency] = useState<number>(2); 

  const [results, setResults] = useState<SuggestionResult[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [progress, setProgress] = useState<{ processed: number; total: number }>({ processed: 0, total: 0 });

  const [aiPrompt, setAiPrompt] = useState<string>('');
  const [isAiFiltering, setIsAiFiltering] = useState<boolean>(false);

  // Manual Filter State
  const [manualFilterText, setManualFilterText] = useState<string>('');

  const abortControllerRef = useRef<AbortController | null>(null);
  const processedKeywordsRef = useRef<Set<string>>(new Set());

  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100)); 
  }, []);

  const fetchSuggestions = async (query: string): Promise<string[]> => {
    const targetUrl = `https://suggestqueries.google.com/complete/search?client=chrome&hl=${language}&gl=${country}&q=${encodeURIComponent(query)}`;

    const proxies = [
      {
        name: 'CORSProxy',
        url: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}`,
        isJsonWrapped: false
      },
      {
        name: 'AllOrigins',
        url: (u: string) => `https://api.allorigins.win/get?url=${encodeURIComponent(u)}`,
        isJsonWrapped: true
      }
    ];

    let lastError: any = null;

    for (const proxy of proxies) {
      if (abortControllerRef.current?.signal.aborted) {
        throw new DOMException('Aborted', 'AbortError');
      }

      try {
        const response = await fetch(proxy.url(targetUrl), {
          signal: abortControllerRef.current?.signal
        });

        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`);
        }

        const data = await response.json();

        let resultData;
        if (proxy.isJsonWrapped) {
          resultData = JSON.parse(data.contents);
        } else {
          resultData = data;
        }

        if (Array.isArray(resultData) && Array.isArray(resultData[1])) {
           return resultData[1];
        }

        return [];

      } catch (error: any) {
        if (error.name === 'AbortError') throw error;
        lastError = error;
      }
    }

    throw lastError || new Error('All proxies failed');
  };

  const startProcessing = async () => {
    if (!seeds.trim()) {
      addLog('لطفا کلمات کلیدی اولیه را وارد کنید.', 'error');
      return;
    }

    setIsProcessing(true);
    setResults([]);
    setLogs([]);
    processedKeywordsRef.current = new Set();
    abortControllerRef.current = new AbortController();

    const seedList = seeds.split('\n').map(s => normalizeText(s)).filter(s => s.length > 0);

    let queue: { keyword: string; source: string; layer: number }[] = seedList.map(s => ({
      keyword: s,
      source: 'SEED',
      layer: 0 
    }));

    seedList.forEach(s => processedKeywordsRef.current.add(s));

    addLog(`شروع پردازش با ${seedList.length} کلمه کلیدی...`, 'info');

    let totalProcessedCount = 0;

    try {
      while (queue.length > 0 && abortControllerRef.current) {

        const currentBatch = queue.splice(0, concurrency);

        setProgress({ processed: totalProcessedCount, total: totalProcessedCount + queue.length + currentBatch.length });

        const batchPromises = currentBatch.map(async (item) => {
          if (item.layer >= depth) return []; 

          try {
            const suggestions = await fetchSuggestions(item.keyword);

            const newKeywords: { keyword: string; source: string; layer: number }[] = [];

            suggestions.forEach(sugg => {
              const normalizedSugg = normalizeText(sugg);

              if (!processedKeywordsRef.current.has(normalizedSugg)) {
                processedKeywordsRef.current.add(normalizedSugg);

                const newResult: SuggestionResult = {
                  id: Math.random().toString(36).substr(2, 9),
                  keyword: normalizedSugg,
                  sourceSeed: item.keyword,
                  layer: item.layer + 1
                };

                setResults(prev => [...prev, newResult]);

                if (item.layer + 1 < depth) {
                  newKeywords.push({
                    keyword: normalizedSugg,
                    source: item.keyword,
                    layer: item.layer + 1
                  });
                }
              }
            });
            return newKeywords;
          } catch (err: any) {
            if (err.name !== 'AbortError') {
               addLog(`خطا در دریافت ساجست برای: "${item.keyword}"`, 'warning');
            }
            return [];
          }
        });

        const batchResults = await Promise.all(batchPromises);
        totalProcessedCount += currentBatch.length;

        batchResults.forEach(newItems => {
          queue.push(...newItems);
        });

        if (queue.length > 0) {
          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }

      if (abortControllerRef.current) {
        addLog('پردازش با موفقیت به پایان رسید.', 'success');
      }

    } catch (error: any) {
      if (error.name !== 'AbortError') {
        addLog('پردازش با خطای غیرمنتظره متوقف شد.', 'error');
      }
    } finally {
      setIsProcessing(false);
      abortControllerRef.current = null;
    }
  };

  const stopProcessing = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
      setIsProcessing(false);
      addLog('پردازش توسط کاربر متوقف شد.', 'warning');
    }
  };

  const handleManualFilter = () => {
    if (!manualFilterText.trim()) return;
    const term = normalizeText(manualFilterText);

    const initialCount = results.length;
    const newResults = results.filter(r => !r.keyword.includes(term));
    const removedCount = initialCount - newResults.length;

    if (removedCount > 0) {
        setResults(newResults);

        // Re-sync processed set to reflect current state
        const newSet = new Set(newResults.map(r => r.keyword));
        processedKeywordsRef.current = newSet;

        addLog(`${removedCount} کلمه حاوی "${term}" حذف شدند.`, 'success');
        setManualFilterText('');
    } else {
        addLog(`هیچ کلمه‌ای حاوی "${term}" پیدا نشد.`, 'warning');
    }
  };

  const handleAiFilter = async () => {
    if (results.length === 0) {
      addLog('هیچ کلمه‌ای برای تحلیل وجود ندارد.', 'warning');
      return;
    }
    if (!aiPrompt.trim()) {
      addLog('لطفا دستور فیلتر (Prompt) را وارد کنید.', 'error');
      return;
    }

    if (!process.env.API_KEY) {
      addLog('API Key یافت نشد. لطفا تنظیمات برنامه را بررسی کنید.', 'error');
      return;
    }

    setIsAiFiltering(true);
    addLog('شروع تحلیل هوشمند کلمات با هوش مصنوعی...', 'info');

    try {
      const CHUNK_SIZE = 75;
      const allKeywords = results.map(r => r.keyword);
      const chunks = [];

      for (let i = 0; i < allKeywords.length; i += CHUNK_SIZE) {
        chunks.push(allKeywords.slice(i, i + CHUNK_SIZE));
      }

      let keptKeywordsSet = new Set<string>();

      const processChunkWithRetry = async (chunk: string[], batchIndex: number, attempt = 1): Promise<string[]> => {
          try {
              return await filterKeywordsBatch(chunk, aiPrompt);
          } catch (e: any) {
              if (attempt <= 3) {
                  const delayTime = 2000 * attempt;
                  addLog(`خطا در دسته ${batchIndex + 1}. تلاش مجدد (${attempt}/3) تا ${delayTime/1000} ثانیه دیگر...`, 'warning');
                  await new Promise(r => setTimeout(r, delayTime));
                  return processChunkWithRetry(chunk, batchIndex, attempt + 1);
              }
              throw e;
          }
      };

      for (let i = 0; i < chunks.length; i++) {
        const chunk = chunks[i];

        addLog(`در حال تحلیل دسته ${i + 1} از ${chunks.length} (${chunk.length} کلمه)...`, 'info');

        try {
          const keptInChunk = await processChunkWithRetry(chunk, i);

          keptInChunk.forEach(k => keptKeywordsSet.add(k));

          if (i < chunks.length - 1) {
            await new Promise(r => setTimeout(r, 1000));
          }

        } catch (err) {
          console.error(err);
          addLog(`خطا در تحلیل دسته ${i + 1} پس از ۳ تلاش. این دسته بدون تغییر باقی می‌ماند.`, 'error');
          chunk.forEach(k => keptKeywordsSet.add(k));
        }
      }

      const initialCount = results.length;
      const finalCount = keptKeywordsSet.size;
      const removedCount = initialCount - finalCount;

      const newResults = results.filter(r => keptKeywordsSet.has(r.keyword));
      setResults(newResults);

      processedKeywordsRef.current = new Set(newResults.map(r => r.keyword));

      addLog(`پایان تحلیل. ${removedCount} کلمه حذف شد و ${finalCount} کلمه باقی ماند.`, 'success');

    } catch (error) {
      addLog('خطای کلی در فرآیند هوش مصنوعی.', 'error');
      console.error(error);
    } finally {
      setIsAiFiltering(false);
    }
  };

  const handleExport = () => {
    const csvContent = generateCSV(results);
    const blob = new Blob([`\uFEFF${csvContent}`], { type: 'text/csv;charset=utf-8;' }); 
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `deep_suggest_${new Date().toISOString().slice(0,10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    addLog('فایل CSV دانلود شد.', 'success');
  };

  const handleCopy = () => {
    const text = results.map(r => r.keyword).join('\n');

    const textArea = document.createElement("textarea");
    textArea.value = text;

    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    textArea.style.top = "0";
    document.body.appendChild(textArea);

    textArea.focus();
    textArea.select();

    try {
      const successful = document.execCommand('copy');
      if (successful) {
        addLog(`${results.length} کلمه کلیدی در کلیپ‌بورد کپی شد.`, 'success');
      } else {
        addLog('کپی ناموفق بود. لطفا دستی کپی کنید.', 'error');
      }
    } catch (err) {
      console.error('Copy failed', err);
      addLog('خطا در کپی کردن متن.', 'error');
    }

    document.body.removeChild(textArea);
  };

  const handleClear = () => {
    setResults([]);
    setLogs([]);
    processedKeywordsRef.current = new Set();
    setProgress({ processed: 0, total: 0 });
  };

  const handleDeleteItem = (targetKeyword: string) => {
    const toRemove = new Set<string>([targetKeyword]);
    const queue = [targetKeyword];

    let head = 0;
    while(head < queue.length){
        const currentParent = queue[head];
        head++;

        const children = results.filter(r => r.sourceSeed === currentParent);

        children.forEach(child => {
            if (!toRemove.has(child.keyword)) {
                toRemove.add(child.keyword);
                queue.push(child.keyword);
            }
        });
    }

    setResults(prev => prev.filter(r => !toRemove.has(r.keyword)));

    toRemove.forEach(k => processedKeywordsRef.current.delete(k));

    addLog(`کلمه "${targetKeyword}" و ${toRemove.size - 1} زیرمجموعه آن حذف شدند.`, 'warning');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

      {/* Left Column: Configuration (4 cols) */}
      <div className="lg:col-span-4 space-y-6">

        {/* Input Panel */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <Database size={20} className="text-blue-500" />
            ورودی‌ها
          </h2>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">کلمات کلیدی اولیه (Seed)</label>
              <textarea
                className="w-full h-32 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm resize-none"
                placeholder="هر خط یک کلمه...&#10;خرید موبایل&#10;آموزش سئو"
                value={seeds}
                onChange={(e) => setSeeds(e.target.value)}
                disabled={isProcessing || isAiFiltering}
              ></textarea>
              <p className="text-xs text-gray-500 mt-1 text-left ltr">
                {seeds.split('\n').filter(s => s.trim()).length} Seed Keywords
              </p>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">زبان (hl)</label>
                <select 
                  value={language} 
                  onChange={(e) => setLanguage(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-md text-sm"
                  disabled={isProcessing || isAiFiltering}
                >
                  <option value="fa">فارسی (fa)</option>
                  <option value="en">English (en)</option>
                  <option value="ar">Arabic (ar)</option>
                  <option value="tr">Turkish (tr)</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">منطقه (gl)</label>
                <select 
                  value={country} 
                  onChange={(e) => setCountry(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-md text-sm"
                  disabled={isProcessing || isAiFiltering}
                >
                  <option value="ir">ایران (ir)</option>
                  <option value="us">United States (us)</option>
                  <option value="ae">UAE (ae)</option>
                  <option value="tr">Turkey (tr)</option>
                </select>
              </div>
            </div>
          </div>
        </div>

        {/* Manual Filter Panel (NEW) */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2 text-red-600">
                <Eraser size={20} />
                فیلتر دستی (حذف)
            </h2>
            <div className="flex gap-2">
                <input
                    type="text"
                    value={manualFilterText}
                    onChange={(e) => setManualFilterText(e.target.value)}
                    placeholder="کلمه جهت حذف..."
                    className="flex-1 p-2 border border-gray-300 rounded-md text-sm focus:border-red-500 focus:ring-1 focus:ring-red-500 outline-none"
                    onKeyDown={(e) => e.key === 'Enter' && handleManualFilter()}
                    disabled={isProcessing || isAiFiltering}
                />
                <button
                    onClick={handleManualFilter}
                    disabled={!manualFilterText || results.length === 0 || isProcessing}
                    className="bg-red-50 text-red-600 border border-red-200 px-3 py-2 rounded-md hover:bg-red-100 transition-colors disabled:opacity-50"
                    title="حذف کلمات حاوی این متن"
                >
                    <Trash2 size={18} />
                </button>
            </div>
            <p className="text-xs text-gray-500 mt-2">
                کلماتی که شامل عبارت بالا باشند از لیست نتایج حذف خواهند شد.
            </p>
        </div>

        {/* AI Filter Panel */}
        <div className="bg-gradient-to-br from-indigo-50 to-purple-50 rounded-xl shadow-sm border border-indigo-100 p-5">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2 text-indigo-900">
            <Sparkles size={20} className="text-indigo-600" />
            فیلتر هوشمند (AI)
          </h2>
          <div className="space-y-3">
            <div>
              <label className="block text-sm font-medium text-indigo-800 mb-1">چه کلماتی را نگه دارم/حذف کنم؟</label>
              <textarea 
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                disabled={isProcessing || isAiFiltering}
                placeholder="مثال: کلمات مربوط به 'رایگان' یا 'کرک' را حذف کن. فقط کلمات خرید آنلاین را نگه دار."
                className="w-full h-24 p-3 border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 text-sm resize-none bg-white"
              />
            </div>
            <button
              onClick={handleAiFilter}
              disabled={isProcessing || isAiFiltering || results.length === 0}
              className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
            >
              {isAiFiltering ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  <span>در حال تحلیل...</span>
                </>
              ) : (
                <>
                  <Filter size={18} />
                  <span>اعمال فیلتر روی نتایج</span>
                </>
              )}
            </button>
            <p className="text-xs text-indigo-400 leading-relaxed">
              این ابزار لیست نتایج فعلی را به Gemini می‌فرستد و بر اساس دستور شما آن را پالایش می‌کند. (تجزیه به بسته‌های کوچک‌تر جهت پایداری)
            </p>
          </div>
        </div>

        {/* Settings Panel */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <Settings size={20} className="text-gray-500" />
            تنظیمات پیشرفته
          </h2>

          <div className="space-y-6">
            <div>
              <div className="flex justify-between mb-1">
                <label className="text-sm font-medium text-gray-700">عمق جستجو (Depth)</label>
                <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">لایه {depth}</span>
              </div>
              <input 
                type="range" 
                min="1" 
                max="3" 
                step="1"
                value={depth}
                onChange={(e) => setDepth(parseInt(e.target.value))}
                disabled={isProcessing || isAiFiltering}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
            </div>

            <div>
              <div className="flex justify-between mb-1">
                <label className="text-sm font-medium text-gray-700">تعداد درخواست همزمان</label>
                <span className="text-xs text-gray-500">{concurrency} درخواست</span>
              </div>
              <input 
                type="range" 
                min="1" 
                max="5" 
                value={concurrency}
                onChange={(e) => setConcurrency(parseInt(e.target.value))}
                disabled={isProcessing || isAiFiltering}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
            </div>

            <div>
              <div className="flex justify-between mb-1">
                <label className="text-sm font-medium text-gray-700">تاخیر بین درخواست‌ها</label>
                <span className="text-xs text-gray-500">{delay} میلی‌ثانیه</span>
              </div>
              <input 
                type="range" 
                min="100" 
                max="3000" 
                step="100"
                value={delay}
                onChange={(e) => setDelay(parseInt(e.target.value))}
                disabled={isProcessing || isAiFiltering}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
            </div>

             {/* Action Buttons inside Settings for Mobile/Compact Layout */}
             <div className="pt-4 flex flex-col gap-2">
                {isProcessing ? (
                <button 
                    onClick={stopProcessing}
                    className="w-full flex items-center justify-center gap-2 bg-red-50 text-red-600 border border-red-200 px-4 py-2 rounded-md hover:bg-red-100 transition-colors"
                >
                    <Square size={18} fill="currentColor" />
                    <span>توقف استخراج</span>
                </button>
                ) : (
                <button 
                    onClick={startProcessing}
                    disabled={isAiFiltering}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white px-6 py-2 rounded-md hover:bg-blue-700 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <Play size={18} fill="currentColor" />
                    <span>شروع استخراج</span>
                </button>
                )}
             </div>
          </div>
        </div>

        {/* Log Panel */}
        <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
            <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
            <Terminal size={14} />
            System Logs
        </h2>
        <div className="flex-1 overflow-y-auto font-mono text-xs space-y-1 custom-scrollbar">
            {logs.length === 0 && <span className="text-gray-600 italic">آماده برای شروع...</span>}
            {logs.map((log) => (
            <div key={log.id} className={`flex gap-2 ${
                log.type === 'error' ? 'text-red-400' : 
                log.type === 'success' ? 'text-green-400' : 
                log.type === 'warning' ? 'text-yellow-400' : 'text-gray-300'
            }`}>
                <span className="text-gray-600">[{log.timestamp}]</span>
                <span>{log.message}</span>
            </div>
            ))}
        </div>
        </div>

      </div>

      {/* Right Column: Results (8 cols) */}
      <div className="lg:col-span-8 flex flex-col h-full space-y-6">

        {/* Stats Bar */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4 flex flex-wrap gap-4 justify-between items-center">
            <div className="flex gap-6">
            <div className="flex flex-col">
                <span className="text-xs text-gray-500">کلمات پیدا شده</span>
                <span className="text-2xl font-bold text-blue-600">{results.length}</span>
            </div>
            <div className="flex flex-col">
                <span className="text-xs text-gray-500">وضعیت</span>
                <span className={`text-sm font-medium mt-1 ${isProcessing ? 'text-amber-500 animate-pulse' : isAiFiltering ? 'text-indigo-500 animate-pulse' : 'text-green-600'}`}>
                {isProcessing ? 'در حال استخراج...' : isAiFiltering ? 'در حال تحلیل AI...' : 'آماده'}
                </span>
            </div>
            {isProcessing && (
                <div className="flex flex-col w-32">
                <span className="text-xs text-gray-500 mb-1">پیشرفت استخراج</span>
                <div className="w-full bg-gray-200 rounded-full h-2.5">
                    <div 
                    className="bg-blue-600 h-2.5 rounded-full transition-all duration-300" 
                    style={{ width: `${Math.min(100, (progress.processed / Math.max(progress.total, 1)) * 100)}%` }}
                    ></div>
                </div>
                </div>
            )}
            </div>

            <div className="flex gap-2">
            <button 
            onClick={handleClear}
            disabled={results.length === 0 || isProcessing || isAiFiltering}
            className="p-2 text-gray-500 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
            title="پاک کردن نتایج"
            >
                <Trash2 size={20} />
            </button>
            <button 
                onClick={handleCopy}
                disabled={results.length === 0 || isProcessing || isAiFiltering}
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 disabled:opacity-50"
            >
                <Copy size={16} />
                <span>کپی</span>
            </button>
            <button 
                onClick={handleExport}
                disabled={results.length === 0 || isProcessing || isAiFiltering}
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-white bg-green-600 rounded-lg hover:bg-green-700 disabled:opacity-50"
            >
                <Download size={16} />
                <span>خروجی اکسل</span>
            </button>
            </div>
        </div>

        {/* Table */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex-1 overflow-hidden flex flex-col min-h-[500px]">
        <div className="overflow-x-auto flex-1">
            <table className="w-full text-sm text-right text-gray-500">
            <thead className="text-xs text-gray-700 uppercase bg-gray-50 sticky top-0 z-0">
                <tr>
                <th scope="col" className="px-6 py-3 w-16 text-center">#</th>
                <th scope="col" className="px-6 py-3">کلمه کلیدی (Keyword)</th>
                <th scope="col" className="px-6 py-3">منبع (Seed)</th>
                <th scope="col" className="px-6 py-3 w-24 text-center">لایه</th>
                <th scope="col" className="px-6 py-3 w-20 text-center">عملیات</th>
                </tr>
            </thead>
            <tbody className={`${isAiFiltering ? 'opacity-50' : ''}`}>
                {results.length === 0 ? (
                <tr>
                    <td colSpan={5} className="px-6 py-20 text-center text-gray-400">
                    <div className="flex flex-col items-center justify-center gap-3">
                        <Layers size={48} className="opacity-20" />
                        <p>هنوز داده‌ای وجود ندارد. کلمات را وارد کرده و دکمه شروع را بزنید.</p>
                    </div>
                    </td>
                </tr>
                ) : (
                results.map((row, index) => (
                    <tr key={row.id} className="bg-white border-b hover:bg-blue-50 transition-colors group">
                    <td className="px-6 py-3 text-center text-gray-400">{index + 1}</td>
                    <td className="px-6 py-3 font-medium text-gray-900">{row.keyword}</td>
                    <td className="px-6 py-3 text-gray-500">{row.sourceSeed}</td>
                    <td className="px-6 py-3 text-center">
                        <span className={`px-2 py-1 rounded text-xs ${
                        row.layer === 1 ? 'bg-blue-100 text-blue-800' :
                        row.layer === 2 ? 'bg-purple-100 text-purple-800' :
                        'bg-orange-100 text-orange-800'
                        }`}>
                        لایه {row.layer}
                        </span>
                    </td>
                    <td className="px-6 py-3 text-center">
                        <button
                            onClick={() => handleDeleteItem(row.keyword)}
                            className="text-gray-400 hover:text-red-600 transition-colors p-1 rounded-full hover:bg-red-50"
                            title="حذف کلمه و زیرمجموعه‌ها"
                        >
                            <XCircle size={18} />
                        </button>
                    </td>
                    </tr>
                ))
                )}
            </tbody>
            </table>
        </div>
        <div className="bg-gray-50 px-6 py-3 border-t border-gray-200 text-xs text-gray-500 flex justify-between">
            <span>تعداد کل: {results.length}</span>
            <span>Deep Suggest Fetcher v1.2 + Gemini AI</span>
        </div>
        </div>

      </div>
    </div>
  );
}

import React, { useState, useRef, useCallback } from 'react';
import { 
  Search, 
  Download, 
  Copy, 
  Play, 
  Square, 
  Settings, 
  Database, 
  Layers, 
  Terminal,
  Trash2,
  XCircle,
  Sparkles,
  Filter,
  Loader2,
  Eraser,
  Eye,
  X
} from 'lucide-react';
import { filterKeywordsBatch } from '../services/geminiService';

// --- Type Definitions ---
interface SuggestionResult {
  id: string;
  keyword: string;
  sourceSeed: string;
  layer: number;
}

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error' | 'warning';
  timestamp: string;
}

// --- Utils ---

const normalizeText = (text: string): string => {
  if (!text) return '';
  return text
    .trim()
    .replace(/\s+/g, ' ') 
    .replace(/ي/g, 'ی')   
    .replace(/ك/g, 'ک')   
    .toLowerCase();       
};

const generateCSV = (data: SuggestionResult[]) => {
  const header = ['Keyword,Source Seed,Layer'];
  const rows = data.map(item => `"${item.keyword}","${item.sourceSeed}",${item.layer}`);
  return [header, ...rows].join('\n');
};

export default function KeywordFetcher() {
  const [seeds, setSeeds] = useState<string>('');
  const [language, setLanguage] = useState<string>('fa');
  const [country, setCountry] = useState<string>('ir');
  const [depth, setDepth] = useState<number>(1);
  const [delay, setDelay] = useState<number>(1000); 
  const [concurrency, setConcurrency] = useState<number>(2); 

  const [results, setResults] = useState<SuggestionResult[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [progress, setProgress] = useState<{ processed: number; total: number }>({ processed: 0, total: 0 });

  const [aiPrompt, setAiPrompt] = useState<string>('');
  const [isAiFiltering, setIsAiFiltering] = useState<boolean>(false);

  // Manual Filter State
  const [manualFilterText, setManualFilterText] = useState<string>('');
  const [filterPreview, setFilterPreview] = useState<SuggestionResult[]>([]);

  const abortControllerRef = useRef<AbortController | null>(null);
  const processedKeywordsRef = useRef<Set<string>>(new Set());

  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100)); 
  }, []);

  const fetchSuggestions = async (query: string): Promise<string[]> => {
    const targetUrl = `https://suggestqueries.google.com/complete/search?client=chrome&hl=${language}&gl=${country}&q=${encodeURIComponent(query)}`;

    const proxies = [
      {
        name: 'CORSProxy',
        url: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}`,
        isJsonWrapped: false
      },
      {
        name: 'AllOrigins',
        url: (u: string) => `https://api.allorigins.win/get?url=${encodeURIComponent(u)}`,
        isJsonWrapped: true
      }
    ];

    let lastError: any = null;

    for (const proxy of proxies) {
      if (abortControllerRef.current?.signal.aborted) {
        throw new DOMException('Aborted', 'AbortError');
      }

      try {
        const response = await fetch(proxy.url(targetUrl), {
          signal: abortControllerRef.current?.signal
        });

        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`);
        }

        const data = await response.json();

        let resultData;
        if (proxy.isJsonWrapped) {
          resultData = JSON.parse(data.contents);
        } else {
          resultData = data;
        }

        if (Array.isArray(resultData) && Array.isArray(resultData[1])) {
           return resultData[1];
        }

        return [];

      } catch (error: any) {
        if (error.name === 'AbortError') throw error;
        lastError = error;
      }
    }

    throw lastError || new Error('All proxies failed');
  };

  const startProcessing = async () => {
    if (!seeds.trim()) {
      addLog('لطفا کلمات کلیدی اولیه را وارد کنید.', 'error');
      return;
    }

    setIsProcessing(true);
    setResults([]);
    setLogs([]);
    processedKeywordsRef.current = new Set();
    abortControllerRef.current = new AbortController();

    const seedList = seeds.split('\n').map(s => normalizeText(s)).filter(s => s.length > 0);

    let queue: { keyword: string; source: string; layer: number }[] = seedList.map(s => ({
      keyword: s,
      source: 'SEED',
      layer: 0 
    }));

    seedList.forEach(s => processedKeywordsRef.current.add(s));

    addLog(`شروع پردازش با ${seedList.length} کلمه کلیدی...`, 'info');

    let totalProcessedCount = 0;

    try {
      while (queue.length > 0 && abortControllerRef.current) {

        const currentBatch = queue.splice(0, concurrency);

        setProgress({ processed: totalProcessedCount, total: totalProcessedCount + queue.length + currentBatch.length });

        const batchPromises = currentBatch.map(async (item) => {
          if (item.layer >= depth) return []; 

          try {
            const suggestions = await fetchSuggestions(item.keyword);

            const newKeywords: { keyword: string; source: string; layer: number }[] = [];

            suggestions.forEach(sugg => {
              const normalizedSugg = normalizeText(sugg);

              if (!processedKeywordsRef.current.has(normalizedSugg)) {
                processedKeywordsRef.current.add(normalizedSugg);

                const newResult: SuggestionResult = {
                  id: Math.random().toString(36).substr(2, 9),
                  keyword: normalizedSugg,
                  sourceSeed: item.keyword,
                  layer: item.layer + 1
                };

                setResults(prev => [...prev, newResult]);

                if (item.layer + 1 < depth) {
                  newKeywords.push({
                    keyword: normalizedSugg,
                    source: item.keyword,
                    layer: item.layer + 1
                  });
                }
              }
            });
            return newKeywords;
          } catch (err: any) {
            if (err.name !== 'AbortError') {
               addLog(`خطا در دریافت ساجست برای: "${item.keyword}"`, 'warning');
            }
            return [];
          }
        });

        const batchResults = await Promise.all(batchPromises);
        totalProcessedCount += currentBatch.length;

        batchResults.forEach(newItems => {
          queue.push(...newItems);
        });

        if (queue.length > 0) {
          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }

      if (abortControllerRef.current) {
        addLog('پردازش با موفقیت به پایان رسید.', 'success');
      }

    } catch (error: any) {
      if (error.name !== 'AbortError') {
        addLog('پردازش با خطای غیرمنتظره متوقف شد.', 'error');
      }
    } finally {
      setIsProcessing(false);
      abortControllerRef.current = null;
    }
  };

  const stopProcessing = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
      setIsProcessing(false);
      addLog('پردازش توسط کاربر متوقف شد.', 'warning');
    }
  };

  const handlePreviewFilter = () => {
    if (!manualFilterText.trim()) return;
    const term = normalizeText(manualFilterText);

    // Find matches
    const matches = results.filter(r => r.keyword.includes(term));

    if (matches.length > 0) {
        setFilterPreview(matches);
    } else {
        setFilterPreview([]);
        addLog(`هیچ کلمه‌ای حاوی "${term}" پیدا نشد.`, 'warning');
    }
  };

  const handleConfirmDelete = () => {
    if (filterPreview.length === 0) return;

    const toRemoveIds = new Set(filterPreview.map(r => r.id));
    const toRemoveKeywords = new Set(filterPreview.map(r => r.keyword));

    setResults(prev => prev.filter(r => !toRemoveIds.has(r.id)));

    // Clean up global set
    toRemoveKeywords.forEach(k => processedKeywordsRef.current.delete(k));

    addLog(`${filterPreview.length} کلمه حذف شدند.`, 'success');

    // Reset states
    setFilterPreview([]);
    setManualFilterText('');
  };

  const handleCancelFilter = () => {
    setFilterPreview([]);
    setManualFilterText('');
  };

  const handleAiFilter = async () => {
    if (results.length === 0) {
      addLog('هیچ کلمه‌ای برای تحلیل وجود ندارد.', 'warning');
      return;
    }
    if (!aiPrompt.trim()) {
      addLog('لطفا دستور فیلتر (Prompt) را وارد کنید.', 'error');
      return;
    }

    if (!process.env.API_KEY) {
      addLog('API Key یافت نشد. لطفا تنظیمات برنامه را بررسی کنید.', 'error');
      return;
    }

    setIsAiFiltering(true);
    addLog('شروع تحلیل هوشمند کلمات با هوش مصنوعی...', 'info');

    try {
      const CHUNK_SIZE = 75;
      const allKeywords = results.map(r => r.keyword);
      const chunks = [];

      for (let i = 0; i < allKeywords.length; i += CHUNK_SIZE) {
        chunks.push(allKeywords.slice(i, i + CHUNK_SIZE));
      }

      let keptKeywordsSet = new Set<string>();

      const processChunkWithRetry = async (chunk: string[], batchIndex: number, attempt = 1): Promise<string[]> => {
          try {
              return await filterKeywordsBatch(chunk, aiPrompt);
          } catch (e: any) {
              if (attempt <= 3) {
                  const delayTime = 2000 * attempt;
                  addLog(`خطا در دسته ${batchIndex + 1}. تلاش مجدد (${attempt}/3) تا ${delayTime/1000} ثانیه دیگر...`, 'warning');
                  await new Promise(r => setTimeout(r, delayTime));
                  return processChunkWithRetry(chunk, batchIndex, attempt + 1);
              }
              throw e;
          }
      };

      for (let i = 0; i < chunks.length; i++) {
        const chunk = chunks[i];

        addLog(`در حال تحلیل دسته ${i + 1} از ${chunks.length} (${chunk.length} کلمه)...`, 'info');

        try {
          const keptInChunk = await processChunkWithRetry(chunk, i);

          keptInChunk.forEach(k => keptKeywordsSet.add(k));

          if (i < chunks.length - 1) {
            await new Promise(r => setTimeout(r, 1000));
          }

        } catch (err) {
          console.error(err);
          addLog(`خطا در تحلیل دسته ${i + 1} پس از ۳ تلاش. این دسته بدون تغییر باقی می‌ماند.`, 'error');
          chunk.forEach(k => keptKeywordsSet.add(k));
        }
      }

      const initialCount = results.length;
      const finalCount = keptKeywordsSet.size;
      const removedCount = initialCount - finalCount;

      const newResults = results.filter(r => keptKeywordsSet.has(r.keyword));
      setResults(newResults);

      processedKeywordsRef.current = new Set(newResults.map(r => r.keyword));

      addLog(`پایان تحلیل. ${removedCount} کلمه حذف شد و ${finalCount} کلمه باقی ماند.`, 'success');

    } catch (error) {
      addLog('خطای کلی در فرآیند هوش مصنوعی.', 'error');
      console.error(error);
    } finally {
      setIsAiFiltering(false);
    }
  };

  const handleExport = () => {
    const csvContent = generateCSV(results);
    const blob = new Blob([`\uFEFF${csvContent}`], { type: 'text/csv;charset=utf-8;' }); 
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `deep_suggest_${new Date().toISOString().slice(0,10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    addLog('فایل CSV دانلود شد.', 'success');
  };

  const handleCopy = () => {
    const text = results.map(r => r.keyword).join('\n');

    const textArea = document.createElement("textarea");
    textArea.value = text;

    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    textArea.style.top = "0";
    document.body.appendChild(textArea);

    textArea.focus();
    textArea.select();

    try {
      const successful = document.execCommand('copy');
      if (successful) {
        addLog(`${results.length} کلمه کلیدی در کلیپ‌بورد کپی شد.`, 'success');
      } else {
        addLog('کپی ناموفق بود. لطفا دستی کپی کنید.', 'error');
      }
    } catch (err) {
      console.error('Copy failed', err);
      addLog('خطا در کپی کردن متن.', 'error');
    }

    document.body.removeChild(textArea);
  };

  const handleClear = () => {
    setResults([]);
    setLogs([]);
    processedKeywordsRef.current = new Set();
    setProgress({ processed: 0, total: 0 });
  };

  const handleDeleteItem = (targetKeyword: string) => {
    const toRemove = new Set<string>([targetKeyword]);
    const queue = [targetKeyword];

    let head = 0;
    while(head < queue.length){
        const currentParent = queue[head];
        head++;

        const children = results.filter(r => r.sourceSeed === currentParent);

        children.forEach(child => {
            if (!toRemove.has(child.keyword)) {
                toRemove.add(child.keyword);
                queue.push(child.keyword);
            }
        });
    }

    setResults(prev => prev.filter(r => !toRemove.has(r.keyword)));

    toRemove.forEach(k => processedKeywordsRef.current.delete(k));

    addLog(`کلمه "${targetKeyword}" و ${toRemove.size - 1} زیرمجموعه آن حذف شدند.`, 'warning');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

      {/* Left Column: Configuration (4 cols) */}
      <div className="lg:col-span-4 space-y-6">

        {/* Input Panel */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <Database size={20} className="text-blue-500" />
            ورودی‌ها
          </h2>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">کلمات کلیدی اولیه (Seed)</label>
              <textarea
                className="w-full h-32 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm resize-none"
                placeholder="هر خط یک کلمه...&#10;خرید موبایل&#10;آموزش سئو"
                value={seeds}
                onChange={(e) => setSeeds(e.target.value)}
                disabled={isProcessing || isAiFiltering}
              ></textarea>
              <p className="text-xs text-gray-500 mt-1 text-left ltr">
                {seeds.split('\n').filter(s => s.trim()).length} Seed Keywords
              </p>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">زبان (hl)</label>
                <select 
                  value={language} 
                  onChange={(e) => setLanguage(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-md text-sm"
                  disabled={isProcessing || isAiFiltering}
                >
                  <option value="fa">فارسی (fa)</option>
                  <option value="en">English (en)</option>
                  <option value="ar">Arabic (ar)</option>
                  <option value="tr">Turkish (tr)</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">منطقه (gl)</label>
                <select 
                  value={country} 
                  onChange={(e) => setCountry(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-md text-sm"
                  disabled={isProcessing || isAiFiltering}
                >
                  <option value="ir">ایران (ir)</option>
