import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
// Note: In a real environment, ensure process.env.API_KEY is set.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Filters a list of keywords based on a user prompt using Gemini.
 * Returns the list of keywords that SHOULD BE KEPT.
 */
export const filterKeywordsBatch = async (
  keywords: string[],
  userPrompt: string
): Promise<string[]> => {
  if (!keywords.length) return [];

  const modelId = 'gemini-3-flash-preview'; 

  // Schema to ensure we get a clean list of strings back
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      keptKeywords: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "The list of keywords that match the criteria and should be kept."
      }
    },
    required: ["keptKeywords"]
  };

  const systemInstruction = `
    You are a specialized SEO keyword filtering assistant.
    Your task is to analyze a list of keywords and filter them based strictly on the user's criteria.

    Rules:
    1. You will receive a JSON list of keywords and a filtering criteria (Prompt).
    2. Return ONLY the keywords that satisfy the user's criteria in the 'keptKeywords' array.
    3. If the user asks to "remove" something, return the list WITHOUT those items.
    4. If the user asks to "keep" something, return ONLY those items.
    5. Do not modify the text of the keywords. Return them exactly as received.
  `;

  const prompt = `
    User Filtering Criteria: "${userPrompt}"

    Keywords List to Process:
    ${JSON.stringify(keywords)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1, // Low temperature for deterministic results
      },
    });

    const text = response.text;
    if (!text) return keywords; // Fallback: keep all if response is empty

    const parsed = JSON.parse(text);
    return parsed.keptKeywords || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

/**
 * Analyzes SERP-based clusters to assign Pillar topics, refine Cluster names, and determine Intent.
 * Processes in batches to avoid payload limits and timeouts.
 */
export const analyzeSerpClusters = async (
  clusters: { id: number; keywords: string[] }[]
): Promise<{ id: number; pillar: string; clusterName: string; intent: string }[]> => {
  if (!clusters.length) return [];

  const modelId = 'gemini-3-flash-preview';

  // Batch configuration
  const BATCH_SIZE = 10;
  const results: { id: number; pillar: string; clusterName: string; intent: string }[] = [];

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      analysis: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.INTEGER, description: "The original cluster ID provided in the input." },
            pillar: { type: Type.STRING, description: "The broad Pillar Page topic this cluster belongs to." },
            clusterName: { type: Type.STRING, description: "A refined, descriptive name for this specific cluster content." },
            intent: { 
              type: Type.STRING, 
              description: "The primary search intent: Informational, Transactional, Commercial, or Navigational." 
            }
          },
          required: ["id", "pillar", "clusterName", "intent"]
        }
      }
    },
    required: ["analysis"]
  };

  const systemInstruction = `
    You are a world-class SEO strategist. 
    I will provide you with a list of keyword clusters that were generated based on SERP overlap.

    Your Task:
    1. Analyze the keywords in each cluster to understand the topic.
    2. Assign a 'Pillar' (Broad Topic) that groups related clusters together.
    3. Assign a 'Cluster Name' (Specific Page Topic). 
       - CRITICAL: If two different clusters are semantically identical, give them the EXACT SAME 'Cluster Name'.
    4. Determine the primary 'Search Intent'.

    Input Format: A list of objects { id, keywords }.
    Output Format: A list of objects { id, pillar, clusterName, intent }.
  `;

  // Process in batches
  for (let i = 0; i < clusters.length; i += BATCH_SIZE) {
    const batch = clusters.slice(i, i + BATCH_SIZE);

    // Simplify input: top 5 keywords per cluster
    const simplifiedInput = batch.map(c => ({
      id: c.id,
      keywords: c.keywords.slice(0, 5) 
    }));

    const prompt = `Analyze these keyword clusters:\n${JSON.stringify(simplifiedInput)}`;

    try {
      const response = await ai.models.generateContent({
        model: modelId,
        contents: prompt,
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: "application/json",
          responseSchema: responseSchema,
          temperature: 0.2,
        },
      });

      const text = response.text;
      if (text) {
        const parsed = JSON.parse(text);
        if (parsed.analysis && Array.isArray(parsed.analysis)) {
           results.push(...parsed.analysis);
        }
      }

      // Delay to avoid rate limits
      if (i + BATCH_SIZE < clusters.length) {
        await new Promise(r => setTimeout(r, 1000));
      }

    } catch (error) {
      console.error(`Gemini API Error (Batch ${i} - ${i + BATCH_SIZE}):`, error);
      // Continue to next batch, logging the error. 
      // This ensures partial success rather than total failure.
    }
  }

  return results;
};

