/**
 * Advanced Clustering Strategy:
 * 1. Checks coherence (Splits mixed clusters).
 * 2. Standardizes names (Allows Merging later).
 * 3. Assigns specific Persian Intents.
 */
export const refineClusteringStrategy = async (
  clusters: { id: number; keywords: string[] }[]
): Promise<{ originalId: number; newClusterName: string; intent: string; keywords: string[] }[]> => {
  if (!clusters.length) return [];

  const modelId = 'gemini-3-flash-preview';
  const BATCH_SIZE = 5; // Reduced batch size for complex logic
  const results: { originalId: number; newClusterName: string; intent: string; keywords: string[] }[] = [];

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      refinedClusters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            originalId: { type: Type.INTEGER, description: "The ID of the input cluster this group came from." },
            newClusterName: { type: Type.STRING, description: "Standardized topic name." },
            intent: { 
              type: Type.STRING, 
              enum: [
                "صفحه دسته بندی",
                "صفحه دسته بندی زیر لایه",
                "صفحه تگ",
                "صفحه محصول تکی",
                "بلاگ"
              ]
            },
            keywords: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "The specific keywords belonging to this new refined group."
            }
          },
          required: ["originalId", "newClusterName", "intent", "keywords"]
        }
      }
    },
    required: ["refinedClusters"]
  };

  const systemInstruction = `
    You are a Senior SEO Strategist for the Persian market.
    I will send you 'Input Clusters' (ID + Keywords) generated by a SERP algorithm.

    YOUR TASKS:
    1. **VALIDATE (SPLIT):** Check if the keywords in a single input cluster truly belong to the exact same page. 
       - If a cluster contains keywords for different intents or distinct sub-topics, SPLIT them into multiple output objects.
       - Example: If a cluster has "buy iphone" and "iphone history", split them.

    2. **STANDARDIZE (MERGE PREP):** Assign a 'newClusterName' that represents the core topic.
       - Use generic, standard names so that if two different input clusters are about the same thing, they get the SAME name (enabling merging later).

    3. **INTENT CLASSIFICATION:** Assign one of these EXACT Persian intents:
       - "صفحه دسته بندی" (Main Category)
       - "صفحه دسته بندی زیر لایه" (Sub-category/Filtered Category)
       - "صفحه تگ" (Tag/Attribute Page)
       - "صفحه محصول تکی" (Single Product Page)
       - "بلاگ" (Informational/Article)

    CRITICAL RULES:
    - Every input keyword MUST appear in exactly one output cluster. Do not lose data.
    - Use Persian for 'newClusterName'.
  `;

  for (let i = 0; i < clusters.length; i += BATCH_SIZE) {
    const batch = clusters.slice(i, i + BATCH_SIZE);

    // We send all keywords to allow splitting
    const prompt = `Refine these clusters:\n${JSON.stringify(batch)}`;

    try {
      const response = await ai.models.generateContent({
        model: modelId,
        contents: prompt,
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: "application/json",
          responseSchema: responseSchema,
          temperature: 0.2,
        },
      });

      const text = response.text;
      if (text) {
        const parsed = JSON.parse(text);
        if (parsed.refinedClusters && Array.isArray(parsed.refinedClusters)) {
           results.push(...parsed.refinedClusters);
        }
      }

      if (i + BATCH_SIZE < clusters.length) {
        await new Promise(r => setTimeout(r, 1500));
      }

    } catch (error) {
      console.error(`Batch Error ${i}:`, error);
      // Fallback: Return original clusters as-is if AI fails
      batch.forEach(c => {
        results.push({
            originalId: c.id,
            newClusterName: "Error - Unprocessed",
            intent: "بررسی دستی",
            keywords: c.keywords
        });
      });
    }
  }

  return results;
};

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  Settings, 
  Play, 
  Download, 
  CheckCircle2, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  PieChart,
  BarChart3,
  BrainCircuit,
  Lightbulb,
  Network
} from 'lucide-react';
import { refineClusteringStrategy } from '../services/geminiService';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

export default function KeywordClusterer() {
  const [file, setFile] = useState<File | null>(null);
  const [domain, setDomain] = useState<string>('');
  const [apiKey, setApiKey] = useState<string>('');
  const [threshold, setThreshold] = useState<number>(5);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [progress, setProgress] = useState({ current: 0, total: 0 });

  // Base Data (SERP Only)
  const [baseSerpData, setBaseSerpData] = useState<any[] | null>(null);
  const [marketShare, setMarketShare] = useState<any[] | null>(null);
  const [originalKeywordsMeta, setOriginalKeywordsMeta] = useState<Record<string, any>>({});

  // AI Refined Data
  const [isAiAnalyzing, setIsAiAnalyzing] = useState<boolean>(false);
  const [refinedClusters, setRefinedClusters] = useState<any[] | null>(null);

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const getTopAddresses = async (keyword: string, currentDomain: string, key: string) => {
    const url = "https://google.serper.dev/search";
    const headers = {
        'X-API-KEY': key,
        'Content-Type': 'application/json'
    };
    const payload = JSON.stringify({ q: keyword, gl: "ir", hl: "fa" });

    try {
        const response = await fetch(url, {
            method: 'POST',
            headers: headers,
            body: payload
        });

        if (!response.ok) throw new Error(`Serper API Error: ${response.status}`);

        const data = await response.json();
        const addresses: string[] = [];
        let ourRank: number | null = null;
        let ourUrl: string | null = null;
        let titleCount = 0;
        let descCount = 0;
        const kLower = keyword.toLowerCase();

        const items = data.organic || [];
        items.forEach((item: any, idx: number) => {
            const link = item.link || '';
            const title = item.title || '';
            const snippet = item.snippet || '';

            if (link) addresses.push(link);

            // Stats
            titleCount += (title.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;
            descCount += (snippet.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;

            // Rank
            if (link && currentDomain && link.includes(currentDomain) && ourRank === null) {
                ourRank = idx + 1;
                ourUrl = link;
            }
        });

        return { addresses, ourRank, ourUrl, titleCount, descCount };
    } catch (error) {
        return { addresses: [], ourRank: null, ourUrl: null, titleCount: 0, descCount: 0 };
    }
  };

  const handleRun = async () => {
    if (!file) return addLog('لطفا فایل اکسل را انتخاب کنید.', 'error');
    if (!apiKey) return addLog('لطفا API Key سرویس Serper را وارد کنید.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setBaseSerpData(null);
    setRefinedClusters(null);
    setMarketShare(null);
    setOriginalKeywordsMeta({});

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        jsonData = jsonData.map(row => {
            const newRow: any = {};
            Object.keys(row).forEach(key => {
                newRow[key.trim().toLowerCase().replace(/ /g, '_')] = row[key];
            });
            return newRow;
        });

        const keywordsData = jsonData.filter(row => row.top_queries && String(row.top_queries).trim() !== '');

        if (keywordsData.length === 0) {
            setIsProcessing(false);
            return addLog('هیچ ستون top_queries معتبری یافت نشد.', 'error');
        }

        // Save original metadata for later lookup
        const metaMap: Record<string, any> = {};
        keywordsData.forEach(row => {
            metaMap[String(row.top_queries).trim()] = row;
        });
        setOriginalKeywordsMeta(metaMap);

        addLog(`${keywordsData.length} کلمه کلیدی یافت شد. شروع پردازش...`, 'info');
        setProgress({ current: 0, total: keywordsData.length });

        // Step 1: Fetch SERP Data
        const serpResults: Record<string, any> = {};
        const BATCH_SIZE = 3;
        for (let i = 0; i < keywordsData.length; i += BATCH_SIZE) {
            const batch = keywordsData.slice(i, i + BATCH_SIZE);
            await Promise.all(batch.map(async (row) => {
                const kw = String(row.top_queries).trim();
                const res = await getTopAddresses(kw, domain, apiKey);
                serpResults[kw] = res;
            }));

            setProgress({ current: Math.min(i + BATCH_SIZE, keywordsData.length), total: keywordsData.length });
            await new Promise(r => setTimeout(r, 500));
        }

        // Market Share
        addLog('در حال محاسبه سهم بازار رقبا...', 'info');
        const domainCounts: Record<string, number> = {};
        let totalUrls = 0;
        Object.values(serpResults).forEach((res: any) => {
            const addresses = res.addresses || [];
            addresses.forEach((url: string) => {
                try {
                    const hostname = new URL(url).hostname.replace(/^www\./, '');
                    if (hostname) {
                        domainCounts[hostname] = (domainCounts[hostname] || 0) + 1;
                        totalUrls++;
                    }
                } catch (e) {}
            });
        });
        const marketShareList = Object.entries(domainCounts)
            .map(([domain, count]) => ({
                Domain: domain,
                Frequency: count,
                'Share (%)': totalUrls > 0 ? ((count / totalUrls) * 100).toFixed(2) : "0"
            }))
            .sort((a, b) => b.Frequency - a.Frequency);
        setMarketShare(marketShareList);

        // Step 2: Basic Overlap Clustering
        addLog('در حال خوشه‌بندی اولیه (SERP Overlap)...', 'info');
        const clusters: string[][] = [];
        const visited = new Set<string>();
        const keywordsList = keywordsData.map(r => String(r.top_queries).trim());

        for (let i = 0; i < keywordsList.length; i++) {
            const kw1 = keywordsList[i];
            if (visited.has(kw1)) continue;

            const cluster = [kw1];
            visited.add(kw1);
            const set1 = new Set(serpResults[kw1]?.addresses || []);

            for (let j = i + 1; j < keywordsList.length; j++) {
                const kw2 = keywordsList[j];
                if (visited.has(kw2)) continue;

                const set2 = new Set(serpResults[kw2]?.addresses || []);
                const intersection = new Set([...set1].filter(x => set2.has(x)));

                if (intersection.size >= threshold) {
                    cluster.push(kw2);
                    visited.add(kw2);
                }
            }
            clusters.push(cluster);
        }

        // Prepare Base Data (Flat format for table)
        const finalRows: any[] = [];
        clusters.forEach((cluster, idx) => {
            const clusterId = idx + 1;
            cluster.forEach(kw => {
                const serp = serpResults[kw];
                finalRows.push({
                    'Cluster ID': clusterId,
                    'Query': kw,
                    'Our Rank': serp?.ourRank || '',
                    'Our URL': serp?.ourUrl || '',
                });
            });
        });

        setBaseSerpData(finalRows);
        addLog(`پردازش اولیه تمام شد. ${clusters.length} خوشه ایجاد شد.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا در پردازش فایل: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleAiRefinement = async () => {
    if (!baseSerpData || baseSerpData.length === 0) return;
    if (!process.env.API_KEY) {
        addLog('API Key تنظیم نشده است.', 'error');
        return;
    }

    setIsAiAnalyzing(true);
    addLog('شروع بازنگری هوشمند (تفکیک و ادغام کلاسترها)...', 'info');

    try {
        // Prepare input for AI (Group by original Cluster ID)
        const clusterMap = new Map<number, string[]>();
        baseSerpData.forEach(row => {
            const id = row['Cluster ID'];
            if (!clusterMap.has(id)) clusterMap.set(id, []);
            clusterMap.get(id)?.push(row['Query']);
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        // 1. Get Refined Clusters from Gemini (Split logic happens here)
        const refinedRaw = await refineClusteringStrategy(clustersInput);

        // 2. Perform Merging Logic (Frontend Side)
        // Group by "newClusterName" + "intent" to merge semantically identical clusters
        const mergedClustersMap = new Map<string, { name: string, intent: string, keywords: Set<string> }>();

        refinedRaw.forEach(item => {
            const key = `${item.newClusterName}::${item.intent}`;
            if (!mergedClustersMap.has(key)) {
                mergedClustersMap.set(key, {
                    name: item.newClusterName,
                    intent: item.intent,
                    keywords: new Set()
                });
            }
            item.keywords.forEach(k => mergedClustersMap.get(key)?.keywords.add(k));
        });

        // Convert Map to Array for display
        const finalRefinedData: any[] = [];
        let newClusterIdCounter = 1;

        mergedClustersMap.forEach((val) => {
            const currentId = newClusterIdCounter++;
            const keywordArray = Array.from(val.keywords);

            // Calculate total volume for this new cluster
            let clusterVolume = 0;
            keywordArray.forEach(k => {
                const meta = originalKeywordsMeta[k];
                if (meta && meta.impressions) clusterVolume += Number(meta.impressions) || 0;
            });

            keywordArray.forEach(kw => {
                // Find original SERP data for this keyword
                const originalSerpRow = baseSerpData.find(r => r['Query'] === kw);
                const meta = originalKeywordsMeta[kw];

                const row: any = {
                    'Refined Cluster ID': currentId,
                    'Cluster Name': val.name,
                    'Intent': val.intent,
                    'Query': kw,
                    'Cluster Volume': clusterVolume,
                    'Our Rank': originalSerpRow?.['Our Rank'] || '',
                    'Our URL': originalSerpRow?.['Our URL'] || ''
                };

                // Add original extra fields
                ['clicks', 'impressions', 'ctr', 'position'].forEach(f => {
                     if (meta && meta[f] !== undefined) {
                         row[f.charAt(0).toUpperCase() + f.slice(1)] = meta[f];
                     }
                });

                finalRefinedData.push(row);
            });
        });

        setRefinedClusters(finalRefinedData);
        addLog(`تحلیل هوشمند پایان یافت. ${mergedClustersMap.size} کلاستر نهایی ایجاد شد (پس از تفکیک و ادغام).`, 'success');

    } catch (error: any) {
        console.error(error);
        addLog('خطا در تحلیل هوشمند: ' + error.message, 'error');
    } finally {
        setIsAiAnalyzing(false);
    }
  };

  const generateMindMapText = () => {
    if (!refinedClusters) return '';

    // Group by Intent -> Cluster Name -> Keywords
    const tree: Record<string, Record<string, string[]>> = {};

    refinedClusters.forEach(row => {
        const intent = row['Intent'];
        const cluster = row['Cluster Name'];
        const kw = row['Query'];

        if (!tree[intent]) tree[intent] = {};
        if (!tree[intent][cluster]) tree[intent][cluster] = [];
        tree[intent][cluster].push(kw);
    });

    let mermaid = 'graph LR\n';
    mermaid += '  Root((استراتژی محتوا)):::root\n';

    let intentIndex = 1;
    for (const [intent, clusters] of Object.entries(tree)) {
        const iId = `I${intentIndex++}`;
        mermaid += `  Root --> ${iId}("${intent}"):::intent\n`;

        let clusterIndex = 1;
        for (const [clusterName, keywords] of Object.entries(clusters)) {
            const cId = `${iId}_C${clusterIndex++}`;
            mermaid += `  ${iId} --> ${cId}["${clusterName}"]:::cluster\n`;

            // Limit shown keywords in mindmap to keep it readable (top 3)
            keywords.slice(0, 3).forEach((k, kIdx) => {
                const kId = `${cId}_K${kIdx}`;
                mermaid += `  ${cId} --> ${kId}("${k}"):::keyword\n`;
            });
        }
    }

    // Styles
    mermaid += '\n  classDef root fill:#f97316,stroke:#fff,color:#fff,stroke-width:2px;';
    mermaid += '\n  classDef intent fill:#3b82f6,stroke:#fff,color:#fff;';
    mermaid += '\n  classDef cluster fill:#10b981,stroke:#fff,color:#fff;';
    mermaid += '\n  classDef keyword fill:#f3f4f6,stroke:#d1d5db,color:#374151;';

    return mermaid;
  };

  const handleDownloadMindMap = () => {
      const content = generateMindMapText();
      if (!content) return;

      const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `mindmap_mermaid_${new Date().getTime()}.txt`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      addLog('فایل مایند مپ (فرمت Mermaid) دانلود شد.', 'success');
  };

  const handleDownloadExcel = () => {
    const wb = XLSX.utils.book_new();

    // Sheet 1: Final Data (Refined or Base)
    const dataToExport = refinedClusters || baseSerpData;
    if (dataToExport) {
        const ws1 = XLSX.utils.json_to_sheet(dataToExport);
        XLSX.utils.book_append_sheet(wb, ws1, "Clusters");
    }

    // Sheet 2: Market Share
    if (marketShare) {
        const ws2 = XLSX.utils.json_to_sheet(marketShare);
        XLSX.utils.book_append_sheet(wb, ws2, "Market Share");
    }

    XLSX.writeFile(wb, "keyword_clusters_pro.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
       {/* Config Panel */}
       <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
             <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
               <Settings size={20} className="text-blue-500" />
               تنظیمات کلاستر
             </h2>

             <div className="space-y-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">فایل اکسل ورودی</label>
                 <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-blue-500 transition-colors">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-2 text-gray-500">
                        <FileSpreadsheet size={32} />
                        <span className="text-xs">{file ? file.name : "فایل را اینجا رها کنید یا کلیک کنید"}</span>
                    </div>
                 </div>
                 <p className="text-xs text-gray-400 mt-1">فایل باید ستون 'top_queries' داشته باشد.</p>
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">
                   دامنه هدف
                   <span className="text-gray-400 font-normal text-xs mr-1">(اختیاری)</span>
                 </label>
                 <input 
                   type="text" 
                   value={domain}
                   onChange={(e) => setDomain(e.target.value)}
                   placeholder="example.com"
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Serper API Key</label>
                 <input 
                   type="password" 
                   value={apiKey}
                   onChange={(e) => setApiKey(e.target.value)}
                   placeholder="sk-..."
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <div className="flex justify-between mb-1">
                   <label className="text-sm font-medium text-gray-700">آستانه همپوشانی (Threshold)</label>
                   <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">{threshold} لینک مشترک</span>
                 </div>
                 <input 
                   type="range" 
                   min="1" 
                   max="10" 
                   value={threshold}
                   onChange={(e) => setThreshold(Number(e.target.value))}
                   className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                   disabled={isProcessing}
                 />
               </div>

               <button 
                 onClick={handleRun}
                 disabled={isProcessing || isAiAnalyzing}
                 className="w-full flex items-center justify-center gap-2 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 disabled:opacity-50 transition-all mt-4"
               >
                 {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Play size={18} />}
                 <span>شروع خوشه‌بندی SERP</span>
               </button>
             </div>
          </div>

          <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
             <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
              <Terminal size={14} />
              Logs
            </h2>
            <div className="flex-1 overflow-y-auto font-mono text-xs space-y-1 custom-scrollbar">
              {logs.map((log) => (
                <div key={log.id} className={`flex gap-2 ${
                  log.type === 'error' ? 'text-red-400' : 
                  log.type === 'success' ? 'text-green-400' : 'text-gray-300'
                }`}>
                  <span className="text-gray-600">[{log.timestamp}]</span>
                  <span>{log.message}</span>
                </div>
              ))}
            </div>
          </div>
       </div>

       {/* Result Panel */}
       <div className="lg:col-span-8 flex flex-col h-full space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col min-h-[400px]">
                {baseSerpData ? (
                    <div className="flex-1 flex flex-col gap-6">

                        {/* Summary Header */}
                        <div className="bg-gray-50 border border-gray-200 rounded-lg p-4 flex items-center justify-between flex-wrap gap-4">
                            <div className="flex items-center gap-3">
                                <div className="bg-blue-500 text-white p-2 rounded-full">
                                    <CheckCircle2 size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-gray-800">
                                        {refinedClusters ? 'خوشه‌بندی نهایی (AI Refined)' : 'خوشه‌بندی اولیه (SERP)'}
                                    </h3>
                                    <p className="text-sm text-gray-600">
                                        {refinedClusters ? refinedClusters.length : baseSerpData.length} رکورد
                                    </p>
                                </div>
                            </div>

                            <div className="flex gap-2">
                                {/* AI Button */}
                                {!refinedClusters && (
                                    <button 
                                        onClick={handleAiRefinement}
                                        disabled={isAiAnalyzing}
                                        className="flex items-center gap-2 bg-purple-600 text-white px-4 py-2 rounded-lg hover:bg-purple-700 transition-colors shadow-sm disabled:opacity-70"
                                    >
                                        {isAiAnalyzing ? <Loader2 size={18} className="animate-spin" /> : <BrainCircuit size={18} />}
                                        <span>اصلاح هوشمند (Split/Merge)</span>
                                    </button>
                                )}

                                {refinedClusters && (
                                    <button 
                                        onClick={handleDownloadMindMap}
                                        className="flex items-center gap-2 bg-orange-500 text-white px-4 py-2 rounded-lg hover:bg-orange-600 transition-colors shadow-sm"
                                        title="دانلود فایل متنی برای استفاده در Mermaid Live Editor"
                                    >
                                        <Network size={18} />
                                        <span>Mind Map</span>
                                    </button>
                                )}

                                <button 
                                    onClick={handleDownloadExcel}
                                    className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors shadow-sm"
                                >
                                    <Download size={18} />
                                    <span>اکسل</span>
                                </button>
                            </div>
                        </div>

                        {/* Data Preview Table */}
                        <div className="bg-white rounded-lg border border-gray-200 overflow-hidden flex-1">
                             <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
                                <table className="w-full text-sm text-right">
                                    <thead className="bg-gray-100 text-gray-700 sticky top-0">
                                        <tr>
                                            {refinedClusters ? (
                                                <>
                                                    <th className="px-4 py-3">ID جدید</th>
                                                    <th className="px-4 py-3">نام کلاستر</th>
                                                    <th className="px-4 py-3">اینتنت</th>
                                                    <th className="px-4 py-3">کلمه کلیدی</th>
                                                    <th className="px-4 py-3">حجم کلاستر</th>
                                                </>
                                            ) : (
                                                <>
                                                    <th className="px-4 py-3">ID اولیه</th>
                                                    <th className="px-4 py-3">کلمه کلیدی</th>
                                                    <th className="px-4 py-3">رتبه ما</th>
                                                </>
                                            )}
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-200">
                                        {(refinedClusters || baseSerpData).slice(0, 100).map((row, idx) => (
