                                                {refinedClusters ? (
                                                    <>
                                                        <td className="px-4 py-2 text-center bg-gray-50 font-mono text-xs">{row['Refined Cluster ID']}</td>
                                                        <td className="px-4 py-2 font-medium">{row['Cluster Name']}</td>
                                                        <td className="px-4 py-2">
