                                </h4>
                                <div className="bg-gray-50 rounded-lg border border-gray-200 overflow-hidden">
                                    <table className="w-full text-sm text-right">
                                        <thead className="bg-gray-100 text-gray-600 border-b border-gray-200">
                                            <tr>
                                                <th className="px-4 py-3">رتبه</th>
                                                <th className="px-4 py-3">دامنه</th>
                                                <th className="px-4 py-3 text-center">تعداد حضور</th>
                                                <th className="px-4 py-3 text-center">سهم (%)</th>
                                                <th className="px-4 py-3 text-left w-32">وضعیت</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-gray-200">
                                            {marketShare.slice(0, 5).map((item, idx) => (
                                                <tr key={idx} className="hover:bg-white transition-colors">
                                                    <td className="px-4 py-3 text-gray-500">{idx + 1}</td>
                                                    <td className="px-4 py-3 font-medium text-gray-800" dir="ltr">{item.Domain}</td>
                                                    <td className="px-4 py-3 text-center text-gray-600">{item.Frequency}</td>
                                                    <td className="px-4 py-3 text-center font-bold text-blue-600">{item['Share (%)']}%</td>
                                                    <td className="px-4 py-3">
                                                        <div className="w-full bg-gray-200 rounded-full h-2">
                                                            <div 
                                                                className="bg-blue-500 h-2 rounded-full" 
                                                                style={{ width: `${Math.min(100, parseFloat(item['Share (%)']))}%` }}
                                                            ></div>
                                                        </div>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        )}
                    </div>
                ) : isProcessing ? (
                    <div className="flex flex-col items-center justify-center flex-1 space-y-4">
                        <Loader2 size={48} className="text-blue-500 animate-spin" />
                        <div className="text-center">
                            <p className="text-lg font-medium text-gray-700">در حال آنالیز کلمات و رقبا...</p>
                            <p className="text-sm text-gray-500 mt-1">{progress.current} از {progress.total} کلمه پردازش شده</p>
                        </div>
                        <div className="w-64 h-2 bg-gray-100 rounded-full overflow-hidden mt-4">
                            <div 
                                className="h-full bg-blue-500 transition-all duration-300"
                                style={{ width: `${(progress.current / Math.max(progress.total, 1)) * 100}%` }}
                            />
                        </div>
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center flex-1 text-gray-400 space-y-4">
                        <div className="bg-gray-50 p-6 rounded-full">
                            <PieChart size={48} className="opacity-20" />
                        </div>
                        <div className="text-center">
                            <h3 className="text-lg font-medium text-gray-600">آماده برای شروع</h3>
                            <p className="text-sm mt-1">فایل اکسل کلمات را بارگذاری کنید تا خوشه‌بندی و تحلیل رقبا انجام شود.</p>
                        </div>
                    </div>
                )}
            </div>
       </div>

       <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #1f2937;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #4b5563;
          border-radius: 3px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #6b7280;
        }
      `}</style>
    </div>
  );
}

