import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  Settings, 
  Play, 
  Download, 
  CheckCircle2, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  PieChart,
  BarChart3
} from 'lucide-react';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

export default function KeywordClusterer() {
  const [file, setFile] = useState<File | null>(null);
  const [domain, setDomain] = useState<string>('');
  const [apiKey, setApiKey] = useState<string>('');
  const [threshold, setThreshold] = useState<number>(5);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [progress, setProgress] = useState({ current: 0, total: 0 });

  // Base Data (SERP Only)
  const [baseSerpData, setBaseSerpData] = useState<any[] | null>(null);
  const [marketShare, setMarketShare] = useState<any[] | null>(null);

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const getTopAddresses = async (keyword: string, currentDomain: string, key: string) => {
    const url = "https://google.serper.dev/search";
    const headers = {
        'X-API-KEY': key,
        'Content-Type': 'application/json'
    };
    const payload = JSON.stringify({ q: keyword, gl: "ir", hl: "fa" });

    try {
        const response = await fetch(url, {
            method: 'POST',
            headers: headers,
            body: payload
        });

        if (!response.ok) throw new Error(`Serper API Error: ${response.status}`);

        const data = await response.json();
        const addresses: string[] = [];
        let ourRank: number | null = null;
        let ourUrl: string | null = null;
        let titleCount = 0;
        let descCount = 0;
        const kLower = keyword.toLowerCase();

        const items = data.organic || [];
        items.forEach((item: any, idx: number) => {
            const link = item.link || '';
            const title = item.title || '';
            const snippet = item.snippet || '';

            if (link) addresses.push(link);

            // Stats
            titleCount += (title.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;
            descCount += (snippet.toLowerCase().match(new RegExp(kLower, 'g')) || []).length;

            // Rank
            if (link && currentDomain && link.includes(currentDomain) && ourRank === null) {
                ourRank = idx + 1;
                ourUrl = link;
            }
        });

        return { addresses, ourRank, ourUrl, titleCount, descCount };
    } catch (error) {
        return { addresses: [], ourRank: null, ourUrl: null, titleCount: 0, descCount: 0 };
    }
  };

  const handleRun = async () => {
    if (!file) return addLog('لطفا فایل اکسل را انتخاب کنید.', 'error');
    if (!apiKey) return addLog('لطفا API Key سرویس Serper را وارد کنید.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setBaseSerpData(null);
    setMarketShare(null);

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        jsonData = jsonData.map(row => {
            const newRow: any = {};
            Object.keys(row).forEach(key => {
                newRow[key.trim().toLowerCase().replace(/ /g, '_')] = row[key];
            });
            return newRow;
        });

        const keywordsData = jsonData.filter(row => row.top_queries && String(row.top_queries).trim() !== '');

        if (keywordsData.length === 0) {
            setIsProcessing(false);
            return addLog('هیچ ستون top_queries معتبری یافت نشد.', 'error');
        }

        addLog(`${keywordsData.length} کلمه کلیدی یافت شد. شروع پردازش...`, 'info');
        setProgress({ current: 0, total: keywordsData.length });

        // Step 1: Fetch SERP Data
        const serpResults: Record<string, any> = {};
        const BATCH_SIZE = 3;
        for (let i = 0; i < keywordsData.length; i += BATCH_SIZE) {
            const batch = keywordsData.slice(i, i + BATCH_SIZE);
            await Promise.all(batch.map(async (row) => {
                const kw = String(row.top_queries).trim();
                const res = await getTopAddresses(kw, domain, apiKey);
                serpResults[kw] = res;
            }));

            setProgress({ current: Math.min(i + BATCH_SIZE, keywordsData.length), total: keywordsData.length });
            await new Promise(r => setTimeout(r, 500));
        }

        // Market Share
        addLog('در حال محاسبه سهم بازار رقبا...', 'info');
        const domainCounts: Record<string, number> = {};
        let totalUrls = 0;
        Object.values(serpResults).forEach((res: any) => {
            const addresses = res.addresses || [];
            addresses.forEach((url: string) => {
                try {
                    const hostname = new URL(url).hostname.replace(/^www\./, '');
                    if (hostname) {
                        domainCounts[hostname] = (domainCounts[hostname] || 0) + 1;
                        totalUrls++;
                    }
                } catch (e) {}
            });
        });
        const marketShareList = Object.entries(domainCounts)
            .map(([domain, count]) => ({
                Domain: domain,
                Frequency: count,
                'Share (%)': totalUrls > 0 ? ((count / totalUrls) * 100).toFixed(2) : "0"
            }))
            .sort((a, b) => b.Frequency - a.Frequency);
        setMarketShare(marketShareList);

        // Step 2: Basic Overlap Clustering
        addLog('در حال خوشه‌بندی اولیه (SERP Overlap)...', 'info');
        const clusters: string[][] = [];
        const visited = new Set<string>();
        const keywordsList = keywordsData.map(r => String(r.top_queries).trim());

        for (let i = 0; i < keywordsList.length; i++) {
            const kw1 = keywordsList[i];
            if (visited.has(kw1)) continue;

            const cluster = [kw1];
            visited.add(kw1);
            const set1 = new Set(serpResults[kw1]?.addresses || []);

            for (let j = i + 1; j < keywordsList.length; j++) {
                const kw2 = keywordsList[j];
                if (visited.has(kw2)) continue;

                const set2 = new Set(serpResults[kw2]?.addresses || []);
                const intersection = new Set([...set1].filter(x => set2.has(x)));

                if (intersection.size >= threshold) {
                    cluster.push(kw2);
                    visited.add(kw2);
                }
            }
            clusters.push(cluster);
        }

        // Prepare Base Data (Flat format for table)
        const finalRows: any[] = [];
        clusters.forEach((cluster, idx) => {
            const clusterId = idx + 1;
            cluster.forEach(kw => {
                const serp = serpResults[kw];
                finalRows.push({
                    'Cluster ID': clusterId,
                    'Query': kw,
                    'Our Rank': serp?.ourRank || '',
                    'Our URL': serp?.ourUrl || '',
                });
            });
        });

        setBaseSerpData(finalRows);
        addLog(`پردازش اولیه تمام شد. ${clusters.length} خوشه ایجاد شد.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا در پردازش فایل: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleDownloadExcel = () => {
    if (!baseSerpData) return;
    const wb = XLSX.utils.book_new();
    const ws1 = XLSX.utils.json_to_sheet(baseSerpData);
    XLSX.utils.book_append_sheet(wb, ws1, "SERP Clusters");
    if (marketShare) {
        const ws2 = XLSX.utils.json_to_sheet(marketShare);
        XLSX.utils.book_append_sheet(wb, ws2, "Market Share");
    }
    XLSX.writeFile(wb, "serp_clusters.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
       {/* Config Panel */}
       <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
             <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
               <Settings size={20} className="text-green-600" />
               تنظیمات SERP
             </h2>

             <div className="space-y-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">فایل اکسل کلمات</label>
                 <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-green-500 transition-colors">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-2 text-gray-500">
                        <FileSpreadsheet size={32} />
                        <span className="text-xs">{file ? file.name : "فایل را اینجا رها کنید"}</span>
                    </div>
                 </div>
                 <p className="text-xs text-gray-400 mt-1">ستون 'top_queries' الزامی است.</p>
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">دامنه هدف (اختیاری)</label>
                 <input 
                   type="text" 
                   value={domain}
                   onChange={(e) => setDomain(e.target.value)}
                   placeholder="example.com"
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Serper API Key</label>
                 <input 
                   type="password" 
                   value={apiKey}
                   onChange={(e) => setApiKey(e.target.value)}
                   placeholder="sk-..."
                   className="w-full p-2 border border-gray-300 rounded-md text-sm text-left ltr"
                   disabled={isProcessing}
                 />
               </div>

               <div>
                 <div className="flex justify-between mb-1">
                   <label className="text-sm font-medium text-gray-700">آستانه همپوشانی (Threshold)</label>
                   <span className="text-xs bg-green-100 text-green-800 px-2 py-0.5 rounded-full">{threshold} لینک</span>
                 </div>
                 <input 
                   type="range" 
                   min="1" 
                   max="10" 
                   value={threshold}
                   onChange={(e) => setThreshold(Number(e.target.value))}
                   className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-green-600"
                   disabled={isProcessing}
                 />
               </div>

               <button 
                 onClick={handleRun}
                 disabled={isProcessing}
                 className="w-full flex items-center justify-center gap-2 bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 disabled:opacity-50 transition-all mt-4"
               >
                 {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <Play size={18} />}
                 <span>شروع خوشه‌بندی</span>
               </button>
             </div>
          </div>

          <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
             <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
              <Terminal size={14} />
              Logs
            </h2>
            <div className="flex-1 overflow-y-auto font-mono text-xs space-y-1 custom-scrollbar">
              {logs.map((log) => (
                <div key={log.id} className={`flex gap-2 ${
                  log.type === 'error' ? 'text-red-400' : 
                  log.type === 'success' ? 'text-green-400' : 'text-gray-300'
                }`}>
                  <span className="text-gray-600">[{log.timestamp}]</span>
                  <span>{log.message}</span>
                </div>
              ))}
            </div>
          </div>
       </div>

       {/* Result Panel */}
       <div className="lg:col-span-8 flex flex-col h-full space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col min-h-[400px]">
                {baseSerpData ? (
                    <div className="flex-1 flex flex-col gap-6">

                        {/* Summary Header */}
                        <div className="bg-gray-50 border border-gray-200 rounded-lg p-4 flex items-center justify-between flex-wrap gap-4">
                            <div className="flex items-center gap-3">
                                <div className="bg-green-500 text-white p-2 rounded-full">
                                    <CheckCircle2 size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-gray-800">نتایج خوشه‌بندی SERP</h3>
                                    <p className="text-sm text-gray-600">{baseSerpData.length} کلمه پردازش شد</p>
                                </div>
                            </div>

                            <button 
                                onClick={handleDownloadExcel}
                                className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors shadow-sm"
                            >
                                <Download size={18} />
                                <span>دانلود اکسل</span>
                            </button>
                        </div>

                        {/* Data Preview Table */}
                        <div className="bg-white rounded-lg border border-gray-200 overflow-hidden flex-1">
                             <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
                                <table className="w-full text-sm text-right">
                                    <thead className="bg-gray-100 text-gray-700 sticky top-0">
                                        <tr>
                                            <th className="px-4 py-3">ID کلاستر</th>
                                            <th className="px-4 py-3">کلمه کلیدی</th>
                                            <th className="px-4 py-3">رتبه ما</th>
                                            <th className="px-4 py-3 text-left" dir="ltr">Our URL</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-200">
                                        {baseSerpData.slice(0, 100).map((row, idx) => (
                                            <tr key={idx} className="hover:bg-gray-50">
                                                <td className="px-4 py-2 text-center bg-gray-50">{row['Cluster ID']}</td>
                                                <td className="px-4 py-2">{row['Query']}</td>
                                                <td className="px-4 py-2 text-center">{row['Our Rank'] || '-'}</td>
