import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  BrainCircuit, 
  Download, 
  CheckCircle2, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  Network,
  GitMerge,
  GitBranch,
  Lightbulb
} from 'lucide-react';
import { refineClusteringStrategy } from '../services/geminiService';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

export default function AiClusterRefiner() {
  const [file, setFile] = useState<File | null>(null);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const [refinedClusters, setRefinedClusters] = useState<any[] | null>(null);
  const [originalMeta, setOriginalMeta] = useState<Record<string, any>>({});

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل کلاستر شده انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const processFileAndRunAi = async () => {
    if (!file) return addLog('لطفا فایل اکسل کلاستر شده (خروجی مرحله قبل) را آپلود کنید.', 'error');
    if (!process.env.API_KEY) return addLog('API Key یافت نشد.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setRefinedClusters(null);
    setOriginalMeta({});

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        // Normalize headers
        jsonData = jsonData.map(row => {
            const newRow: any = {};
            Object.keys(row).forEach(key => {
                const normKey = key.trim().toLowerCase().replace(/ /g, '_');
                newRow[normKey] = row[key];
                // Handle different possible column names for Cluster ID and Query
                if (normKey === 'cluster_id' || normKey === 'id') newRow['cluster_id'] = row[key];
                if (normKey === 'query' || normKey === 'keyword' || normKey === 'top_queries') newRow['query'] = row[key];
            });
            // Keep original row data for preservation
            newRow._original = row;
            return newRow;
        });

        const validRows = jsonData.filter(r => r.cluster_id && r.query);

        if (validRows.length === 0) {
            setIsProcessing(false);
            return addLog('فایل نامعتبر است. ستون‌های Cluster ID و Query پیدا نشدند.', 'error');
        }

        // Save original metadata
        const meta: Record<string, any> = {};
        validRows.forEach(row => {
            meta[String(row.query).trim()] = row._original;
        });
        setOriginalMeta(meta);

        addLog(`${validRows.length} کلمه از فایل خوانده شد. گروه‌بندی جهت ارسال به AI...`, 'info');

        // Group by Cluster ID
        const clusterMap = new Map<number, string[]>();
        validRows.forEach(row => {
            const id = parseInt(row.cluster_id);
            if (!clusterMap.has(id)) clusterMap.set(id, []);
            clusterMap.get(id)?.push(String(row.query).trim());
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        addLog(`شروع تحلیل ${clustersInput.length} کلاستر توسط Gemini...`, 'info');

        // 1. AI Processing (Split Logic)
        const refinedRaw = await refineClusteringStrategy(clustersInput);

        // 2. Merge Logic (Frontend)
        addLog('در حال ادغام کلاسترهای مشابه...', 'info');
        const mergedClustersMap = new Map<string, { name: string, intent: string, keywords: Set<string> }>();

        refinedRaw.forEach(item => {
            const key = `${item.newClusterName}::${item.intent}`;
            if (!mergedClustersMap.has(key)) {
                mergedClustersMap.set(key, {
                    name: item.newClusterName,
                    intent: item.intent,
                    keywords: new Set()
                });
            }
            item.keywords.forEach(k => mergedClustersMap.get(key)?.keywords.add(k));
        });

        // 3. Finalize Data
        const finalRefinedData: any[] = [];
        let newClusterIdCounter = 1;

        mergedClustersMap.forEach((val) => {
            const currentId = newClusterIdCounter++;
            const keywordArray = Array.from(val.keywords);

            keywordArray.forEach(kw => {
                const originalData = meta[kw] || {};

                const row: any = {
                    'Refined ID': currentId,
                    'Cluster Name': val.name,
                    'Intent': val.intent,
                    'Query': kw,
                    ...originalData // Keep original metrics
                };
                // Clean up internal keys
                delete row['cluster_id'];
                delete row['query'];
                delete row['_original'];
                delete row['Refined Cluster ID']; // Avoid duplicate keys if file was already refined

                finalRefinedData.push(row);
            });
        });

        setRefinedClusters(finalRefinedData);
        addLog(`پایان عملیات. ${mergedClustersMap.size} کلاستر نهایی ایجاد شد.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const generateMindMapText = () => {
    if (!refinedClusters) return '';

    // Group by Intent -> Cluster Name -> Keywords
    const tree: Record<string, Record<string, string[]>> = {};

    refinedClusters.forEach(row => {
        const intent = row['Intent'];
        const cluster = row['Cluster Name'];
        const kw = row['Query'];

        if (!tree[intent]) tree[intent] = {};
        if (!tree[intent][cluster]) tree[intent][cluster] = [];
        tree[intent][cluster].push(kw);
    });

    let mermaid = 'graph LR\n';
    mermaid += '  Root((استراتژی محتوا)):::root\n';

    let intentIndex = 1;
    for (const [intent, clusters] of Object.entries(tree)) {
        const iId = `I${intentIndex++}`;

        // Define specific classes for known intents to match user request colors implies
        let intentClass = 'defaultIntent';
        if (intent.includes('محصول')) intentClass = 'productIntent';
        else if (intent.includes('دسته')) intentClass = 'catIntent';
        else if (intent.includes('بلاگ')) intentClass = 'blogIntent';

        mermaid += `  Root --> ${iId}("${intent}"):::${intentClass}\n`;

        let clusterIndex = 1;
        for (const [clusterName, keywords] of Object.entries(clusters)) {
            const cId = `${iId}_C${clusterIndex++}`;
            mermaid += `  ${iId} --> ${cId}["${clusterName}"]:::cluster\n`;

            // Limit keywords in visualization
            keywords.slice(0, 5).forEach((k, kIdx) => {
                const kId = `${cId}_K${kIdx}`;
                mermaid += `  ${cId} --> ${kId}("${k}"):::keyword\n`;
            });
        }
    }

    // Aesthetic Styles based on user preferences/standard SEO maps
    mermaid += '\n  classDef root fill:#2d3748,stroke:#fff,color:#fff,stroke-width:2px;';

    // Intent Colors
    mermaid += '\n  classDef catIntent fill:#3b82f6,stroke:#fff,color:#fff;'; // Blue for Categories
    mermaid += '\n  classDef productIntent fill:#ef4444,stroke:#fff,color:#fff;'; // Red for Products
    mermaid += '\n  classDef blogIntent fill:#10b981,stroke:#fff,color:#fff;'; // Green for Blog
    mermaid += '\n  classDef defaultIntent fill:#8b5cf6,stroke:#fff,color:#fff;'; // Purple for others

    // Cluster & Keyword Colors
    mermaid += '\n  classDef cluster fill:#e2e8f0,stroke:#cbd5e1,color:#1e293b;'; // Light gray for clusters
    mermaid += '\n  classDef keyword fill:#fff,stroke:#e2e8f0,color:#64748b,font-size:10px;'; // White for keywords

    return mermaid;
  };

  const handleDownloadMindMap = () => {
      const content = generateMindMapText();
      if (!content) return;

      const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `mindmap_pro_${new Date().getTime()}.txt`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      addLog('فایل مایند مپ دانلود شد. آن را در سایت mermaid.live باز کنید.', 'success');
  };

  const handleDownloadExcel = () => {
    if (!refinedClusters) return;
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(refinedClusters);
    XLSX.utils.book_append_sheet(wb, ws, "AI Refined Clusters");
    XLSX.writeFile(wb, "ai_refined_strategy.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
       {/* Config Panel */}
       <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
             <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
               <BrainCircuit size={20} className="text-purple-600" />
               تنظیمات تحلیل هوشمند
             </h2>

             <div className="space-y-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">فایل اکسل کلاستر شده</label>
                 <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-purple-500 transition-colors">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-2 text-gray-500">
                        <FileSpreadsheet size={32} />
                        <span className="text-xs">{file ? file.name : "فایل خروجی مرحله قبل را اینجا رها کنید"}</span>
                    </div>
                 </div>
                 <p className="text-xs text-gray-400 mt-1">باید شامل ستون های Cluster ID و Query باشد.</p>
               </div>

               <div className="bg-purple-50 p-3 rounded-lg text-xs text-purple-700 space-y-2">
                 <p className="font-semibold flex items-center gap-1"><Lightbulb size={12}/> کارهایی که انجام می‌شود:</p>
                 <ul className="list-disc list-inside space-y-1 opacity-80">
                   <li>تفکیک کلاسترهای نامرتبط (Split)</li>
                   <li>ادغام کلاسترهای هم‌معنی (Merge)</li>
                   <li>تشخیص هدف کاربر (Intent)</li>
                   <li>آماده‌سازی برای نقشه‌ذهنی (Mind Map)</li>
                 </ul>
               </div>

               <button 
                 onClick={processFileAndRunAi}
                 disabled={isProcessing}
                 className="w-full flex items-center justify-center gap-2 bg-purple-600 text-white py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 transition-all mt-4"
               >
                 {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <BrainCircuit size={18} />}
                 <span>شروع تحلیل AI</span>
               </button>
             </div>
          </div>

          <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
             <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
              <Terminal size={14} />
              Logs
