import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const filterKeywordsBatch = async (
  keywords: string[],
  userPrompt: string
): Promise<string[]> => {
  if (!keywords.length) return [];

  const modelId = 'gemini-3-flash-preview'; 

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      keptKeywords: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "The list of keywords that match the criteria and should be kept."
      }
    },
    required: ["keptKeywords"]
  };

  const systemInstruction = `
    You are a specialized SEO keyword filtering assistant.
    Your task is to analyze a list of keywords and filter them based strictly on the user's criteria.
    Rules:
    1. Return ONLY the keywords that satisfy the user's criteria.
    2. Do not modify the text of the keywords.
  `;

  const prompt = `User Criteria: "${userPrompt}"\nKeywords: ${JSON.stringify(keywords)}`;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1,
      },
    });

    const text = response.text;
    if (!text) return keywords;
    const parsed = JSON.parse(text);
    return parsed.keptKeywords || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

/**
 * Advanced Clustering Strategy:
 * 1. Checks coherence (Splits mixed clusters).
 * 2. Standardizes names (Allows Merging later).
 * 3. Assigns specific Persian Intents.
 * 4. Determines Parent/Child Hierarchy.
 */
export const refineClusteringStrategy = async (
  clusters: { id: number; keywords: string[] }[]
): Promise<{ originalId: number; newClusterName: string; intent: string; parents: string[]; keywords: string[] }[]> => {
  if (!clusters.length) return [];

  const modelId = 'gemini-3-flash-preview';
  const BATCH_SIZE = 5; 
  const results: { originalId: number; newClusterName: string; intent: string; parents: string[]; keywords: string[] }[] = [];

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      refinedClusters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            originalId: { type: Type.INTEGER, description: "The ID of the input cluster this group came from." },
            newClusterName: { type: Type.STRING, description: "Standardized topic name." },
            intent: { 
              type: Type.STRING, 
              enum: [
                "صفحه دسته بندی",
                "صفحه دسته بندی زیر لایه",
                "صفحه تگ",
                "صفحه محصول تکی",
                "بلاگ"
              ]
            },
            parents: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "List of parent category names. If it's a root category, leave empty."
            },
            keywords: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "The specific keywords belonging to this new refined group."
            }
          },
          required: ["originalId", "newClusterName", "intent", "keywords", "parents"]
        }
      }
    },
    required: ["refinedClusters"]
  };

  const systemInstruction = `
    You are a Senior SEO Strategist & Information Architect for the Persian market.
    I will send you 'Input Clusters' (ID + Keywords).

    YOUR TASKS:
    1. **VALIDATE (SPLIT):** 
       - If a cluster contains keywords with DIFFERENT Intents or distinct TOPICS, SPLIT them into separate objects.
       - Example: Input ID 10 has "buy shoe" (Category) and "shoe repair guide" (Blog). Return TWO objects with originalId 10.

    2. **HIERARCHY (PARENTS):**
       - For every resulting cluster, determine its 'parents' (the broader category it belongs to).
       - A cluster can have MULTIPLE parents (e.g., 'Men's Running Shoes' belongs to 'Men's Shoes' AND 'Sports Equipment').
       - If it is a top-level category, the 'parents' array should be empty.
       - Use generic Persian names for parents (e.g., "لوازم دیجیتال", "پوشاک").

    3. **NAMING & INTENT:**
       - Assign 'newClusterName' (Standard Persian Name).
       - Assign 'intent' from: "صفحه دسته بندی", "صفحه دسته بندی زیر لایه", "صفحه تگ", "صفحه محصول تکی", "بلاگ".

    CRITICAL RULES:
    - Every input keyword MUST appear in exactly one output cluster.
    - Output must be JSON.
  `;

  for (let i = 0; i < clusters.length; i += BATCH_SIZE) {
    const batch = clusters.slice(i, i + BATCH_SIZE);

    const prompt = `Refine and Architect these clusters:\n${JSON.stringify(batch)}`;

    try {
      const response = await ai.models.generateContent({
        model: modelId,
        contents: prompt,
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: "application/json",
          responseSchema: responseSchema,
          temperature: 0.2,
        },
      });

      const text = response.text;
      if (text) {
        const parsed = JSON.parse(text);
        if (parsed.refinedClusters && Array.isArray(parsed.refinedClusters)) {
           results.push(...parsed.refinedClusters);
        }
      }

      if (i + BATCH_SIZE < clusters.length) {
        await new Promise(r => setTimeout(r, 1500));
      }

    } catch (error) {
      console.error(`Batch Error ${i}:`, error);
      // Fallback
      batch.forEach(c => {
        results.push({
            originalId: c.id,
            newClusterName: "Error - Unprocessed",
            intent: "بررسی دستی",
            parents: [],
            keywords: c.keywords
        });
      });
    }
  }

  return results;
};

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  BrainCircuit, 
  Download, 
  CheckCircle2, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  Network,
  GitMerge,
  GitBranch,
  Lightbulb,
  Split
} from 'lucide-react';
import { refineClusteringStrategy } from '../services/geminiService';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

interface RefinedClusterData {
    'Refined ID': string; // String to support "36-1"
    'Cluster Name': string;
    'Intent': string;
    'Parents': string; // Comma separated string for display
    'Query': string;
    [key: string]: any;
}

export default function AiClusterRefiner() {
  const [file, setFile] = useState<File | null>(null);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const [refinedClusters, setRefinedClusters] = useState<RefinedClusterData[] | null>(null);
  const [originalMeta, setOriginalMeta] = useState<Record<string, any>>({});

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل کلاستر شده انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const processFileAndRunAi = async () => {
    if (!file) return addLog('لطفا فایل اکسل کلاستر شده (خروجی مرحله قبل) را آپلود کنید.', 'error');
    if (!process.env.API_KEY) return addLog('API Key یافت نشد.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setRefinedClusters(null);
    setOriginalMeta({});

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        // Normalize headers
        jsonData = jsonData.map(row => {
            const newRow: any = {};
            Object.keys(row).forEach(key => {
                const normKey = key.trim().toLowerCase().replace(/ /g, '_');
                newRow[normKey] = row[key];
                if (normKey === 'cluster_id' || normKey === 'id') newRow['cluster_id'] = row[key];
                if (normKey === 'query' || normKey === 'keyword' || normKey === 'top_queries') newRow['query'] = row[key];
            });
            newRow._original = row;
            return newRow;
        });

        const validRows = jsonData.filter(r => r.cluster_id && r.query);

        if (validRows.length === 0) {
            setIsProcessing(false);
            return addLog('فایل نامعتبر است. ستون‌های Cluster ID و Query پیدا نشدند.', 'error');
        }

        const meta: Record<string, any> = {};
        validRows.forEach(row => {
            meta[String(row.query).trim()] = row._original;
        });
        setOriginalMeta(meta);

        addLog(`${validRows.length} کلمه از فایل خوانده شد. گروه‌بندی جهت ارسال به AI...`, 'info');

        const clusterMap = new Map<number, string[]>();
        validRows.forEach(row => {
            const id = parseInt(row.cluster_id);
            if (!clusterMap.has(id)) clusterMap.set(id, []);
            clusterMap.get(id)?.push(String(row.query).trim());
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        addLog(`شروع تحلیل معماری ${clustersInput.length} کلاستر توسط Gemini...`, 'info');

        // 1. AI Processing (Split & Hierarchy)
        const refinedRaw = await refineClusteringStrategy(clustersInput);

        // 2. Process Splits & Assign IDs (N, N-1, N-2...)
        // We group results by 'originalId' first to track splits
        const splitGroups = new Map<number, typeof refinedRaw>();
        refinedRaw.forEach(item => {
            if (!splitGroups.has(item.originalId)) splitGroups.set(item.originalId, []);
            splitGroups.get(item.originalId)?.push(item);
        });

        const finalRefinedData: RefinedClusterData[] = [];

        splitGroups.forEach((items, origId) => {
            items.forEach((item, index) => {
                // ID Generation Logic:
                // Index 0 -> Original ID (e.g., "36")
                // Index > 0 -> Original ID - Index (e.g., "36-1", "36-2")
                const displayId = index === 0 ? String(origId) : `${origId}-${index}`;

                item.keywords.forEach(kw => {
                    const originalData = meta[kw] || {};
                    const parentStr = item.parents && item.parents.length > 0 ? item.parents.join(' | ') : 'Root';

                    const row: RefinedClusterData = {
                        'Refined ID': displayId,
                        'Cluster Name': item.newClusterName,
                        'Intent': item.intent,
                        'Parents': parentStr,
                        'Query': kw,
                        ...originalData
                    };

                    delete row['cluster_id'];
                    delete row['query'];
                    delete row['_original'];
                    delete row['Refined Cluster ID']; 

                    finalRefinedData.push(row);
                });
            });
        });

        // Sorting for better view (Numeric sort handling dashes)
        finalRefinedData.sort((a, b) => {
            const idA = parseFloat(a['Refined ID'].replace('-', '.'));
            const idB = parseFloat(b['Refined ID'].replace('-', '.'));
            return idA - idB;
        });

        setRefinedClusters(finalRefinedData);
        addLog(`تحلیل پایان یافت. ساختار سلسله‌مراتبی ایجاد شد.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const generateHierarchicalMindMap = () => {
    if (!refinedClusters) return '';

    // 1. Build Nodes and Edges
    // Map<ClusterName, { intent, id }>
    const clusters = new Map<string, { intent: string, id: string, keywords: string[] }>();
    const relationships: { parent: string, child: string }[] = [];

    refinedClusters.forEach(row => {
        const cName = row['Cluster Name'];
        if (!clusters.has(cName)) {
            clusters.set(cName, { 
                intent: row['Intent'], 
                id: `node_${Math.abs(hashCode(cName))}`, // Generate safe ID
                keywords: []
            });
        }
        clusters.get(cName)?.keywords.push(row['Query']);

        const parentStr = row['Parents'];
        if (parentStr && parentStr !== 'Root') {
            const parents = parentStr.split('|').map(p => p.trim());
            parents.forEach(p => {
                relationships.push({ parent: p, child: cName });
                // Ensure parent exists as a node (likely a Category) if not already
                if (!clusters.has(p)) {
                    clusters.set(p, { 
                        intent: 'صفحه دسته بندی', // Assume parent is category
                        id: `node_${Math.abs(hashCode(p))}`,
                        keywords: [] 
                    }); 
                }
            });
        } else {
             // Connect Roots to a central node
             relationships.push({ parent: 'Main_Topic', child: cName });
        }
    });

    // 2. Generate Mermaid String
    let mermaid = 'graph LR\n';
    mermaid += '  Main_Topic((استراتژی محتوا)):::root\n';

    // Define Nodes
    clusters.forEach((data, name) => {
        let shapeStart = '[';
        let shapeEnd = ']';

        // Shape based on intent logic
        if (data.intent.includes('محصول')) { shapeStart = '(['; shapeEnd = '])'; } // Oval
        else if (data.intent.includes('دسته')) { shapeStart = '['; shapeEnd = ']'; } // Rect

        // Clean name for display label (remove quotes)
        const label = name.replace(/"/g, '');

        // Determine Class
        let cssClass = 'defaultIntent';
        if (data.intent.includes('محصول')) cssClass = 'productIntent';
        else if (data.intent.includes('دسته')) cssClass = 'catIntent';
        else if (data.intent.includes('بلاگ')) cssClass = 'blogIntent';
        else if (data.intent.includes('تگ')) cssClass = 'tagIntent';

        mermaid += `  ${data.id}${shapeStart}"${label}"${shapeEnd}:::${cssClass}\n`;

        // Add Top 3 Keywords as a subgraph or tooltip-like node (simplified here as attached nodes)
        // Only for leaf nodes (not parents) to reduce clutter, or just list 2
        if (data.keywords.length > 0) {
            // Check if this node is a parent to anyone?
            const isParent = relationships.some(r => r.parent === name);
            if (!isParent) {
                 data.keywords.slice(0, 3).forEach((k, idx) => {
                    mermaid += `  ${data.id} -.-> ${data.id}_k${idx}("${k}"):::keyword\n`;
                 });
            }
        }
    });

    // Define Edges
    const uniqueEdges = new Set<string>();
    relationships.forEach(rel => {
        const pId = clusters.get(rel.parent)?.id || 'Main_Topic';
        const cId = clusters.get(rel.child)?.id;
        if (pId && cId) {
            const edgeKey = `${pId}->${cId}`;
            if (!uniqueEdges.has(edgeKey)) {
                mermaid += `  ${pId} --> ${cId}\n`;
                uniqueEdges.add(edgeKey);
            }
        }
    });

    // Styles
    mermaid += '\n  classDef root fill:#1e293b,stroke:#fff,color:#fff,stroke-width:2px;';
    mermaid += '\n  classDef catIntent fill:#3b82f6,stroke:#1d4ed8,color:#fff;'; // Blue
    mermaid += '\n  classDef productIntent fill:#ef4444,stroke:#b91c1c,color:#fff;'; // Red
    mermaid += '\n  classDef blogIntent fill:#10b981,stroke:#047857,color:#fff;'; // Green
    mermaid += '\n  classDef tagIntent fill:#f59e0b,stroke:#b45309,color:#fff;'; // Amber
    mermaid += '\n  classDef defaultIntent fill:#8b5cf6,stroke:#6d28d9,color:#fff;'; // Purple
    mermaid += '\n  classDef keyword fill:#f8fafc,stroke:#e2e8f0,color:#64748b,font-size:10px,stroke-dasharray: 5 5;';

    return mermaid;
  };

  // Helper for unique IDs
  const hashCode = (str: string) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        const char = str.charCodeAt(i);
        hash = (hash << 5) - hash + char;
        hash = hash & hash; 
    }
    return hash;
  };

  const handleDownloadMindMap = () => {
      const content = generateHierarchicalMindMap();
      if (!content) return;

      const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `hierarchy_mindmap_${new Date().getTime()}.txt`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      addLog('مایند مپ سلسله‌مراتبی دانلود شد.', 'success');
  };

  const handleDownloadExcel = () => {
    if (!refinedClusters) return;
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(refinedClusters);
    XLSX.utils.book_append_sheet(wb, ws, "Hierarchical Strategy");
    XLSX.writeFile(wb, "seo_hierarchy_strategy.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
       {/* Config Panel */}
       <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
             <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
               <BrainCircuit size={20} className="text-purple-600" />
               تنظیمات تحلیل هوشمند
             </h2>

             <div className="space-y-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">فایل اکسل کلاستر شده</label>
                 <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-purple-500 transition-colors">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-2 text-gray-500">
                        <FileSpreadsheet size={32} />
                        <span className="text-xs">{file ? file.name : "فایل خروجی مرحله قبل را اینجا رها کنید"}</span>
                    </div>
                 </div>
                 <p className="text-xs text-gray-400 mt-1">باید شامل ستون های Cluster ID و Query باشد.</p>
               </div>

               <div className="bg-purple-50 p-3 rounded-lg text-xs text-purple-700 space-y-2">
                 <p className="font-semibold flex items-center gap-1"><Lightbulb size={12}/> ویژگی‌های جدید:</p>
                 <ul className="list-disc list-inside space-y-1 opacity-80">
                   <li><span className="font-bold">تفکیک (Split):</span> کلاسترهای مخلوط جدا می‌شوند (ID جدید: 36-1).</li>
                   <li><span className="font-bold">سلسله‌مراتب:</span> تشخیص والد (Parent) برای هر کلاستر.</li>
                   <li><span className="font-bold">چند والدی:</span> پشتیبانی از محصولاتی که در چند دسته هستند.</li>
                 </ul>
               </div>

               <button 
                 onClick={processFileAndRunAi}
                 disabled={isProcessing}
                 className="w-full flex items-center justify-center gap-2 bg-purple-600 text-white py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 transition-all mt-4"
               >
                 {isProcessing ? <Loader2 size={18} className="animate-spin" /> : <BrainCircuit size={18} />}
                 <span>شروع تحلیل معماری</span>
               </button>
             </div>
          </div>

          <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
             <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
              <Terminal size={14} />
              Logs
            </h2>
            <div className="flex-1 overflow-y-auto font-mono text-xs space-y-1 custom-scrollbar">
              {logs.map((log) => (
                <div key={log.id} className={`flex gap-2 ${
                  log.type === 'error' ? 'text-red-400' : 
                  log.type === 'success' ? 'text-green-400' : 'text-gray-300'
                }`}>
                  <span className="text-gray-600">[{log.timestamp}]</span>
                  <span>{log.message}</span>
                </div>
              ))}
            </div>
          </div>
       </div>

       {/* Result Panel */}
       <div className="lg:col-span-8 flex flex-col h-full space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col min-h-[400px]">
                {refinedClusters ? (
                    <div className="flex-1 flex flex-col gap-6">

                        {/* Summary Header */}
                        <div className="bg-purple-50 border border-purple-100 rounded-lg p-4 flex items-center justify-between flex-wrap gap-4">
                            <div className="flex items-center gap-3">
                                <div className="bg-purple-500 text-white p-2 rounded-full">
                                    <GitBranch size={24} />
                                </div>
                                <div>
                                    <h3 className="font-bold text-gray-800">معماری سلسله‌مراتبی</h3>
                                    <p className="text-sm text-gray-600">{refinedClusters.length} رکورد در ساختار درختی</p>
                                </div>
                            </div>

                            <div className="flex gap-2">
                                <button 
                                    onClick={handleDownloadMindMap}
                                    className="flex items-center gap-2 bg-orange-500 text-white px-4 py-2 rounded-lg hover:bg-orange-600 transition-colors shadow-sm"
                                >
                                    <Network size={18} />
                                    <span>Mind Map درختی</span>
                                </button>
                                <button 
                                    onClick={handleDownloadExcel}
                                    className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors shadow-sm"
                                >
                                    <Download size={18} />
                                    <span>اکسل</span>
                                </button>
                            </div>
                        </div>

                        {/* Data Preview Table */}
                        <div className="bg-white rounded-lg border border-gray-200 overflow-hidden flex-1">
                             <div className="overflow-x-auto max-h-[500px] custom-scrollbar">
                                <table className="w-full text-sm text-right">
                                    <thead className="bg-gray-100 text-gray-700 sticky top-0">
                                        <tr>
                                            <th className="px-4 py-3">ID</th>
                                            <th className="px-4 py-3">نام کلاستر</th>
                                            <th className="px-4 py-3">والد (Parent)</th>
                                            <th className="px-4 py-3">اینتنت</th>
                                            <th className="px-4 py-3">کلمه کلیدی</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-200">
                                        {refinedClusters.slice(0, 100).map((row, idx) => (
                                            <tr key={idx} className="hover:bg-gray-50">
                                                <td className="px-4 py-2 text-center bg-gray-50 font-mono text-xs text-purple-700 font-bold">
                                                    {row['Refined ID']}
                                                    {row['Refined ID'].includes('-') && <Split size={12} className="inline ml-1 text-orange-500"/>}
                                                </td>
                                                <td className="px-4 py-2 font-bold text-gray-800">{row['Cluster Name']}</td>
                                                <td className="px-4 py-2 text-gray-600">
                                                    {row['Parents'] === 'Root' ? <span className="opacity-30">-</span> : row['Parents']}
                                                </td>
                                                <td className="px-4 py-2">
                                                    <span className={`px-2 py-0.5 rounded text-xs ${
                                                        row['Intent'] === 'صفحه محصول تکی' ? 'bg-red-100 text-red-800' :
                                                        row['Intent'] === 'بلاگ' ? 'bg-green-100 text-green-800' :
                                                        row['Intent'].includes('دسته') ? 'bg-blue-100 text-blue-800' :
                                                        'bg-gray-100 text-gray-800'
                                                    }`}>
                                                        {row['Intent']}
                                                    </span>
                                                </td>
                                                <td className="px-4 py-2 text-xs text-gray-500">{row['Query']}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                             </div>
                             {refinedClusters.length > 100 && (
                                 <div className="p-2 text-center text-xs text-gray-500 bg-gray-50 border-t">
                                     نمایش ۱۰۰ ردیف اول. لیست کامل در اکسل موجود است.
                                 </div>
                             )}
                        </div>

                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center flex-1 text-gray-400 space-y-4">
                        <div className="bg-gray-50 p-6 rounded-full">
                            <GitBranch size={48} className="opacity-20 text-purple-600" />
                        </div>
                        <div className="text-center">
                            <h3 className="text-lg font-medium text-gray-600">تحلیل معماری و سلسله‌مراتب</h3>
                            <p className="text-sm mt-1 max-w-md mx-auto">
                                فایل کلاستر شده را آپلود کنید تا هوش مصنوعی موارد زیر را انجام دهد:
                                <br/>
                                1. تفکیک کلاسترهای مخلوط (ID بندی جدید)
                                <br/>
                                2. تشخیص والد و فرزند (Hierarchy)
                            </p>
                        </div>
                    </div>
                )}
            </div>
       </div>

       <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #1f2937;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #4b5563;
          border-radius: 3px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #6b7280;
        }
      `}</style>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const filterKeywordsBatch = async (
  keywords: string[],
  userPrompt: string
): Promise<string[]> => {
  if (!keywords.length) return [];

  const modelId = 'gemini-3-flash-preview'; 

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      keptKeywords: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
