import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  BrainCircuit, 
  Download, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  Network,
  GitBranch,
  Lightbulb,
  Split,
  Merge
} from 'lucide-react';
import { refineClusteringStrategy } from '../services/geminiService';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

interface RefinedClusterData {
    'Refined ID': string; 
    'Cluster Name': string;
    'Intent': string;
    'Parents': string; 
    'Total Volume': number;
    'Query': string;
    'Individual Volume': number;
    [key: string]: any;
}

export default function AiClusterRefiner() {
  const [file, setFile] = useState<File | null>(null);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const [refinedClusters, setRefinedClusters] = useState<RefinedClusterData[] | null>(null);
  const [originalMeta, setOriginalMeta] = useState<Record<string, any>>({});

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const processFileAndRunAi = async () => {
    if (!file) return addLog('لطفا فایل اکسل کلاستر شده را آپلود کنید.', 'error');
    if (!process.env.API_KEY) return addLog('API Key یافت نشد.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setRefinedClusters(null);
    setOriginalMeta({});

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        // Normalize headers & Extract Volume
        jsonData = jsonData.map(row => {
            const newRow: any = {};
            let volume = 0;
            Object.keys(row).forEach(key => {
                const normKey = key.trim().toLowerCase().replace(/ /g, '_');
                newRow[normKey] = row[key];

                // Try to find volume column
                if (['volume', 'search_volume', 'avg_monthly_searches', 'vol'].includes(normKey)) {
                    volume = parseInt(row[key]) || 0;
                }

                if (normKey === 'cluster_id' || normKey === 'id') newRow['cluster_id'] = row[key];
                if (normKey === 'query' || normKey === 'keyword' || normKey === 'top_queries') newRow['query'] = row[key];
            });
            newRow._volume = volume;
            newRow._original = row;
            return newRow;
        });

        const validRows = jsonData.filter(r => r.cluster_id && r.query);

        if (validRows.length === 0) {
            setIsProcessing(false);
            return addLog('فایل نامعتبر است. ستون‌های Cluster ID و Query پیدا نشدند.', 'error');
        }

        const meta: Record<string, any> = {};
        validRows.forEach(row => {
            meta[String(row.query).trim()] = { ...row._original, _volume: row._volume };
        });
        setOriginalMeta(meta);

        addLog(`${validRows.length} کلمه خوانده شد. شروع گروه‌بندی...`, 'info');

        const clusterMap = new Map<number, string[]>();
        validRows.forEach(row => {
            const id = parseInt(row.cluster_id);
            if (!clusterMap.has(id)) clusterMap.set(id, []);
            clusterMap.get(id)?.push(String(row.query).trim());
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        addLog(`ارسال ${clustersInput.length} کلاستر به هوش مصنوعی...`, 'info');

        // 1. AI Refinement (Split & Hierarchy & Naming)
        const refinedRaw = await refineClusteringStrategy(clustersInput);

        // 2. MERGING LOGIC (Global Aggregation)
        // Group by (ClusterName + Intent) to identify duplicates across batches
        addLog('در حال ادغام کلاسترهای مشابه (24, 25)...', 'info');

        const mergedGroups = new Map<string, {
            name: string;
            intent: string;
            parents: Set<string>;
            originalIds: Set<number>;
            keywords: Set<string>;
        }>();

        refinedRaw.forEach(item => {
            // Create a unique key for the Topic
            const key = `${item.newClusterName}::${item.intent}`;

            if (!mergedGroups.has(key)) {
                mergedGroups.set(key, {
                    name: item.newClusterName,
                    intent: item.intent,
                    parents: new Set(),
                    originalIds: new Set(),
                    keywords: new Set()
                });
            }

            const group = mergedGroups.get(key)!;
            group.originalIds.add(item.originalId);
            item.keywords.forEach(k => group.keywords.add(k));
            if (item.parents) {
                item.parents.forEach(p => group.parents.add(p));
            }
        });

        // 3. Final Formatting
        const finalRefinedData: RefinedClusterData[] = [];

        mergedGroups.forEach((group) => {
            const sortedIds = Array.from(group.originalIds).sort((a, b) => a - b);
            const displayId = sortedIds.join(', '); // e.g., "24, 25"

            // Handle Parents
            const parentStr = group.parents.size > 0 ? Array.from(group.parents).join(' | ') : 'Root';

            // Calculate Total Volume for this merged cluster
            let totalVolume = 0;
            group.keywords.forEach(kw => {
                totalVolume += (meta[kw]?._volume || 0);
            });

            group.keywords.forEach(kw => {
                const originalData = meta[kw] || {};
                // Clean internal fields
                const { _volume, _original, ...cleanOriginal } = originalData;

                finalRefinedData.push({
                    'Refined ID': displayId,
                    'Cluster Name': group.name,
                    'Intent': group.intent,
                    'Parents': parentStr,
                    'Total Volume': totalVolume,
                    'Query': kw,
                    'Individual Volume': _volume || 0,
                    ...cleanOriginal
                });
            });
        });

        // Sort by ID
        finalRefinedData.sort((a, b) => {
            const firstIdA = parseInt(a['Refined ID'].split(',')[0]);
            const firstIdB = parseInt(b['Refined ID'].split(',')[0]);
            return firstIdA - firstIdB;
        });

        setRefinedClusters(finalRefinedData);
        addLog(`عملیات با موفقیت انجام شد. کلاسترهای مشابه ادغام شدند.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  const generateHierarchicalMindMap = () => {
    if (!refinedClusters) return '';

    // 1. Build Nodes (Unique Clusters)
    // Map<ClusterName, NodeData>
    const nodes = new Map<string, { 
        intent: string; 
        id: string; 
        volume: number;
        parents: string[];
    }>();

    refinedClusters.forEach(row => {
        const cName = row['Cluster Name'];
        if (!nodes.has(cName)) {
            nodes.set(cName, {
                intent: row['Intent'],
                id: `node_${Math.abs(hashCode(cName))}`,
                volume: row['Total Volume'], // Already aggregated in step 3
                parents: row['Parents'] !== 'Root' ? row['Parents'].split('|').map(p => p.trim()) : []
            });
        }
    });

    // 2. Generate Mermaid
    let mermaid = 'graph LR\n';
    mermaid += '  Root((استراتژی محتوا)):::root\n';

    const edges = new Set<string>();

    nodes.forEach((data, name) => {
        // Node Shape & Style
        let shapeStart = '[';
        let shapeEnd = ']';
        if (data.intent.includes('محصول')) { shapeStart = '(['; shapeEnd = '])'; }
        else if (data.intent.includes('دسته')) { shapeStart = '['; shapeEnd = ']'; }

        // Label: Name + Volume
        const label = `"${name}\\n(Vol: ${data.volume.toLocaleString()})"`;

        // CSS Class
        let cssClass = 'defaultIntent';
        if (data.intent.includes('محصول')) cssClass = 'productIntent';
        else if (data.intent.includes('دسته')) cssClass = 'catIntent';
        else if (data.intent.includes('بلاگ')) cssClass = 'blogIntent';

        mermaid += `  ${data.id}${shapeStart}${label}${shapeEnd}:::${cssClass}\n`;

        // Edges
        if (data.parents.length === 0) {
            mermaid += `  Root --> ${data.id}\n`;
        } else {
            data.parents.forEach(pName => {
                // Determine Parent ID. If parent exists in refined data, use it.
                // If parent is abstract (not in our list), create a dummy node.
                let parentId;
                if (nodes.has(pName)) {
                    parentId = nodes.get(pName)!.id;
                } else {
                    parentId = `node_${Math.abs(hashCode(pName))}`;
                    // Define abstract parent if not defined yet
                    const pEdgeKey = `def:${parentId}`;
                    if (!edges.has(pEdgeKey)) {
                        mermaid += `  ${parentId}["${pName}"]:::catIntent\n`;
                        mermaid += `  Root -.-> ${parentId}\n`; // Loose connection to root
                        edges.add(pEdgeKey);
                    }
                }

                const edgeKey = `${parentId}->${data.id}`;
                if (!edges.has(edgeKey)) {
                    mermaid += `  ${parentId} --> ${data.id}\n`;
                    edges.add(edgeKey);
                }
            });
        }
    });

    // Styles
    mermaid += '\n  classDef root fill:#1e293b,stroke:#fff,color:#fff,stroke-width:2px;';
    mermaid += '\n  classDef catIntent fill:#3b82f6,stroke:#1d4ed8,color:#fff;';
    mermaid += '\n  classDef productIntent fill:#ef4444,stroke:#b91c1c,color:#fff;';
    mermaid += '\n  classDef blogIntent fill:#10b981,stroke:#047857,color:#fff;';
    mermaid += '\n  classDef defaultIntent fill:#8b5cf6,stroke:#6d28d9,color:#fff;';

    return mermaid;
  };

  const hashCode = (str: string) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = (hash << 5) - hash + str.charCodeAt(i);
        hash = hash & hash; 
    }
    return hash;
  };

  const handleDownloadMindMap = () => {
      const content = generateHierarchicalMindMap();
      if (!content) return;

      const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `seo_mindmap_${new Date().getTime()}.txt`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      addLog('مایند مپ (فرمت Mermaid) دانلود شد.', 'success');
  };

  const handleDownloadExcel = () => {
    if (!refinedClusters) return;
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(refinedClusters);
    XLSX.utils.book_append_sheet(wb, ws, "Strategy");
    XLSX.writeFile(wb, "seo_strategy_merged.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
       {/* Config Panel */}
       <div className="lg:col-span-4 space-y-6">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
             <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
               <BrainCircuit size={20} className="text-purple-600" />
               تنظیمات تحلیل هوشمند
             </h2>

             <div className="space-y-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">فایل اکسل ورودی</label>
                 <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-purple-500 transition-colors">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-2 text-gray-500">
                        <FileSpreadsheet size={32} />
                        <span className="text-xs">{file ? file.name : "فایل کلاستر شده را اینجا رها کنید"}</span>
                    </div>
                 </div>
                 <p className="text-xs text-gray-400 mt-1">ستون‌های الزامی: cluster_id, query. (ستون volume اختیاری)</p>
               </div>

               <div className="bg-purple-50 p-3 rounded-lg text-xs text-purple-700 space-y-2">
                 <p className="font-semibold flex items-center gap-1"><Lightbulb size={12}/> قابلیت‌های فعال:</p>
                 <ul className="list-disc list-inside space-y-1 opacity-80">
                   <li><span className="font-bold">ادغام (Merge):</span> کلاسترهای هم‌معنی یکی می‌شوند (ID: 24, 25).</li>
