import { GoogleGenAI, Type } from "@google/genai";

// Initialize Gemini Client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const filterKeywordsBatch = async (
  keywords: string[],
  userPrompt: string
): Promise<string[]> => {
  if (!keywords.length) return [];

  const modelId = 'gemini-3-flash-preview'; 

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      keptKeywords: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "The list of keywords that match the criteria and should be kept."
      }
    },
    required: ["keptKeywords"]
  };

  const systemInstruction = `
    You are a specialized SEO keyword filtering assistant.
    Your task is to analyze a list of keywords and filter them based strictly on the user's criteria.
    Rules:
    1. Return ONLY the keywords that satisfy the user's criteria.
    2. Do not modify the text of the keywords.
  `;

  const prompt = `User Criteria: "${userPrompt}"\nKeywords: ${JSON.stringify(keywords)}`;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.1,
      },
    });

    const text = response.text;
    if (!text) return keywords;
    const parsed = JSON.parse(text);
    return parsed.keptKeywords || [];

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

/**
 * Advanced Clustering Strategy for WordPress SEO
 */
export const refineClusteringStrategy = async (
  clusters: { id: number; keywords: string[] }[]
): Promise<{ originalId: number; newClusterName: string; intent: string; parents: string[]; keywords: string[] }[]> => {
  if (!clusters.length) return [];

  const modelId = 'gemini-3-flash-preview';
  const BATCH_SIZE = 5; 
  const results: { originalId: number; newClusterName: string; intent: string; parents: string[]; keywords: string[] }[] = [];

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      refinedClusters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            originalId: { type: Type.INTEGER, description: "The ID of the input cluster." },
            newClusterName: { type: Type.STRING, description: "Standardized Persian topic name for the URL slug/Title." },
            intent: { 
              type: Type.STRING, 
              enum: [
                "Category", // Main Category (Archive)
                "SubCategory", // Sub Category (Archive)
                "Product", // Single Product Page
                "Blog", // Blog Post
                "Tag" // Product Tag
              ]
            },
            parents: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Immediate parent name. Use 'Root' for top-level."
            },
            keywords: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "Keywords belonging to this specific intent group."
            }
          },
          required: ["originalId", "newClusterName", "intent", "keywords", "parents"]
        }
      }
    },
    required: ["refinedClusters"]
  };

  const systemInstruction = `
    You are a WordPress SEO Architect & Content Strategist.

    INPUT: A list of keyword clusters (ID + Keywords).
    OUTPUT: A structured architecture for a WordPress website (WooCommerce).

    **CRITICAL RULE 1: SPLITTING MIXED INTENTS (Separation)**
    - Analyze the keywords in EACH input cluster.
    - If a cluster (e.g., ID 36) contains keywords with DIFFERENT intents (e.g., "Buy Shoes" vs "How to clean shoes"), you MUST split them into separate output objects.
    - Example Input: ID 36 has ["buy nike", "nike price", "nike history", "cleaning nike"].
    - Example Output:
      1. { originalId: 36, newClusterName: "کفش نایک", intent: "Category", keywords: ["buy nike", "nike price"] }
      2. { originalId: 36, newClusterName: "تاریخچه نایک", intent: "Blog", keywords: ["nike history"] }
      3. { originalId: 36, newClusterName: "آموزش تمیز کردن کفش", intent: "Blog", keywords: ["cleaning nike"] }

    **CRITICAL RULE 2: STANDARDIZING FOR MERGING**
    - Use generic, consistent Persian names for 'newClusterName'.
    - If Input ID 24 is "Price of Nike" and Input ID 25 is "Nike Store", name BOTH of them "کفش نایک" (if they map to the same Category page).
    - My system will merge them if names match.

    **HIERARCHY (PARENTS):**
    - **Category**: Broad topic. Parent: 'Root' or another Category.
    - **SubCategory**: Specific topic. Parent: The related Category.
    - **Product**: A specific sellable item. Parent: The related SubCategory.
    - **Blog**: Informational content. Parent: 'Blog Root' or related Category.

    **INTENTS:**
    - Use strictly: "Category", "SubCategory", "Product", "Blog", "Tag".
  `;

  for (let i = 0; i < clusters.length; i += BATCH_SIZE) {
    const batch = clusters.slice(i, i + BATCH_SIZE);

    const prompt = `Architect these clusters for WordPress:\n${JSON.stringify(batch)}`;

    try {
      const response = await ai.models.generateContent({
        model: modelId,
        contents: prompt,
        config: {
          systemInstruction: systemInstruction,
          responseMimeType: "application/json",
          responseSchema: responseSchema,
          temperature: 0.1, 
        },
      });

      const text = response.text;
      if (text) {
        const parsed = JSON.parse(text);
        if (parsed.refinedClusters && Array.isArray(parsed.refinedClusters)) {
           results.push(...parsed.refinedClusters);
        }
      }

      if (i + BATCH_SIZE < clusters.length) {
        await new Promise(r => setTimeout(r, 1500));
      }

    } catch (error) {
      console.error(`Batch Error ${i}:`, error);
      // Fallback
      batch.forEach(c => {
        results.push({
            originalId: c.id,
            newClusterName: "خطا در پردازش",
            intent: "Category",
            parents: ["Root"],
            keywords: c.keywords
        });
      });
    }
  }

  return results;
};

import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import { 
  Upload, 
  BrainCircuit, 
  Download, 
  Terminal,
  Loader2,
  FileSpreadsheet,
  Network,
  GitBranch,
  Lightbulb,
  Merge,
  Split,
  Edit2,
  Save,
  RefreshCw
} from 'lucide-react';
import { refineClusteringStrategy } from '../services/geminiService';

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error';
  timestamp: string;
}

interface RefinedClusterData {
    id: string; // Unique ID for React Key (e.g. "merged_1")
    displayIds: string; // The user-facing ID string (e.g. "24, 25, 36-1")
    clusterName: string;
    intent: string;
    parents: string; // Pipe separated string for UI editing
    totalVolume: number;
    keywords: string[]; // List of keywords in this group
}

export default function AiClusterRefiner() {
  const [file, setFile] = useState<File | null>(null);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const [refinedClusters, setRefinedClusters] = useState<RefinedClusterData[]>([]);

  // Metadata for volume calculation
  const [keywordMeta, setKeywordMeta] = useState<Record<string, number>>({}); 

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const processFileAndRunAi = async () => {
    if (!file) return addLog('لطفا فایل اکسل کلاستر شده را آپلود کنید.', 'error');
    if (!process.env.API_KEY) return addLog('API Key یافت نشد.', 'error');

    setIsProcessing(true);
    setLogs([]);
    setRefinedClusters([]);
    setKeywordMeta({});

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        // Normalize headers & Extract Volume
        const meta: Record<string, number> = {};
        jsonData = jsonData.map(row => {
            const newRow: any = {};
            let volume = 0;
            Object.keys(row).forEach(key => {
                const normKey = key.trim().toLowerCase().replace(/ /g, '_');
                newRow[normKey] = row[key];

                if (['volume', 'search_volume', 'avg_monthly_searches', 'vol'].includes(normKey)) {
                    volume = parseInt(row[key]) || 0;
                }
                if (normKey === 'cluster_id' || normKey === 'id') newRow['cluster_id'] = row[key];
                if (normKey === 'query' || normKey === 'keyword' || normKey === 'top_queries') newRow['query'] = row[key];
            });
            if (newRow.query) {
                meta[String(newRow.query).trim()] = volume;
            }
            return newRow;
        });
        setKeywordMeta(meta);

        const validRows = jsonData.filter(r => r.cluster_id && r.query);
        if (validRows.length === 0) return addLog('فایل نامعتبر است. ستون‌های Cluster ID و Query پیدا نشدند.', 'error');

        addLog(`${validRows.length} کلمه خوانده شد. شروع تحلیل هوشمند...`, 'info');

        const clusterMap = new Map<number, string[]>();
        validRows.forEach(row => {
            const id = parseInt(row.cluster_id);
            if (!clusterMap.has(id)) clusterMap.set(id, []);
            clusterMap.get(id)?.push(String(row.query).trim());
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        // 1. Get AI Results
        addLog(`ارسال ${clustersInput.length} کلاستر به هوش مصنوعی...`, 'info');
        const aiResults = await refineClusteringStrategy(clustersInput);

        // 2. PROCESS SPLITS (n+1 Logic)
        // We track how many times an Original ID appears. 
        // If > 1, we suffix it.
        const idCounts = new Map<number, number>();

        // First pass to count
        aiResults.forEach(res => {
            idCounts.set(res.originalId, (idCounts.get(res.originalId) || 0) + 1);
        });

        // Second pass to assign specific IDs
        const idIterators = new Map<number, number>();

        const processedWithSplitIds = aiResults.map(res => {
            const count = idCounts.get(res.originalId) || 0;
            let finalId = res.originalId.toString();

            if (count > 1) {
                const currentIter = (idIterators.get(res.originalId) || 0);
                idIterators.set(res.originalId, currentIter + 1);

                // Rule: "اگر 2 تا از کلمات کلاستر 36 به نظر ai نیاز به صفحه جدا داشت، یک کلاستر جدید با شماره 36+1 تعریف شود"
                // Implementation: First one is "36", second is "36-1", third "36-2".
                if (currentIter > 0) {
                    finalId = `${res.originalId}-${currentIter}`;
                }
            }
            return { ...res, finalDisplayId: finalId };
        });

        // 3. PROCESS MERGES (Group by Name + Intent)
        addLog('در حال ادغام (Merging) و آماده‌سازی جدول...', 'info');
        const mergedGroups = new Map<string, {
            name: string;
            intent: string;
            parents: Set<string>;
            ids: Set<string>;
            keywords: Set<string>;
        }>();

        processedWithSplitIds.forEach(item => {
            // Key determines merging. 
            // Note: If names are slightly different (e.g. spaces), normalize them.
            const normName = item.newClusterName.trim();
            const key = `${normName}::${item.intent}`;

            if (!mergedGroups.has(key)) {
                mergedGroups.set(key, {
                    name: normName,
                    intent: item.intent,
                    parents: new Set(),
                    ids: new Set(),
                    keywords: new Set()
                });
            }

            const group = mergedGroups.get(key)!;
            group.ids.add(item.finalDisplayId);
            item.keywords.forEach(k => group.keywords.add(k));
            if (item.parents) item.parents.forEach(p => group.parents.add(p));
        });

        // 4. Convert to State Array
        const finalState: RefinedClusterData[] = [];
        let indexCounter = 0;

        mergedGroups.forEach(group => {
            let vol = 0;
            group.keywords.forEach(k => {
                vol += (meta[k] || 0);
            });

            // Format IDs: Sort nicely (numbers then strings)
            const sortedIds = Array.from(group.ids).sort((a, b) => {
                const numA = parseInt(a.split('-')[0]);
                const numB = parseInt(b.split('-')[0]);
                return numA - numB;
            });

            // Format Parents
            const parentStr = group.parents.size > 0 
                ? Array.from(group.parents).filter(p => p !== 'Root').join(' | ') 
                : '';

            finalState.push({
                id: `cluster_${indexCounter++}`,
                displayIds: sortedIds.join(', '),
                clusterName: group.name,
                intent: group.intent,
                parents: parentStr,
                totalVolume: vol,
                keywords: Array.from(group.keywords)
            });
        });

        // Sort by volume descending for better SEO view
        finalState.sort((a, b) => b.totalVolume - a.totalVolume);

        setRefinedClusters(finalState);
        addLog(`ساختار نهایی ایجاد شد. شما می‌توانید جدول را ویرایش کنید.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  // --- Handlers for Editing ---

  const handleEdit = (id: string, field: keyof RefinedClusterData, value: string) => {
    setRefinedClusters(prev => prev.map(item => {
        if (item.id === id) {
            return { ...item, [field]: value };
        }
        return item;
    }));
  };

  // --- Mind Map Generation (Uses State) ---
  const generateHierarchicalMindMap = () => {
    if (refinedClusters.length === 0) return '';

    // Map<ClusterName, NodeData>
    const nodes = new Map<string, { 
        intent: string; 
        id: string; 
        volume: number;
        parents: string[];
        isVirtual?: boolean;
    }>();

    // 1. Create nodes from current table state
    refinedClusters.forEach(row => {
        const cName = row.clusterName.trim();
        if (!cName) return;

        // If duplicate names exist in table (user edited them to be same), merge volume? 
        // For visual simplicity, we assume unique names or overwrite.
        // Let's sum volume if exists.
        if (nodes.has(cName)) {
             const existing = nodes.get(cName)!;
             existing.volume += row.totalVolume;
             // Union parents
             const pList = row.parents ? row.parents.split('|').map(p => p.trim()) : [];
             pList.forEach(p => {
                 if (!existing.parents.includes(p)) existing.parents.push(p);
             });
        } else {
            nodes.set(cName, {
                intent: row.intent,
                id: `n${Math.abs(hashCode(cName))}`,
                volume: row.totalVolume,
                parents: row.parents ? row.parents.split('|').map(p => p.trim()).filter(Boolean) : []
            });
        }
    });

    let mermaid = 'graph LR\n';
    mermaid += '  Root((صفحه اصلی)):::root\n';
    const edges = new Set<string>();

    nodes.forEach((data, name) => {
        // Node Styling
        let open = '['; let close = ']';
        let styleClass = 'catIntent';

        if (data.intent === 'Product') { open = '(['; close = '])'; styleClass = 'productIntent'; }
        else if (data.intent === 'Blog') { open = '{{'; close = '}}'; styleClass = 'blogIntent'; }
        else if (data.intent === 'SubCategory') { open = '[['; close = ']]'; styleClass = 'subCatIntent'; }
        else if (data.intent === 'Tag') { open = '>'; close = ']'; styleClass = 'tagIntent'; }

        const label = `"${name}\\n(Vol: ${data.volume.toLocaleString()})"`;
        mermaid += `  ${data.id}${open}${label}${close}:::${styleClass}\n`;

        // Edges
        if (data.parents.length === 0) {
             const edge = `Root --> ${data.id}`;
             if (!edges.has(edge)) { mermaid += `  ${edge}\n`; edges.add(edge); }
        } else {
            data.parents.forEach(pName => {
                let parentId;

                // Check if parent exists in our nodes
                if (nodes.has(pName)) {
                    parentId = nodes.get(pName)!.id;
                } else {
                    // Create Virtual Parent Node
                    parentId = `v_${Math.abs(hashCode(pName))}`;
                    const vEdgeKey = `virtual:${parentId}`;
                    if (!edges.has(vEdgeKey)) {
                        mermaid += `  ${parentId}["${pName}"]:::virtualNode\n`;
                        mermaid += `  Root -.-> ${parentId}\n`;
                        edges.add(vEdgeKey);
                    }
                }

                const edgeKey = `${parentId}->${data.id}`;
                if (!edges.has(edgeKey)) {
                    mermaid += `  ${parentId} --> ${data.id}\n`;
                    edges.add(edgeKey);
                }
            });
        }
    });

    // Styles
    mermaid += '\n  classDef root fill:#1e293b,stroke:#fff,color:#fff,stroke-width:2px;';
    mermaid += '\n  classDef catIntent fill:#3b82f6,stroke:#1d4ed8,color:#fff,rx:5px;';
    mermaid += '\n  classDef subCatIntent fill:#60a5fa,stroke:#2563eb,color:#fff,rx:5px;';
