  const [customInstruction, setCustomInstruction] = useState<string>('');

  // Metadata for volume calculation
  const [keywordMeta, setKeywordMeta] = useState<Record<string, number>>({}); 

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      addLog(`فایل انتخاب شد: ${e.target.files[0].name}`, 'info');
    }
  };

  const processFileAndRunAi = async () => {
    if (!file) return addLog('لطفا فایل اکسل کلاستر شده را آپلود کنید.', 'error');
    if (!process.env.API_KEY) return addLog('API Key یافت نشد. (لطفا process.env.API_KEY را بررسی کنید)', 'error');

    setIsProcessing(true);
    setLogs([]);
    setRefinedClusters([]);
    setKeywordMeta({});

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const sheet = workbook.Sheets[sheetName];
        let jsonData: any[] = XLSX.utils.sheet_to_json(sheet);

        // Normalize headers & Extract Volume
        const meta: Record<string, number> = {};
        jsonData = jsonData.map(row => {
            const newRow: any = {};
            let volume = 0;
            Object.keys(row).forEach(key => {
                const normKey = key.trim().toLowerCase().replace(/ /g, '_');
                newRow[normKey] = row[key];

                if (['volume', 'search_volume', 'avg_monthly_searches', 'vol'].includes(normKey)) {
                    volume = parseInt(row[key]) || 0;
                }
                if (normKey === 'cluster_id' || normKey === 'id') newRow['cluster_id'] = row[key];
                if (normKey === 'query' || normKey === 'keyword' || normKey === 'top_queries') newRow['query'] = row[key];
            });
            if (newRow.query) {
                meta[String(newRow.query).trim()] = volume;
            }
            return newRow;
        });
        setKeywordMeta(meta);

        const validRows = jsonData.filter(r => r.cluster_id && r.query);
        if (validRows.length === 0) return addLog('فایل نامعتبر است. ستون‌های Cluster ID و Query پیدا نشدند.', 'error');

        addLog(`${validRows.length} کلمه خوانده شد. شروع تحلیل هوشمند...`, 'info');

        const clusterMap = new Map<number, string[]>();
        validRows.forEach(row => {
            const id = parseInt(row.cluster_id);
            if (!clusterMap.has(id)) clusterMap.set(id, []);
            clusterMap.get(id)?.push(String(row.query).trim());
        });

        const clustersInput = Array.from(clusterMap.entries()).map(([id, keywords]) => ({
            id,
            keywords
        }));

        // 1. Get AI Results
        addLog(`ارسال ${clustersInput.length} کلاستر به هوش مصنوعی...`, 'info');
        const aiResults = await refineClusteringStrategy(clustersInput, customInstruction);

        // 2. PROCESS SPLITS (n+1 Logic)
        const idCounts = new Map<number, number>();
        aiResults.forEach(res => {
            idCounts.set(res.originalId, (idCounts.get(res.originalId) || 0) + 1);
        });

        const idIterators = new Map<number, number>();
        const processedWithSplitIds = aiResults.map(res => {
            const count = idCounts.get(res.originalId) || 0;
            let finalId = res.originalId.toString();

            if (count > 1) {
                const currentIter = (idIterators.get(res.originalId) || 0);
                idIterators.set(res.originalId, currentIter + 1);

                if (currentIter > 0) {
                    finalId = `${res.originalId}-${currentIter}`;
                }
            }
            return { ...res, finalDisplayId: finalId };
        });

        // 3. PROCESS MERGES (Group by Name + Intent)
        addLog('در حال ادغام (Merging) و آماده‌سازی جدول...', 'info');
        const mergedGroups = new Map<string, {
            name: string;
            intent: string;
            parents: Set<string>;
            ids: Set<string>;
            keywords: Set<string>;
        }>();

        processedWithSplitIds.forEach(item => {
            const normName = item.newClusterName.trim();
            const key = `${normName}::${item.intent}`;

            if (!mergedGroups.has(key)) {
                mergedGroups.set(key, {
                    name: normName,
                    intent: item.intent,
                    parents: new Set(),
                    ids: new Set(),
                    keywords: new Set()
                });
            }

            const group = mergedGroups.get(key)!;
            group.ids.add(item.finalDisplayId);
            item.keywords.forEach(k => group.keywords.add(k));
            if (item.parents) item.parents.forEach(p => group.parents.add(p));
        });

        // 4. Convert to State Array
        const finalState: RefinedClusterData[] = [];
        let indexCounter = 0;

        mergedGroups.forEach(group => {
            let vol = 0;
            group.keywords.forEach(k => {
                vol += (meta[k] || 0);
            });

            const sortedIds = Array.from(group.ids).sort((a, b) => {
                const numA = parseInt(a.split('-')[0]);
                const numB = parseInt(b.split('-')[0]);
                return numA - numB;
            });

            const parentStr = group.parents.size > 0 
                ? Array.from(group.parents).filter(p => p !== 'Root').join(' | ') 
                : '';

            finalState.push({
                id: `cluster_${indexCounter++}`,
                displayIds: sortedIds.join(', '),
                clusterName: group.name,
                intent: group.intent,
                parents: parentStr,
                totalVolume: vol,
                keywords: Array.from(group.keywords)
            });
        });

        finalState.sort((a, b) => b.totalVolume - a.totalVolume);

        setRefinedClusters(finalState);
        addLog(`ساختار نهایی ایجاد شد. شما می‌توانید جدول را ویرایش کنید.`, 'success');

      } catch (err: any) {
        console.error(err);
        addLog('خطا: ' + err.message, 'error');
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsBinaryString(file);
  };

  // --- Handlers for Editing ---
  const handleEdit = (id: string, field: keyof RefinedClusterData, value: string) => {
    setRefinedClusters(prev => prev.map(item => {
        if (item.id === id) {
            return { ...item, [field]: value };
        }
        return item;
    }));
  };

  // --- Mind Map Generation ---
  const generateHierarchicalMindMap = () => {
    if (refinedClusters.length === 0) return '';

    const nodes = new Map<string, { 
        intent: string; 
        id: string; 
        volume: number;
        parents: string[];
    }>();

    refinedClusters.forEach(row => {
        const cName = row.clusterName.trim();
        if (!cName) return;

        if (nodes.has(cName)) {
             const existing = nodes.get(cName)!;
             existing.volume += row.totalVolume;
             const pList = row.parents ? row.parents.split('|').map(p => p.trim()) : [];
             pList.forEach(p => {
                 if (!existing.parents.includes(p)) existing.parents.push(p);
             });
        } else {
            nodes.set(cName, {
                intent: row.intent,
                id: `n${Math.abs(hashCode(cName))}`,
                volume: row.totalVolume,
                parents: row.parents ? row.parents.split('|').map(p => p.trim()).filter(Boolean) : []
            });
        }
    });

    let mermaid = 'graph LR\n';
    mermaid += '  Root((صفحه اصلی)):::root\n';
    const edges = new Set<string>();

    nodes.forEach((data, name) => {
        let open = '['; let close = ']';
        let styleClass = 'catIntent';

        if (data.intent === 'Product') { open = '(['; close = '])'; styleClass = 'productIntent'; }
        else if (data.intent === 'Blog') { open = '{{'; close = '}}'; styleClass = 'blogIntent'; }
        else if (data.intent === 'SubCategory') { open = '[['; close = ']]'; styleClass = 'subCatIntent'; }
        else if (data.intent === 'Tag') { open = '>'; close = ']'; styleClass = 'tagIntent'; }

        const label = `"${name}\\n(Vol: ${data.volume.toLocaleString()})"`;
        mermaid += `  ${data.id}${open}${label}${close}:::${styleClass}\n`;

        if (data.parents.length === 0) {
             const edge = `Root --> ${data.id}`;
             if (!edges.has(edge)) { mermaid += `  ${edge}\n`; edges.add(edge); }
        } else {
            data.parents.forEach(pName => {
                let parentId;
                if (nodes.has(pName)) {
                    parentId = nodes.get(pName)!.id;
                } else {
                    parentId = `v_${Math.abs(hashCode(pName))}`;
                    const vEdgeKey = `virtual:${parentId}`;
                    if (!edges.has(vEdgeKey)) {
                        mermaid += `  ${parentId}["${pName}"]:::virtualNode\n`;
                        mermaid += `  Root -.-> ${parentId}\n`;
                        edges.add(vEdgeKey);
                    }
                }
                const edgeKey = `${parentId}->${data.id}`;
                if (!edges.has(edgeKey)) {
                    mermaid += `  ${parentId} --> ${data.id}\n`;
                    edges.add(edgeKey);
                }
            });
        }
    });

    mermaid += '\n  classDef root fill:#1e293b,stroke:#fff,color:#fff,stroke-width:2px;';
    mermaid += '\n  classDef catIntent fill:#3b82f6,stroke:#1d4ed8,color:#fff,rx:5px;';
    mermaid += '\n  classDef subCatIntent fill:#60a5fa,stroke:#2563eb,color:#fff,rx:5px;';
    mermaid += '\n  classDef productIntent fill:#ef4444,stroke:#b91c1c,color:#fff;';
    mermaid += '\n  classDef blogIntent fill:#10b981,stroke:#047857,color:#fff;';
    mermaid += '\n  classDef tagIntent fill:#f59e0b,stroke:#d97706,color:#fff,stroke-dasharray: 5 5;';
    mermaid += '\n  classDef virtualNode fill:#94a3b8,stroke:#64748b,color:#fff,stroke-dasharray: 3 3;';

    return mermaid;
  };

  const hashCode = (str: string) => {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = (hash << 5) - hash + str.charCodeAt(i);
        hash = hash & hash; 
    }
    return hash;
  };

  const handleDownloadMindMap = () => {
      const content = generateHierarchicalMindMap();
      if (!content) return addLog('داده‌ای برای ساخت گراف وجود ندارد.', 'error');

      const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `seo_architecture_mermaid.txt`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      addLog('فایل Mermaid دانلود شد. می‌توانید در mermaid.live مشاهده کنید.', 'success');
  };

  const handleDownloadExcel = () => {
    if (refinedClusters.length === 0) return;
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.json_to_sheet(refinedClusters.map(r => ({
        'Source IDs': r.displayIds,
        'Page Title (Cluster)': r.clusterName,
        'Intent': r.intent,
        'Parent Category': r.parents || 'Root',
        'Total Search Volume': r.totalVolume,
        'Keywords List': r.keywords.join(', ')
    })));
    XLSX.utils.book_append_sheet(wb, ws, "WordPress Structure");
    XLSX.writeFile(wb, "wordpress_seo_structure.xlsx");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-100px)]">
       {/* Sidebar Config */}
       <div className="lg:col-span-3 space-y-4 flex flex-col h-full overflow-hidden">
          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
             <h2 className="text-md font-bold mb-3 flex items-center gap-2 text-gray-800">
               <BrainCircuit size={18} className="text-purple-600" />
               تنظیمات ورودی
             </h2>

             <div className="space-y-4">
               {/* File Input */}
               <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-4 text-center hover:border-purple-500 transition-colors bg-gray-50">
                    <input 
                        type="file" 
                        accept=".xlsx" 
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        disabled={isProcessing}
                    />
                    <div className="flex flex-col items-center gap-1 text-gray-500">
                        {isProcessing ? <Loader2 className="animate-spin text-purple-600" /> : <Upload size={24} />}
                        <span className="text-xs">{file ? file.name : "آپلود فایل کلاستر"}</span>
                    </div>
               </div>

               {/* Custom Prompt Input */}
               <div>
                  <label className="block text-xs font-medium text-gray-700 mb-1 flex items-center gap-1">
                     <MessageSquarePlus size={12} className="text-blue-500" />
                     دستورالعمل هوش مصنوعی (اختیاری)
                  </label>
                  <textarea 
                    value={customInstruction}
                    onChange={(e) => setCustomInstruction(e.target.value)}
                    placeholder="مثال: روی فروشگاه لباس تمرکز کن. دسته‌بندی‌ها ساده باشند. برندها را جدا نکن..."
                    className="w-full h-24 p-2 border border-gray-300 rounded-lg text-xs resize-none focus:border-purple-500 focus:ring-1 focus:ring-purple-500 outline-none"
                    disabled={isProcessing}
                  />
                  <p className="text-[10px] text-gray-400 mt-1">این متن به عنوان راهنمای اضافی به پرامپت اضافه می‌شود.</p>
               </div>

               <button 
                 onClick={processFileAndRunAi}
                 disabled={isProcessing}
                 className="w-full flex items-center justify-center gap-2 bg-purple-600 text-white py-2 rounded-lg hover:bg-purple-700 disabled:opacity-50 transition-all text-sm font-medium shadow-sm"
               >
                 {isProcessing ? 'در حال تحلیل...' : 'اجرای هوش مصنوعی'}
               </button>
             </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4 flex-1 flex flex-col min-h-0">
             <h2 className="text-xs font-bold text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-100 pb-2">
              <Terminal size={14} />
              رخدادها
            </h2>
            <div className="flex-1 overflow-y-auto font-mono text-[10px] space-y-1 custom-scrollbar pr-1">
              {logs.map((log) => (
                <div key={log.id} className={`flex gap-1 ${
                  log.type === 'error' ? 'text-red-500' : 
                  log.type === 'success' ? 'text-green-600' : 'text-gray-500'
                }`}>
                  <span className="opacity-50">[{log.timestamp.split(' ')[0]}]</span>
                  <span>{log.message}</span>
                </div>
              ))}
            </div>
          </div>
       </div>

       {/* Main Content: Editable Table */}
       <div className="lg:col-span-9 flex flex-col h-full space-y-4">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col h-full overflow-hidden">

                {/* Header */}
                <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-gray-50">
                    <div className="flex items-center gap-3">
                        <div className="bg-white p-2 rounded-lg border border-gray-200 shadow-sm">
                            <GitBranch size={20} className="text-purple-600" />
                        </div>
                        <div>
                            <h3 className="font-bold text-gray-800 text-sm">معماری محتوای وردپرس</h3>
                            <p className="text-xs text-gray-500">
                                {refinedClusters.length > 0 ? `${refinedClusters.length} صفحه شناسایی شد.` : 'منتظر پردازش...'}
                            </p>
                        </div>
                    </div>

                    <div className="flex gap-2">
                        <button 
                            onClick={handleDownloadMindMap}
                            disabled={refinedClusters.length === 0}
                            className="flex items-center gap-1.5 bg-orange-500 text-white px-3 py-1.5 rounded-lg hover:bg-orange-600 text-xs shadow-sm disabled:opacity-50"
                        >
                            <Network size={16} />
                            <span>گراف (Mermaid)</span>
                        </button>
                        <button 
                            onClick={handleDownloadExcel}
                            disabled={refinedClusters.length === 0}
                            className="flex items-center gap-1.5 bg-green-600 text-white px-3 py-1.5 rounded-lg hover:bg-green-700 text-xs shadow-sm disabled:opacity-50"
                        >
                            <Download size={16} />
                            <span>اکسل نهایی</span>
                        </button>
                    </div>
                </div>

                {/* Table Area */}
                <div className="flex-1 overflow-auto custom-scrollbar bg-slate-50 relative">
                    {refinedClusters.length > 0 ? (
                        <table className="w-full text-sm border-collapse">
                            <thead className="bg-white text-gray-600 sticky top-0 z-10 shadow-sm">
                                <tr>
                                    <th className="px-3 py-3 text-right font-medium text-xs w-24">IDها</th>
                                    <th className="px-3 py-3 text-right font-medium text-xs w-1/4">نام صفحه (URL Slug)</th>
                                    <th className="px-3 py-3 text-right font-medium text-xs w-24">Volume</th>
                                    <th className="px-3 py-3 text-right font-medium text-xs w-32">نوع صفحه (Intent)</th>
                                    <th className="px-3 py-3 text-right font-medium text-xs w-1/4">والد (Parent)</th>
                                    <th className="px-3 py-3 text-right font-medium text-xs">کلمات کلیدی</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-200 bg-white">
                                {refinedClusters.map((row) => (
                                    <tr key={row.id} className="hover:bg-blue-50 transition-colors group">
                                        {/* IDs */}
                                        <td className="px-3 py-2 align-top">
                                            <div className="flex flex-wrap gap-1">
                                                {row.displayIds.split(', ').map(id => (
                                                    <span key={id} className={`text-[10px] px-1.5 py-0.5 rounded border ${
                                                        id.includes('-') ? 'bg-amber-50 border-amber-200 text-amber-700' : 'bg-gray-100 border-gray-200 text-gray-600'
                                                    }`}>
                                                        {id}
                                                        {id.includes('-') && <Split size={8} className="inline mr-1" />}
                                                    </span>
                                                ))}
                                                {row.displayIds.includes(',') && <Merge size={12} className="text-purple-400 mt-0.5" />}
                                            </div>
                                        </td>

                                        {/* Editable Name */}
                                        <td className="px-3 py-2 align-top">
                                            <div className="relative">
                                                <input 
                                                    type="text" 
                                                    value={row.clusterName}
                                                    onChange={(e) => handleEdit(row.id, 'clusterName', e.target.value)}
                                                    className="w-full p-1.5 border border-transparent hover:border-gray-300 focus:border-blue-500 rounded text-gray-800 font-bold bg-transparent focus:bg-white transition-all outline-none"
                                                />
                                                <Edit2 size={12} className="absolute left-2 top-2.5 text-gray-300 opacity-0 group-hover:opacity-100 pointer-events-none" />
                                            </div>
                                        </td>

                                        {/* Volume */}
                                        <td className="px-3 py-2 align-top pt-3 font-mono text-xs text-blue-600">
                                            {row.totalVolume.toLocaleString()}
                                        </td>

                                        {/* Editable Intent */}
                                        <td className="px-3 py-2 align-top">
                                            <select 
                                                value={row.intent}
                                                onChange={(e) => handleEdit(row.id, 'intent', e.target.value)}
                                                className={`w-full p-1.5 rounded text-xs border border-transparent hover:border-gray-300 focus:border-blue-500 cursor-pointer outline-none appearance-none font-medium ${
                                                    row.intent === 'Product' ? 'text-red-600 bg-red-50' :
                                                    row.intent === 'Blog' ? 'text-green-600 bg-green-50' :
                                                    row.intent === 'SubCategory' ? 'text-blue-600 bg-blue-50' :
                                                    'text-purple-600 bg-purple-50'
                                                }`}
                                            >
                                                <option value="Category">Category</option>
                                                <option value="SubCategory">SubCategory</option>
                                                <option value="Product">Product</option>
                                                <option value="Blog">Blog</option>
                                                <option value="Tag">Tag</option>
                                            </select>
                                        </td>

                                        {/* Editable Parent */}
                                        <td className="px-3 py-2 align-top">
                                            <input 
                                                type="text" 
                                                value={row.parents}
                                                onChange={(e) => handleEdit(row.id, 'parents', e.target.value)}
                                                placeholder="Root"
                                                className="w-full p-1.5 border border-transparent hover:border-gray-300 focus:border-blue-500 rounded text-gray-600 text-xs bg-transparent focus:bg-white transition-all outline-none"
                                            />
                                        </td>

                                        {/* Keywords Preview */}
                                        <td className="px-3 py-2 align-top">
                                            <div className="text-[10px] text-gray-400 leading-relaxed max-h-16 overflow-hidden">
                                                {row.keywords.join('، ')}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-gray-400 space-y-4">
                            <div className="bg-white p-6 rounded-full shadow-sm">
                                <FileSpreadsheet size={48} className="opacity-20 text-purple-600" />
                            </div>
                            <div className="text-center">
                                <h3 className="text-lg font-medium text-gray-600">داده‌ای موجود نیست</h3>
                                <p className="text-sm mt-1 max-w-xs mx-auto">
                                    فایل را از ستون سمت راست بارگذاری کنید تا جدول ویرایشگر فعال شود.
                                </p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
       </div>

       <style>{`
        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
          height: 6px;
        }
        .custom-scrollbar::-webkit-scrollbar-track {
          background: #f1f5f9;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: #cbd5e1;
          border-radius: 3px;
        }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #94a3b8;
        }
      `}</style>
    </div>
  );
}

import React, { useState, useRef, useCallback, useMemo } from 'react';
import { 
  Search, 
  Download, 
  Copy, 
  Play, 
  Square, 
  Settings, 
  Database, 
  Layers, 
  Terminal,
  Trash2,
  XCircle,
  Sparkles,
  Filter,
  Loader2,
  Eraser,
  Eye,
  X,
  CheckSquare,
  MinusSquare
} from 'lucide-react';
import { filterKeywordsBatch } from '../services/geminiService';

// --- Type Definitions ---
interface SuggestionResult {
  id: string;
  keyword: string;
  sourceSeed: string;
  layer: number;
}

interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'error' | 'warning';
  timestamp: string;
}

// --- Utils ---

const normalizeText = (text: string): string => {
  if (!text) return '';
  return text
    .trim()
    .replace(/\s+/g, ' ') 
    .replace(/ي/g, 'ی')   
    .replace(/ك/g, 'ک')   
    .toLowerCase();       
};

const generateCSV = (data: SuggestionResult[]) => {
  const header = ['Keyword,Source Seed,Layer'];
  const rows = data.map(item => `"${item.keyword}","${item.sourceSeed}",${item.layer}`);
  return [header, ...rows].join('\n');
};

export default function KeywordFetcher() {
  const [seeds, setSeeds] = useState<string>('');
  const [language, setLanguage] = useState<string>('fa');
  const [country, setCountry] = useState<string>('ir');
  const [depth, setDepth] = useState<number>(1);
  const [delay, setDelay] = useState<number>(1000); 
  const [concurrency, setConcurrency] = useState<number>(2); 

  const [results, setResults] = useState<SuggestionResult[]>([]);
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [isProcessing, setIsProcessing] = useState<boolean>(false);
  const [progress, setProgress] = useState<{ processed: number; total: number }>({ processed: 0, total: 0 });

  const [aiPrompt, setAiPrompt] = useState<string>('');
  const [isAiFiltering, setIsAiFiltering] = useState<boolean>(false);

  // --- New Manual Filter & Selection State ---
  const [filterText, setFilterText] = useState<string>('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  const abortControllerRef = useRef<AbortController | null>(null);
  const processedKeywordsRef = useRef<Set<string>>(new Set());

  const addLog = useCallback((message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date().toLocaleTimeString()
    }, ...prev].slice(0, 100)); 
  }, []);

  // --- Filter Logic ---
  const filteredResults = useMemo(() => {
    if (!filterText.trim()) return results;
    const term = normalizeText(filterText);
    return results.filter(r => normalizeText(r.keyword).includes(term));
  }, [results, filterText]);

  // --- Selection Logic ---
  const handleSelectAll = () => {
    if (selectedIds.size === filteredResults.length && filteredResults.length > 0) {
      // Deselect all visible
      const newSelected = new Set(selectedIds);
      filteredResults.forEach(r => newSelected.delete(r.id));
      setSelectedIds(newSelected);
    } else {
      // Select all visible
      const newSelected = new Set(selectedIds);
      filteredResults.forEach(r => newSelected.add(r.id));
      setSelectedIds(newSelected);
    }
  };

  const handleSelectRow = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedIds(newSelected);
  };

  const handleDeleteSelected = () => {
    if (selectedIds.size === 0) return;

    setResults(prev => {
      const newResults = prev.filter(r => !selectedIds.has(r.id));
      // Update the processed reference set
      processedKeywordsRef.current = new Set(newResults.map(r => r.keyword));
      return newResults;
    });

    addLog(`${selectedIds.size} کلمه انتخاب شده حذف شدند.`, 'success');
    setSelectedIds(new Set());
  };


  const fetchSuggestions = async (query: string): Promise<string[]> => {
    const targetUrl = `https://suggestqueries.google.com/complete/search?client=chrome&hl=${language}&gl=${country}&q=${encodeURIComponent(query)}`;

    const proxies = [
      {
        name: 'CORSProxy',
        url: (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}`,
        isJsonWrapped: false
      },
      {
        name: 'AllOrigins',
        url: (u: string) => `https://api.allorigins.win/get?url=${encodeURIComponent(u)}`,
        isJsonWrapped: true
      }
    ];

    let lastError: any = null;

    for (const proxy of proxies) {
      if (abortControllerRef.current?.signal.aborted) {
        throw new DOMException('Aborted', 'AbortError');
      }

      try {
        const response = await fetch(proxy.url(targetUrl), {
          signal: abortControllerRef.current?.signal
        });

        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`);
        }

        const data = await response.json();

        let resultData;
        if (proxy.isJsonWrapped) {
          resultData = JSON.parse(data.contents);
        } else {
          resultData = data;
        }

        if (Array.isArray(resultData) && Array.isArray(resultData[1])) {
           return resultData[1];
        }

        return [];

      } catch (error: any) {
        if (error.name === 'AbortError') throw error;
        lastError = error;
      }
    }

    throw lastError || new Error('All proxies failed');
  };

  const startProcessing = async () => {
    if (!seeds.trim()) {
      addLog('لطفا کلمات کلیدی اولیه را وارد کنید.', 'error');
      return;
    }

    setIsProcessing(true);
    setResults([]);
    setLogs([]);
    processedKeywordsRef.current = new Set();
    abortControllerRef.current = new AbortController();

    const seedList = seeds.split('\n').map(s => normalizeText(s)).filter(s => s.length > 0);

    let queue: { keyword: string; source: string; layer: number }[] = seedList.map(s => ({
      keyword: s,
      source: 'SEED',
      layer: 0 
    }));

    seedList.forEach(s => processedKeywordsRef.current.add(s));

    addLog(`شروع پردازش با ${seedList.length} کلمه کلیدی...`, 'info');

    let totalProcessedCount = 0;

    try {
      while (queue.length > 0 && abortControllerRef.current) {

        const currentBatch = queue.splice(0, concurrency);

        setProgress({ processed: totalProcessedCount, total: totalProcessedCount + queue.length + currentBatch.length });

        const batchPromises = currentBatch.map(async (item) => {
          if (item.layer >= depth) return []; 

          try {
            const suggestions = await fetchSuggestions(item.keyword);

            const newKeywords: { keyword: string; source: string; layer: number }[] = [];

            suggestions.forEach(sugg => {
              const normalizedSugg = normalizeText(sugg);

              if (!processedKeywordsRef.current.has(normalizedSugg)) {
                processedKeywordsRef.current.add(normalizedSugg);

                const newResult: SuggestionResult = {
                  id: Math.random().toString(36).substr(2, 9),
                  keyword: normalizedSugg,
                  sourceSeed: item.keyword,
                  layer: item.layer + 1
                };

                setResults(prev => [...prev, newResult]);

                if (item.layer + 1 < depth) {
                  newKeywords.push({
                    keyword: normalizedSugg,
                    source: item.keyword,
                    layer: item.layer + 1
                  });
                }
              }
            });
            return newKeywords;
          } catch (err: any) {
            if (err.name !== 'AbortError') {
               addLog(`خطا در دریافت ساجست برای: "${item.keyword}"`, 'warning');
            }
            return [];
          }
        });

        const batchResults = await Promise.all(batchPromises);
        totalProcessedCount += currentBatch.length;

        batchResults.forEach(newItems => {
          queue.push(...newItems);
        });

        if (queue.length > 0) {
          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }

      if (abortControllerRef.current) {
        addLog('پردازش با موفقیت به پایان رسید.', 'success');
      }

    } catch (error: any) {
      if (error.name !== 'AbortError') {
        addLog('پردازش با خطای غیرمنتظره متوقف شد.', 'error');
      }
    } finally {
      setIsProcessing(false);
      abortControllerRef.current = null;
    }
  };

  const stopProcessing = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
      setIsProcessing(false);
      addLog('پردازش توسط کاربر متوقف شد.', 'warning');
    }
  };

  const handleAiFilter = async () => {
    if (results.length === 0) {
      addLog('هیچ کلمه‌ای برای تحلیل وجود ندارد.', 'warning');
      return;
    }
    if (!aiPrompt.trim()) {
      addLog('لطفا دستور فیلتر (Prompt) را وارد کنید.', 'error');
      return;
    }

    if (!process.env.API_KEY) {
      addLog('API Key یافت نشد. لطفا تنظیمات برنامه را بررسی کنید.', 'error');
      return;
    }

    setIsAiFiltering(true);
    addLog('شروع تحلیل هوشمند کلمات با هوش مصنوعی...', 'info');

    try {
      const CHUNK_SIZE = 75;
      const allKeywords = results.map(r => r.keyword);
      const chunks = [];

      for (let i = 0; i < allKeywords.length; i += CHUNK_SIZE) {
        chunks.push(allKeywords.slice(i, i + CHUNK_SIZE));
      }

      let keptKeywordsSet = new Set<string>();

      const processChunkWithRetry = async (chunk: string[], batchIndex: number, attempt = 1): Promise<string[]> => {
          try {
              return await filterKeywordsBatch(chunk, aiPrompt);
          } catch (e: any) {
              if (attempt <= 3) {
                  const delayTime = 2000 * attempt;
                  addLog(`خطا در دسته ${batchIndex + 1}. تلاش مجدد (${attempt}/3) تا ${delayTime/1000} ثانیه دیگر...`, 'warning');
                  await new Promise(r => setTimeout(r, delayTime));
                  return processChunkWithRetry(chunk, batchIndex, attempt + 1);
              }
              throw e;
          }
      };

      for (let i = 0; i < chunks.length; i++) {
        const chunk = chunks[i];

        addLog(`در حال تحلیل دسته ${i + 1} از ${chunks.length} (${chunk.length} کلمه)...`, 'info');

        try {
          const keptInChunk = await processChunkWithRetry(chunk, i);

          keptInChunk.forEach(k => keptKeywordsSet.add(k));

          if (i < chunks.length - 1) {
            await new Promise(r => setTimeout(r, 1000));
          }

        } catch (err) {
          console.error(err);
          addLog(`خطا در تحلیل دسته ${i + 1} پس از ۳ تلاش. این دسته بدون تغییر باقی می‌ماند.`, 'error');
          chunk.forEach(k => keptKeywordsSet.add(k));
        }
      }

      const initialCount = results.length;
      const finalCount = keptKeywordsSet.size;
      const removedCount = initialCount - finalCount;

      const newResults = results.filter(r => keptKeywordsSet.has(r.keyword));
      setResults(newResults);

      processedKeywordsRef.current = new Set(newResults.map(r => r.keyword));

      addLog(`پایان تحلیل. ${removedCount} کلمه حذف شد و ${finalCount} کلمه باقی ماند.`, 'success');

    } catch (error) {
      addLog('خطای کلی در فرآیند هوش مصنوعی.', 'error');
      console.error(error);
    } finally {
      setIsAiFiltering(false);
    }
  };

  const handleExport = () => {
    const csvContent = generateCSV(results);
    const blob = new Blob([`\uFEFF${csvContent}`], { type: 'text/csv;charset=utf-8;' }); 
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `deep_suggest_${new Date().toISOString().slice(0,10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    addLog('فایل CSV دانلود شد.', 'success');
  };

  const handleCopy = () => {
    const text = results.map(r => r.keyword).join('\n');

    const textArea = document.createElement("textarea");
    textArea.value = text;

    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    textArea.style.top = "0";
    document.body.appendChild(textArea);

    textArea.focus();
    textArea.select();

    try {
      const successful = document.execCommand('copy');
      if (successful) {
        addLog(`${results.length} کلمه کلیدی در کلیپ‌بورد کپی شد.`, 'success');
      } else {
        addLog('کپی ناموفق بود. لطفا دستی کپی کنید.', 'error');
      }
    } catch (err) {
      console.error('Copy failed', err);
      addLog('خطا در کپی کردن متن.', 'error');
    }

    document.body.removeChild(textArea);
  };

  const handleClear = () => {
    setResults([]);
    setLogs([]);
    setSelectedIds(new Set());
    setFilterText('');
    processedKeywordsRef.current = new Set();
    setProgress({ processed: 0, total: 0 });
  };

  const handleDeleteItem = (targetKeyword: string) => {
    const toRemove = new Set<string>([targetKeyword]);
    const queue = [targetKeyword];

    let head = 0;
    while(head < queue.length){
        const currentParent = queue[head];
        head++;

        const children = results.filter(r => r.sourceSeed === currentParent);

        children.forEach(child => {
            if (!toRemove.has(child.keyword)) {
                toRemove.add(child.keyword);
                queue.push(child.keyword);
            }
        });
    }

    setResults(prev => prev.filter(r => !toRemove.has(r.keyword)));

    toRemove.forEach(k => processedKeywordsRef.current.delete(k));

    addLog(`کلمه "${targetKeyword}" و ${toRemove.size - 1} زیرمجموعه آن حذف شدند.`, 'warning');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

      {/* Left Column: Configuration (4 cols) */}
      <div className="lg:col-span-4 space-y-6">

        {/* Input Panel */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <Database size={20} className="text-blue-500" />
            ورودی‌ها
          </h2>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">کلمات کلیدی اولیه (Seed)</label>
              <textarea
                className="w-full h-32 p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 text-sm resize-none"
                placeholder="هر خط یک کلمه...&#10;خرید موبایل&#10;آموزش سئو"
                value={seeds}
                onChange={(e) => setSeeds(e.target.value)}
                disabled={isProcessing || isAiFiltering}
              ></textarea>
              <p className="text-xs text-gray-500 mt-1 text-left ltr">
                {seeds.split('\n').filter(s => s.trim()).length} Seed Keywords
              </p>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">زبان (hl)</label>
                <select 
                  value={language} 
                  onChange={(e) => setLanguage(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-md text-sm"
                  disabled={isProcessing || isAiFiltering}
                >
                  <option value="fa">فارسی (fa)</option>
                  <option value="en">English (en)</option>
                  <option value="ar">Arabic (ar)</option>
                  <option value="tr">Turkish (tr)</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">منطقه (gl)</label>
                <select 
                  value={country} 
                  onChange={(e) => setCountry(e.target.value)}
                  className="w-full p-2 border border-gray-300 rounded-md text-sm"
                  disabled={isProcessing || isAiFiltering}
                >
                  <option value="ir">ایران (ir)</option>
                  <option value="us">United States (us)</option>
                  <option value="ae">UAE (ae)</option>
                  <option value="tr">Turkey (tr)</option>
                </select>
              </div>
            </div>
          </div>
        </div>

        {/* Removed Old Manual Filter Panel */}

        {/* AI Filter Panel */}
        <div className="bg-gradient-to-br from-indigo-50 to-purple-50 rounded-xl shadow-sm border border-indigo-100 p-5">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2 text-indigo-900">
            <Sparkles size={20} className="text-indigo-600" />
            فیلتر هوشمند (AI)
          </h2>
          <div className="space-y-3">
            <div>
              <label className="block text-sm font-medium text-indigo-800 mb-1">چه کلماتی را نگه دارم/حذف کنم؟</label>
              <textarea 
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                disabled={isProcessing || isAiFiltering}
                placeholder="مثال: کلمات مربوط به 'رایگان' یا 'کرک' را حذف کن. فقط کلمات خرید آنلاین را نگه دار."
                className="w-full h-24 p-3 border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 text-sm resize-none bg-white"
              />
            </div>
            <button
              onClick={handleAiFilter}
              disabled={isProcessing || isAiFiltering || results.length === 0}
              className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
            >
              {isAiFiltering ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  <span>در حال تحلیل...</span>
                </>
              ) : (
                <>
                  <Filter size={18} />
                  <span>اعمال فیلتر روی نتایج</span>
                </>
              )}
            </button>
            <p className="text-xs text-indigo-400 leading-relaxed">
              این ابزار لیست نتایج فعلی را به Gemini می‌فرستد و بر اساس دستور شما آن را پالایش می‌کند. (تجزیه به بسته‌های کوچک‌تر جهت پایداری)
            </p>
          </div>
        </div>

        {/* Settings Panel */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-5">
          <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <Settings size={20} className="text-gray-500" />
            تنظیمات پیشرفته
          </h2>

          <div className="space-y-6">
            <div>
              <div className="flex justify-between mb-1">
                <label className="text-sm font-medium text-gray-700">عمق جستجو (Depth)</label>
                <span className="text-xs bg-blue-100 text-blue-800 px-2 py-0.5 rounded-full">لایه {depth}</span>
              </div>
              <input 
                type="range" 
                min="1" 
                max="3" 
                step="1"
                value={depth}
                onChange={(e) => setDepth(parseInt(e.target.value))}
                disabled={isProcessing || isAiFiltering}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
            </div>

            <div>
              <div className="flex justify-between mb-1">
                <label className="text-sm font-medium text-gray-700">تعداد درخواست همزمان</label>
                <span className="text-xs text-gray-500">{concurrency} درخواست</span>
              </div>
              <input 
                type="range" 
                min="1" 
                max="5" 
                value={concurrency}
                onChange={(e) => setConcurrency(parseInt(e.target.value))}
                disabled={isProcessing || isAiFiltering}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
            </div>

            <div>
              <div className="flex justify-between mb-1">
                <label className="text-sm font-medium text-gray-700">تاخیر بین درخواست‌ها</label>
                <span className="text-xs text-gray-500">{delay} میلی‌ثانیه</span>
              </div>
              <input 
                type="range" 
                min="100" 
                max="3000" 
                step="100"
                value={delay}
                onChange={(e) => setDelay(parseInt(e.target.value))}
                disabled={isProcessing || isAiFiltering}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
              />
            </div>

             {/* Action Buttons inside Settings for Mobile/Compact Layout */}
             <div className="pt-4 flex flex-col gap-2">
                {isProcessing ? (
                <button 
                    onClick={stopProcessing}
                    className="w-full flex items-center justify-center gap-2 bg-red-50 text-red-600 border border-red-200 px-4 py-2 rounded-md hover:bg-red-100 transition-colors"
                >
                    <Square size={18} fill="currentColor" />
                    <span>توقف استخراج</span>
                </button>
                ) : (
                <button 
                    onClick={startProcessing}
                    disabled={isAiFiltering}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white px-6 py-2 rounded-md hover:bg-blue-700 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    <Play size={18} fill="currentColor" />
                    <span>شروع استخراج</span>
                </button>
                )}
             </div>
          </div>
        </div>

        {/* Log Panel */}
        <div className="bg-gray-900 rounded-xl shadow-sm border border-gray-800 p-4 h-64 flex flex-col">
            <h2 className="text-xs font-mono text-gray-400 mb-2 flex items-center gap-2 border-b border-gray-700 pb-2">
            <Terminal size={14} />
            System Logs
        </h2>
        <div className="flex-1 overflow-y-auto font-mono text-xs space-y-1 custom-scrollbar">
            {logs.length === 0 && <span className="text-gray-600 italic">آماده برای شروع...</span>}
            {logs.map((log) => (
            <div key={log.id} className={`flex gap-2 ${
                log.type === 'error' ? 'text-red-400' : 
                log.type === 'success' ? 'text-green-400' : 
                log.type === 'warning' ? 'text-yellow-400' : 'text-gray-300'
            }`}>
                <span className="text-gray-600">[{log.timestamp}]</span>
                <span>{log.message}</span>
            </div>
            ))}
        </div>
        </div>

      </div>

      {/* Right Column: Results (8 cols) */}
      <div className="lg:col-span-8 flex flex-col h-full space-y-6">

        {/* Stats Bar */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4 flex flex-wrap gap-4 justify-between items-center">
            <div className="flex gap-6">
            <div className="flex flex-col">
                <span className="text-xs text-gray-500">کلمات پیدا شده</span>
                <span className="text-2xl font-bold text-blue-600">{results.length}</span>
            </div>
            <div className="flex flex-col">
                <span className="text-xs text-gray-500">وضعیت</span>
                <span className={`text-sm font-medium mt-1 ${isProcessing ? 'text-amber-500 animate-pulse' : isAiFiltering ? 'text-indigo-500 animate-pulse' : 'text-green-600'}`}>
                {isProcessing ? 'در حال استخراج...' : isAiFiltering ? 'در حال تحلیل AI...' : 'آماده'}
                </span>
            </div>
            {isProcessing && (
                <div className="flex flex-col w-32">
                <span className="text-xs text-gray-500 mb-1">پیشرفت استخراج</span>
                <div className="w-full bg-gray-200 rounded-full h-2.5">
                    <div 
                    className="bg-blue-600 h-2.5 rounded-full transition-all duration-300" 
                    style={{ width: `${Math.min(100, (progress.processed / Math.max(progress.total, 1)) * 100)}%` }}
                    ></div>
                </div>
                </div>
            )}
            </div>

            <div className="flex gap-2">
            <button 
            onClick={handleClear}
            disabled={results.length === 0 || isProcessing || isAiFiltering}
            className="p-2 text-gray-500 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
            title="پاک کردن نتایج"
            >
                <Trash2 size={20} />
            </button>
            <button 
                onClick={handleCopy}
                disabled={results.length === 0 || isProcessing || isAiFiltering}
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 disabled:opacity-50"
            >
                <Copy size={16} />
                <span>کپی</span>
            </button>
            <button 
                onClick={handleExport}
                disabled={results.length === 0 || isProcessing || isAiFiltering}
                className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-white bg-green-600 rounded-lg hover:bg-green-700 disabled:opacity-50"
            >
                <Download size={16} />
